import React, { useState, useEffect } from 'react';
import { BackendService } from '../services/BackendService';
import { User } from '../types';

interface LoginModalProps {
    onClose: () => void;
    onLoginSuccess: (user: User) => void;
    darkMode: boolean;
}

export const LoginModal: React.FC<LoginModalProps> = ({ onClose, onLoginSuccess, darkMode }) => {
    const [isLoginView, setIsLoginView] = useState(true);
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);

    // Close on Escape key
    useEffect(() => {
        const handleEsc = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose();
        };
        window.addEventListener('keydown', handleEsc);
        return () => window.removeEventListener('keydown', handleEsc);
    }, [onClose]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);
        setLoading(true);

        try {
            const response = isLoginView 
                ? await BackendService.login(username, password)
                : await BackendService.register(username, password);

            if (response.success && response.user) {
                onLoginSuccess(response.user);
                onClose();
            } else {
                setError(response.error || "An unknown error occurred");
            }
        } catch (err) {
            setError("Terminal Link Failure");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div 
            className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/80 backdrop-blur-xl animate-in fade-in duration-300 p-4"
            onClick={onClose}
        >
            {/* Modal Container */}
            <div 
                className={`
                    w-full max-w-md p-10 rounded-[3rem] shadow-[0_0_100px_rgba(0,0,0,1)] transform scale-100 transition-all border-[3px] relative overflow-hidden
                    ${darkMode ? 'bg-[#0a0a0a] border-white/10' : 'bg-white border-black/10'}
                `}
                onClick={(e) => e.stopPropagation()}
            >
                {/* Decorative Elements */}
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500/50 to-transparent"></div>
                <div className="absolute -top-12 -right-12 w-32 h-32 bg-cyan-500/5 rounded-full blur-3xl pointer-events-none"></div>
                <div className="absolute -bottom-12 -left-12 w-32 h-32 bg-blue-500/5 rounded-full blur-3xl pointer-events-none"></div>

                {/* Close Button */}
                <button 
                    onClick={(e) => {
                        e.preventDefault();
                        onClose();
                    }} 
                    className="absolute top-8 right-8 p-3 group hover:bg-white/5 rounded-2xl transition-all z-20"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white/20 group-hover:text-red-500 transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                </button>

                {/* Header Section */}
                <div className="text-center mb-10 relative z-10">
                    <div className="inline-block px-4 py-1.5 rounded-full bg-cyan-500/10 border border-cyan-500/20 mb-4">
                        <span className="text-[10px] font-black text-cyan-500 uppercase tracking-[0.3em]">Access_Protocol</span>
                    </div>
                    <h2 className="text-4xl font-black italic tracking-tighter text-white uppercase leading-none">
                        {isLoginView ? 'System_Login' : 'User_Enlist'}
                    </h2>
                </div>

                {/* Tab Switcher */}
                <div className="flex justify-center mb-10 relative z-10">
                    <div className="flex p-1.5 rounded-[1.2rem] bg-black/60 border border-white/5 w-full">
                        <button 
                            onClick={() => {
                                setIsLoginView(true);
                                setError(null);
                            }}
                            className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase tracking-widest transition-all ${isLoginView ? 'bg-white text-black shadow-lg' : 'text-white/40 hover:text-white/60'}`}
                        >
                            Log_In
                        </button>
                        <button 
                            onClick={() => {
                                setIsLoginView(false);
                                setError(null);
                            }}
                            className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase tracking-widest transition-all ${!isLoginView ? 'bg-white text-black shadow-lg' : 'text-white/40 hover:text-white/60'}`}
                        >
                            Sign_Up
                        </button>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6 relative z-10">
                    <div className="space-y-3">
                        <div className="flex justify-between items-center px-1">
                            <label className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em]">Pilot_Identity</label>
                        </div>
                        <input 
                            type="text" 
                            required
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            className={`w-full px-6 py-4 rounded-2xl border-2 font-black text-lg focus:outline-none transition-all uppercase tracking-widest ${darkMode ? 'bg-black/60 border-white/5 text-cyan-400 focus:border-cyan-500/40 focus:bg-cyan-500/5' : 'bg-gray-50 border-gray-100 text-gray-800'}`}
                            placeholder="COMMANDER_NAME"
                        />
                    </div>

                    <div className="space-y-3">
                        <div className="flex justify-between items-center px-1">
                            <label className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em]">Security_Key</label>
                        </div>
                        <input 
                            type="password" 
                            required
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            className={`w-full px-6 py-4 rounded-2xl border-2 font-black text-lg focus:outline-none transition-all tracking-widest ${darkMode ? 'bg-black/60 border-white/5 text-cyan-400 focus:border-cyan-500/40 focus:bg-cyan-500/5' : 'bg-gray-50 border-gray-100 text-gray-800'}`}
                            placeholder="••••••••"
                        />
                    </div>

                    {error && (
                        <div className="bg-red-500/10 border border-red-500/30 text-red-500 text-[10px] font-black p-4 rounded-2xl text-center animate-in slide-in-from-top-2 uppercase tracking-widest">
                            {error}
                        </div>
                    )}

                    <button 
                        type="submit" 
                        disabled={loading}
                        className={`
                            w-full py-6 mt-6 rounded-[2rem] font-black text-xl italic tracking-[0.2em] shadow-2xl flex items-center justify-center gap-3 transition-all
                            ${loading ? 'opacity-70 cursor-wait' : 'hover:scale-[1.02] active:scale-95'}
                            ${isLoginView ? 'bg-gradient-to-b from-cyan-400 to-blue-700 text-white' : 'bg-gradient-to-b from-green-400 to-emerald-700 text-white'}
                        `}
                    >
                        {loading ? (
                            <svg className="animate-spin h-6 w-6 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                            </svg>
                        ) : (
                            <span>{isLoginView ? 'INITIATE_LINK' : 'ENLIST_UNIT'}</span>
                        )}
                    </button>
                </form>

                {/* Footer Disclaimer */}
                <div className="mt-8 text-center">
                    <p className="text-[8px] font-black text-white/10 uppercase tracking-[0.5em]">Global_Encryption_Active // v4.2.0_SECURE</p>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameMode, GameState, HighScoreEntry, StatType, TankClass, User, Team } from './types';
import { GameEngine } from './services/GameEngine';
import { BackendService } from './services/BackendService';
import { LoginModal } from './components/LoginModal';
import { ShopModal } from './components/ShopModal';
import { AlmanacModal } from './components/AlmanacModal';
import { COLORS, SHOP_ITEMS } from './constants';
import { TankPreview } from './components/TankPreview';

interface GameSettings {
    volume: number;
    darkMode: boolean;
}

const DEFAULT_SETTINGS: GameSettings = {
    volume: 0.15,
    darkMode: true
};

interface Mission {
    id: number;
    text: string;
    progress: number;
    total: number;
    reward: string;
    rewardValue: number;
    claimed: boolean;
}

const INITIAL_MISSIONS: Mission[] = [
    { id: 1, text: "Play 3 Games", progress: 0, total: 3, reward: "250 DC", rewardValue: 250, claimed: false },
    { id: 2, text: "Reach Level 20", progress: 0, total: 20, reward: "350 DC", rewardValue: 350, claimed: false },
    { id: 3, text: "Earn 10k Score", progress: 0, total: 10000, reward: "750 DC", rewardValue: 750, claimed: false },
];

const TIPS = [
    "Press 'E' for Auto-Fire",
    "Pentagon Nest is high-risk, high-reward",
    "Body Damage protects against collisions",
    "Recoil can be used as a speed boost",
    "Sandbox Mode allows instant class switching"
];

const NEWS = [
    { id: 1, title: "SANDBOX MODE", date: "NEW", content: "Test mechanics in a private dev sector." },
    { id: 2, title: "Remaster v1.6", date: "Today", content: "Physics and console commands synced." },
];

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [engine, setEngine] = useState<GameEngine | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [playerName, setPlayerName] = useState(() => localStorage.getItem('diep_remix_name') || '');
  const [highScores, setHighScores] = useState<HighScoreEntry[]>([]);
  const [settings, setSettings] = useState<GameSettings>(DEFAULT_SETTINGS);
  const [missions, setMissions] = useState<Mission[]>(INITIAL_MISSIONS);

  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showShop, setShowShop] = useState(false);
  const [showAlmanac, setShowAlmanac] = useState(false);

  const [featuredClass, setFeaturedClass] = useState<TankClass>(TankClass.BASIC);
  const [selectedServer] = useState("US East");
  const [currentTipIndex, setCurrentTipIndex] = useState(0);
  const [gameMode, setGameMode] = useState<GameMode>(GameMode.FFA);
  const [selectedTeam, setSelectedTeam] = useState<Team>(Team.BLUE);

  const [menuMousePos, setMenuMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  const activeColor = useMemo(() => {
      if (user && user.equippedItem) {
          const item = SHOP_ITEMS.find(i => i.id === user.equippedItem);
          if (item) return item.value;
      }
      return COLORS.player;
  }, [user]);

  const playHover = useCallback(() => engine?.sound.playUIHover(), [engine]);
  const playClick = useCallback(() => engine?.sound.playUIClick(), [engine]);

  useEffect(() => {
    if (playerName) localStorage.setItem('diep_remix_name', playerName);
  }, [playerName]);

  useEffect(() => {
      const interval = setInterval(() => setCurrentTipIndex(prev => (prev + 1) % TIPS.length), 6000);
      return () => clearInterval(interval);
  }, []);

  useEffect(() => {
      const classes = Object.values(TankClass);
      const interval = setInterval(() => {
          setFeaturedClass(prev => {
              const idx = classes.indexOf(prev);
              return classes[(idx + 1) % classes.length];
          });
      }, 5000);
      return () => clearInterval(interval);
  }, []);

  useEffect(() => {
      const storedScores = localStorage.getItem('diep_clone_highscores');
      if (storedScores) { try { setHighScores(JSON.parse(storedScores)); } catch (e) {} }
      const storedSettings = localStorage.getItem('diep_clone_settings');
      if (storedSettings) { try { setSettings({ ...DEFAULT_SETTINGS, ...JSON.parse(storedSettings) }); } catch (e) {} }
      BackendService.getSession().then(res => { if (res.success && res.user) { setUser(res.user); setPlayerName(res.user.username); } });
  }, []);

  const updateSettings = (newSettings: Partial<GameSettings>) => {
      setSettings(prev => {
          const updated = { ...prev, ...newSettings };
          localStorage.setItem('diep_clone_settings', JSON.stringify(updated));
          return updated;
      });
  };

  useEffect(() => { if (engine) { engine.setDarkMode(settings.darkMode); engine.sound.setVolume(settings.volume); } }, [engine, settings]);
  const handleMouseMove = (e: React.MouseEvent) => { if (isPlaying) return; setMenuMousePos({ x: e.clientX, y: e.clientY }); };
  const handleLoginSuccess = (loggedInUser: User) => { setUser(loggedInUser); setPlayerName(loggedInUser.username); };
  const handleLogout = () => { playClick(); BackendService.logout(); setUser(null); setPlayerName(''); };

  const handleGameOver = useCallback(async (score: number, level: number, classType: TankClass) => {
      if (gameMode === GameMode.SANDBOX) return;
      const entry: HighScoreEntry = { name: playerName || 'Guest', score, level, classType, date: new Date().toISOString() };
      setHighScores(prev => {
          const newScores = [...prev, entry].sort((a, b) => b.score - a.score).slice(0, 20); 
          localStorage.setItem('diep_clone_highscores', JSON.stringify(newScores));
          return newScores;
      });
      const kills = Math.floor(score / 1500);
      setMissions(prev => prev.map(m => {
          if (m.claimed) return m;
          let newProgress = m.progress;
          if (m.text.includes("Play")) newProgress += 1;
          else if (m.text.includes("Score")) newProgress += score;
          else if (m.text.includes("Reach Level")) { if (level > newProgress) newProgress = level; }
          return { ...m, progress: Math.min(newProgress, m.total) };
      }));
      if (user) {
          const updatedUser = await BackendService.updateUserStats(user.username, { totalGames: 1, totalScore: score, highScore: score, maxLevel: level, totalKills: kills, totalDeaths: 1 });
          if (updatedUser) setUser(updatedUser);
      }
  }, [playerName, user, gameMode]);

  const handleStateUpdate = useCallback((newState: GameState) => setGameState(newState), []);
  const handleUpgradeStat = (stat: StatType) => engine?.upgradeStat(engine.player, stat);
  const handleUpgradeClass = (cls: TankClass) => engine?.upgradeClass(cls);

  const handleStartGame = (e: React.FormEvent) => {
    e.preventDefault();
    playClick();
    if (engine) {
        engine.setPlayerName(playerName || 'Guest');
        engine.setGameMode(gameMode);
        if (gameMode !== GameMode.TEAMS) engine.setPlayerColor(activeColor);
        else engine.setPlayerTeam(selectedTeam);
        engine.resetPlayer(false);
        setIsPlaying(true);
    }
  };

  const handleRestart = () => { playClick(); if (engine) { engine.resetPlayer(true); setIsPlaying(true); } };
  const handleBackToMenu = () => { playClick(); setIsPlaying(false); engine?.setAttractMode(true); };
  const handleModeSelect = (mode: GameMode) => { playClick(); setGameMode(mode); };

  const handleClaimMission = (id: number) => {
      playClick();
      const mission = missions.find(m => m.id === id);
      if (!mission || mission.claimed || mission.progress < mission.total) return;
      setMissions(prev => prev.map(m => m.id === id ? { ...m, claimed: true } : m));
      if (user) BackendService.updateUserStats(user.username, {}, mission.rewardValue).then(updatedUser => { if (updatedUser) setUser(updatedUser); });
  };

  const currentStats = user ? user.stats : { totalScore: 0, totalGames: 0, maxLevel: 1, totalKills: 0, totalDeaths: 0 };
  const kdRatio = currentStats.totalDeaths > 0 ? (currentStats.totalKills / currentStats.totalDeaths).toFixed(2) : currentStats.totalKills.toFixed(2);
  const tankColor = gameMode === GameMode.TEAMS ? (selectedTeam === Team.BLUE ? COLORS.player : COLORS.enemy) : activeColor;

  const getRotationToMouse = () => {
      if (!containerRef.current) return 0;
      const rect = containerRef.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      const angle = Math.atan2(menuMousePos.y - centerY, menuMousePos.x - centerX);
      return angle * (180 / Math.PI);
  };

  return (
    <div ref={containerRef} onMouseMove={handleMouseMove} className={`relative w-screen h-screen overflow-hidden font-ubuntu transition-colors duration-700 ${settings.darkMode ? 'bg-[#020202]' : 'bg-[#e5e5e5]'}`}>
      <GameCanvas onStateUpdate={handleStateUpdate} onEngineInit={setEngine} onGameOver={handleGameOver} gameMode={gameMode} />
      {isPlaying && gameState && (
        <UIOverlay gameState={gameState} onUpgradeStat={handleUpgradeStat} onUpgradeClass={handleUpgradeClass} onRestart={handleRestart} onExit={handleBackToMenu} highScores={highScores} playHover={playHover} engine={engine} />
      )}
      <div className={`absolute inset-0 z-50 flex flex-col items-center justify-between py-6 px-6 md:px-12 bg-gradient-to-b from-black/80 via-transparent to-black/90 backdrop-blur-[1px] transition-all duration-1000 ease-in-out transform ${isPlaying ? 'opacity-0 scale-105 pointer-events-none filter blur-3xl' : 'opacity-100 scale-100'}`}>
             <div className="absolute inset-0 pointer-events-none overflow-hidden opacity-[0.03]"><div className="w-full h-[1px] bg-white animate-[scan_6s_linear_infinite]" /></div>

             {/* Header */}
             <div className="w-full max-w-[1440px] flex justify-between items-center animate-in slide-in-from-top-12 duration-700 z-10 shrink-0">
                <div className="flex items-center gap-4">
                    <div className="flex items-center gap-4 p-2 pl-4 pr-3 rounded-xl bg-black/60 border border-white/10 backdrop-blur-2xl hover:border-cyan-500/30 transition-all duration-300">
                        <div className="w-10 h-10 rounded-lg bg-[#111] border border-white/10 flex items-center justify-center text-cyan-400 font-black">{user ? user.username.charAt(0).toUpperCase() : '?'}</div>
                        <div className="flex flex-col"><span className="text-[10px] font-black text-white tracking-widest truncate max-w-[120px]">{user ? user.username : (playerName || 'GUEST_SIGNAL')}</span><span className="text-[8px] font-black text-cyan-500/80 uppercase">LV.{currentStats.maxLevel} • {kdRatio} K/D</span></div>
                        <button onClick={() => user ? handleLogout() : setShowLogin(true)} className="ml-2 p-2 rounded-lg bg-white/5 hover:bg-white/10 text-white/40 hover:text-white transition-colors"><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d={user ? "M17 16l4-4m0 0l-4-4m4 4H7" : "M11 16l-4-4m0 0l4-4m-4 4h14"} /></svg></button>
                    </div>
                </div>
                <div className="flex gap-4">
                    <div className="hidden sm:flex items-center gap-3 px-4 py-2 rounded-xl bg-black/60 border border-white/10 backdrop-blur-2xl hover:border-green-500/30 transition-all duration-300 group">
                        <span className="text-[9px] font-black text-white/40 uppercase tracking-widest">{selectedServer} NODE</span>
                        <div className="flex items-center gap-1.5 px-2 py-0.5 rounded bg-green-500/10 border border-green-500/30 group-hover:bg-green-500/20 transition-all">
                            <div className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse"></div>
                            <span className="text-[9px] font-black text-green-400 font-mono">24MS</span>
                        </div>
                    </div>
                    <div className="flex gap-2">
                        <button onClick={() => { playClick(); setShowAlmanac(true); }} className="p-3 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 text-white/60 hover:text-white transition-all hover:scale-110 active:scale-95 shadow-lg"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg></button>
                        <button onClick={() => { playClick(); setShowSettings(true); }} className="p-3 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 text-white/60 hover:text-white transition-all hover:scale-110 active:scale-95 shadow-lg"><svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg></button>
                    </div>
                </div>
             </div>

             {/* Main Content Area */}
             <div className="flex-1 w-full max-w-[1440px] grid grid-cols-1 lg:grid-cols-4 gap-8 items-center justify-items-stretch overflow-hidden">

                {/* Left Sidebar */}
                <div className="hidden lg:flex flex-col gap-4 animate-in slide-in-from-left-20 duration-1000 delay-300">
                    <span className="text-[10px] font-black text-cyan-500 uppercase tracking-[0.4em] mb-2 px-2 opacity-60">Network_Intel</span>
                    <div className="space-y-4">
                        {NEWS.map((news, idx) => (
                            <div key={news.id} style={{ animationDelay: `${400 + idx * 100}ms` }} className="p-4 rounded-2xl bg-white/[0.03] border border-white/10 backdrop-blur-md group hover:bg-white/[0.08] hover:border-cyan-500/20 hover:-translate-y-1 transition-all duration-300 cursor-pointer shadow-xl animate-in fade-in slide-in-from-left-8">
                                <div className="flex items-center justify-between mb-2"><span className="text-[8px] font-black bg-red-600 text-white px-1.5 py-0.5 rounded tracking-widest">{news.date}</span><span className="text-[10px] font-black text-white/80 tracking-tighter uppercase">{news.title}</span></div>
                                <p className="text-[10px] text-white/40 leading-relaxed font-medium group-hover:text-white/60 transition-colors">{news.content}</p>
                            </div>
                        ))}
                    </div>
                    {user && <button onClick={() => { playClick(); setShowShop(true); }} className="mt-4 p-5 rounded-2xl bg-gradient-to-br from-yellow-500 to-amber-600 text-black font-black text-xs uppercase tracking-widest shadow-[0_10px_30px_rgba(245,158,11,0.3)] hover:scale-[1.05] hover:shadow-[0_15px_40px_rgba(245,158,11,0.5)] active:scale-95 transition-all duration-300 animate-in fade-in slide-in-from-left-12 delay-700">ENTER ARMORY ({user.currency})</button>}
                </div>

                {/* Center Main Panel */}
                <div className="lg:col-span-2 flex flex-col items-center justify-center gap-6 md:gap-10 h-full overflow-hidden">
                    <div className="relative text-center select-none group animate-in zoom-in-95 fade-in duration-1000">
                        <h1 className="text-[clamp(4rem,12vh,10rem)] font-black text-[#00b2e1] italic tracking-tighter drop-shadow-[0_15px_40px_rgba(0,178,225,0.4)] leading-[0.85] transition-transform group-hover:scale-110 duration-1000 ease-out" style={{ WebkitTextStroke: '3px #000' }}>DIEP</h1>
                        <div className="flex items-center justify-center gap-4 mt-2 animate-in slide-in-from-bottom-4 duration-1000 delay-500">
                            <div className="h-[2px] w-12 bg-red-600/60 transition-all group-hover:w-20"></div>
                            <h2 className="text-xl md:text-2xl font-black italic tracking-[0.4em] text-white/40 uppercase group-hover:text-white/60 transition-colors">REMIX</h2>
                            <div className="h-[2px] w-12 bg-red-600/60 transition-all group-hover:w-20"></div>
                        </div>
                    </div>

                    <div className={`w-full max-w-lg p-8 md:p-10 rounded-[2.5rem] shadow-[0_30px_100px_rgba(0,0,0,0.5)] border-2 flex flex-col items-center relative overflow-hidden backdrop-blur-3xl animate-in slide-in-from-bottom-20 fade-in duration-1000 delay-700 ${settings.darkMode ? 'bg-white/[0.02] border-white/10' : 'bg-white border-black/10'}`}>
                        <div className="w-full mb-8 flex p-1.5 rounded-2xl bg-black/60 border border-white/5 animate-in fade-in delay-1000 duration-500">
                            {[GameMode.FFA, GameMode.TEAMS, GameMode.SANDBOX].map((mode, idx) => {
                                const label = mode === GameMode.FFA ? 'FFA' : mode === GameMode.TEAMS ? 'TEAMS' : 'SANDBOX';
                                return (
                                    <button key={mode} onClick={() => handleModeSelect(mode)} className={`flex-1 py-3 rounded-xl font-black text-[9px] uppercase tracking-[0.2em] transition-all duration-300 ${gameMode === mode ? 'bg-gradient-to-br from-blue-500 to-indigo-700 text-white shadow-lg scale-105 z-10' : 'text-white/40 hover:text-white/60 hover:bg-white/5'}`}>
                                        {label}
                                    </button>
                                );
                            })}
                        </div>
                        <form onSubmit={handleStartGame} className="w-full space-y-8 animate-in fade-in delay-[1200ms] duration-700">
                            <div className="relative group/input">
                                <input type="text" placeholder="IDENTIFY_CMD" value={playerName} onChange={(e) => setPlayerName(e.target.value)} disabled={!!user} className={`w-full px-6 py-4 md:py-5 border-2 rounded-2xl text-center font-black text-xl md:text-2xl focus:outline-none transition-all duration-300 uppercase tracking-[0.2em] ${settings.darkMode ? 'bg-black/60 border-white/10 text-cyan-400 focus:border-cyan-400 focus:bg-cyan-500/5' : 'bg-gray-100 border-gray-300 text-gray-900 focus:border-blue-500'} ${user ? 'opacity-50 cursor-not-allowed' : 'group-hover/input:border-white/20'}`} maxLength={15} />
                                {!user && <div className="absolute inset-0 rounded-2xl bg-cyan-500/5 opacity-0 group-hover/input:opacity-100 transition-opacity pointer-events-none"></div>}
                            </div>
                            <div className="flex flex-col items-center justify-center py-4">
                                {gameMode === GameMode.TEAMS ? (
                                    <button type="button" onClick={() => { playClick(); setSelectedTeam(prev => prev === Team.BLUE ? Team.RED : Team.BLUE); }} className={`group relative flex items-center gap-8 px-10 py-5 rounded-[2rem] border-2 transition-all duration-500 hover:scale-[1.03] ${selectedTeam === Team.BLUE ? 'bg-blue-500/10 border-blue-500/50 text-blue-400 shadow-[0_0_30px_rgba(59,130,246,0.2)]' : 'bg-red-500/10 border-red-500/50 text-red-400 shadow-[0_0_30px_rgba(239,68,68,0.2)]'}`}>
                                        <div className={`w-14 h-14 rounded-full flex items-center justify-center ${selectedTeam === Team.BLUE ? 'bg-blue-500' : 'bg-red-500'} shadow-lg transform group-hover:scale-110 transition-transform duration-500`}>
                                            <div style={{ transform: `rotate(${getRotationToMouse()}deg)` }} className="transition-transform duration-75"><TankPreview tankClass={TankClass.BASIC} color={tankColor} size={48} /></div>
                                        </div>
                                        <div className="text-left"><span className="text-[10px] font-black opacity-40 uppercase tracking-[0.4em] mb-1">Target Sector</span><div className="text-2xl font-black uppercase italic tracking-tighter">{selectedTeam} FORCE</div></div>
                                    </button>
                                ) : (
                                    <div className="relative group cursor-pointer" onClick={() => user && setShowShop(true)}>
                                        <div className="absolute -inset-10 bg-cyan-500/5 rounded-full blur-[40px] opacity-0 group-hover:opacity-100 group-hover:bg-cyan-500/15 transition-all duration-700"></div>
                                        <div style={{ transform: `rotate(${getRotationToMouse()}deg)` }} className="relative z-10 transition-transform duration-75 group-hover:scale-110"><TankPreview tankClass={TankClass.BASIC} color={tankColor} size={110} /></div>
                                        <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 text-[8px] font-black text-cyan-500/40 uppercase tracking-[0.5em] opacity-0 group-hover:opacity-100 translate-y-2 group-hover:translate-y-0 transition-all duration-500">MOD_CHASSIS</div>
                                    </div>
                                )}
                            </div>
                            <button type="submit" onMouseEnter={() => playHover()} className="group relative w-full py-6 md:py-7 rounded-[2rem] bg-gradient-to-b from-cyan-400 to-blue-700 overflow-hidden transition-all duration-500 hover:scale-[1.02] hover:shadow-[0_25px_80px_-15px_rgba(0,178,225,0.7)] active:scale-[0.96] shadow-[0_20px_60px_-15px_rgba(0,178,225,0.6)] border-b-8 border-blue-900 active:border-b-4 active:translate-y-1">
                                <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                <span className="relative z-10 text-3xl md:text-4xl font-black text-white italic tracking-[0.3em] drop-shadow-lg">{gameMode === GameMode.SANDBOX ? 'DEBUG' : 'ENGAGE'}</span>
                            </button>
                        </form>
                    </div>
                </div>

                {/* Right Sidebar */}
                <div className="hidden lg:flex flex-col gap-4 animate-in slide-in-from-right-20 duration-1000 delay-300">
                    <span className="text-[10px] font-black text-orange-500 uppercase tracking-[0.4em] mb-2 px-2 text-right opacity-60">Combat_Ops</span>
                    <div className="space-y-4">
                        {missions.map((m, idx) => (
                            <div key={m.id} style={{ animationDelay: `${500 + idx * 100}ms` }} className="p-4 rounded-2xl bg-white/[0.03] border border-white/10 backdrop-blur-md group hover:bg-white/[0.08] hover:border-orange-500/30 transition-all duration-300 hover:translate-x-1 shadow-xl animate-in fade-in slide-in-from-right-8">
                                <div className="flex justify-between items-center mb-3"><span className="text-[9px] font-black text-white/80 uppercase tracking-tighter">{m.text}</span><span className="text-[8px] font-mono text-white/30">{m.progress}/{m.total}</span></div>
                                <div className="h-[3px] w-full bg-black/40 rounded-full overflow-hidden">
                                    <div className="h-full bg-orange-600 shadow-[0_0_8px_#ea580c] transition-all duration-1000" style={{ width: `${(m.progress/m.total)*100}%` }}></div>
                                </div>
                                {m.progress >= m.total && !m.claimed && <button onClick={() => handleClaimMission(m.id)} className="w-full mt-3 py-1.5 rounded-lg bg-orange-600/20 hover:bg-orange-600 text-orange-500 hover:text-white text-[9px] font-black uppercase tracking-widest transition-all duration-300 shadow-md">CLAIM_REWARD</button>}
                            </div>
                        ))}
                    </div>
                    <div className="mt-6 p-5 rounded-[2rem] border-2 border-white/5 bg-black/40 backdrop-blur-3xl flex items-center gap-6 group hover:border-cyan-500/40 hover:bg-cyan-500/5 transition-all duration-500 animate-in fade-in slide-in-from-right-12 delay-[800ms] shadow-2xl">
                        <div className="p-3 rounded-xl bg-white/5 group-hover:rotate-12 group-hover:scale-110 transition-all duration-500"><TankPreview tankClass={featuredClass} size={36} color={tankColor} /></div>
                        <div className="flex flex-col"><span className="text-[8px] font-black text-cyan-500 uppercase tracking-widest mb-1 opacity-60">Highlight</span><span className="text-lg font-black text-white italic truncate leading-none transition-colors group-hover:text-cyan-400">{featuredClass.replace(' Tank', '')}</span></div>
                    </div>
                </div>
             </div>

             {/* Bottom Bar */}
             <div className="w-full max-w-[1440px] flex flex-col md:flex-row justify-between items-center gap-6 animate-in slide-in-from-bottom-12 duration-1000 delay-[1000ms] z-10 shrink-0">
                <div className="flex items-center gap-4 px-8 py-3 rounded-full bg-black/60 border border-white/10 backdrop-blur-2xl hover:border-white/20 transition-all duration-500">
                    <div className="w-1.5 h-1.5 rounded-full bg-cyan-400 animate-pulse"></div>
                    <span className="text-[10px] font-black text-white/60 tracking-wider uppercase italic">{TIPS[currentTipIndex]}</span>
                </div>
                <div className="flex gap-10 px-6">
                    {['Discord', 'GitHub', 'Wiki'].map(link => (
                        <a key={link} href="#" className="text-[10px] font-black text-white/20 hover:text-cyan-400 uppercase tracking-[0.4em] transition-all hover:scale-110 hover:-translate-y-0.5">{link}</a>
                    ))}
                </div>
             </div>

             {/* Modals */}
             {showLogin && <LoginModal onClose={() => setShowLogin(false)} onLoginSuccess={handleLoginSuccess} darkMode={settings.darkMode} />}
             {showShop && <ShopModal user={user} onClose={() => setShowShop(false)} onUpdateUser={setUser} darkMode={settings.darkMode} playSound={playClick} />}
             {showAlmanac && <AlmanacModal onClose={() => setShowAlmanac(false)} darkMode={settings.darkMode} playSound={playClick} />}
             {showSettings && (
                 <div className="absolute inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-md animate-in fade-in duration-500">
                     <div className={`w-full max-w-md p-10 rounded-[3rem] shadow-[0_0_80px_rgba(0,0,0,1)] border-2 relative animate-in zoom-in-95 duration-500 ${settings.darkMode ? 'bg-[#050505] border-white/10' : 'bg-white border-black/10'}`}>
                        <button onClick={() => setShowSettings(false)} className="absolute top-8 right-8 p-3 hover:bg-white/10 rounded-xl transition-all group active:scale-90"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-500 group-hover:text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
                        <h2 className="text-3xl font-black mb-10 text-center tracking-tighter italic uppercase text-white">System Config</h2>
                        <div className="space-y-8">
                            <div className="flex items-center justify-between p-5 rounded-2xl bg-white/[0.02] border border-white/5 group hover:bg-white/[0.05] transition-all"><div className="flex flex-col"><span className="font-black text-sm uppercase text-gray-200 tracking-widest">Protocol Dark</span><span className="text-[10px] font-bold text-gray-500 uppercase mt-1">Holographic Mode</span></div><button onClick={() => { playClick(); updateSettings({ darkMode: !settings.darkMode }); }} className={`w-16 h-9 rounded-full p-1.5 transition-all duration-500 ${settings.darkMode ? 'bg-cyan-500 shadow-[0_0_15px_#22d3ee]' : 'bg-gray-700'}`}><div className={`w-6 h-6 rounded-full bg-white transition-all transform duration-500 ${settings.darkMode ? 'translate-x-7' : ''}`} /></button></div>
                            <div className="space-y-6 p-5 rounded-2xl bg-white/[0.02] border border-white/5 group hover:bg-white/[0.05] transition-all"><div className="flex justify-between items-end"><div className="flex flex-col"><span className="font-black text-sm uppercase text-gray-200 tracking-widest">Audio Array</span><span className="text-[10px] font-bold text-gray-500 mt-1">Signal Strength</span></div><span className="text-2xl font-black text-cyan-400 font-mono transition-all group-hover:scale-110">{Math.round(settings.volume * 100)}%</span></div><input type="range" min="0" max="1" step="0.01" value={settings.volume} onChange={(e) => updateSettings({ volume: parseFloat(e.target.value) })} className="w-full h-2 bg-black rounded-lg accent-cyan-500 appearance-none cursor-pointer border border-white/10" /></div>
                        </div>
                        <button onClick={() => { playClick(); setShowSettings(false); }} className="w-full mt-10 py-5 bg-gradient-to-r from-cyan-600 to-blue-700 text-white font-black rounded-2xl shadow-xl hover:from-cyan-500 hover:to-blue-600 transition-all uppercase tracking-[0.4em] text-sm border border-white/10 active:scale-95">SYNC_CHANGES</button>
                     </div>
                 </div>
             )}
        </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameMode, GameState, HighScoreEntry, StatType, TankClass, User, Team } from './types';
import { GameEngine } from './services/GameEngine';
import { BackendService } from './services/BackendService';
import { LoginModal } from './components/LoginModal';
import { ShopModal } from './components/ShopModal';
import { AlmanacModal } from './components/AlmanacModal';
import { COLORS, SHOP_ITEMS } from './constants';
import { TankPreview } from './components/TankPreview';

interface GameSettings {
    volume: number;
    darkMode: boolean;
}

const DEFAULT_SETTINGS: GameSettings = {
    volume: 0.15,
    darkMode: true
};

interface Mission {
    id: number;
    text: string;
    progress: number;
    total: number;
    reward: string;
    rewardValue: number;
    claimed: boolean;
}

const INITIAL_MISSIONS: Mission[] = [
    { id: 1, text: "Play 3 Games", progress: 0, total: 3, reward: "250 DC", rewardValue: 250, claimed: false },
    { id: 2, text: "Reach Level 20", progress: 0, total: 20, reward: "350 DC", rewardValue: 350, claimed: false },
    { id: 3, text: "Earn 10k Score", progress: 0, total: 10000, reward: "750 DC", rewardValue: 750, claimed: false },
];

const TIPS = [
    "Press 'E' for Auto-Fire",
    "Pentagon Nest is high-risk, high-reward",
    "Body Damage protects against collisions",
    "Recoil can be used as a speed boost",
    "Sandbox Mode allows instant class switching"
];

const NEWS = [
    { id: 1, title: "SANDBOX MODE", date: "NEW", content: "Test mechanics in a private dev sector." },
    { id: 2, title: "Remaster v1.6", date: "Today", content: "Physics and console commands synced." },
];

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [engine, setEngine] = useState<GameEngine | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [playerName, setPlayerName] = useState(() => localStorage.getItem('diep_remix_name') || '');
  const [highScores, setHighScores] = useState<HighScoreEntry[]>([]);
  const [settings, setSettings] = useState<GameSettings>(DEFAULT_SETTINGS);
  const [missions, setMissions] = useState<Mission[]>(INITIAL_MISSIONS);

  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showShop, setShowShop] = useState(false);
  const [showAlmanac, setShowAlmanac] = useState(false);

  const [featuredClass, setFeaturedClass] = useState<TankClass>(TankClass.BASIC);
  const [selectedServer] = useState("US East");
  const [currentTipIndex, setCurrentTipIndex] = useState(0);
  const [gameMode, setGameMode] = useState<GameMode>(GameMode.FFA);
  const [selectedTeam, setSelectedTeam] = useState<Team>(Team.BLUE);

  const [menuMousePos, setMenuMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  // Parallax Calculation
  const parallax = useMemo(() => {
    const x = (menuMousePos.x / window.innerWidth - 0.5) * 2;
    const y = (menuMousePos.y / window.innerHeight - 0.5) * 2;
    return { x, y };
  }, [menuMousePos]);

  const activeColor = useMemo(() => {
      if (user && user.equippedItem) {
          const item = SHOP_ITEMS.find(i => i.id === user.equippedItem);
          if (item) return item.value;
      }
      return COLORS.player;
  }, [user]);

  const playHover = useCallback(() => engine?.sound.playUIHover(), [engine]);
  const playClick = useCallback(() => engine?.sound.playUIClick(), [engine]);

  useEffect(() => {
    if (playerName) localStorage.setItem('diep_remix_name', playerName);
  }, [playerName]);

  useEffect(() => {
      const interval = setInterval(() => setCurrentTipIndex(prev => (prev + 1) % TIPS.length), 6000);
      return () => clearInterval(interval);
  }, []);

  useEffect(() => {
      const classes = Object.values(TankClass);
      const interval = setInterval(() => {
          setFeaturedClass(prev => {
              const idx = classes.indexOf(prev);
              return classes[(idx + 1) % classes.length];
          });
      }, 5000);
      return () => clearInterval(interval);
  }, []);

  useEffect(() => {
      const storedScores = localStorage.getItem('diep_clone_highscores');
      if (storedScores) { try { setHighScores(JSON.parse(storedScores)); } catch (e) {} }
      const storedSettings = localStorage.getItem('diep_clone_settings');
      if (storedSettings) { try { setSettings({ ...DEFAULT_SETTINGS, ...JSON.parse(storedSettings) }); } catch (e) {} }
      BackendService.getSession().then(res => { if (res.success && res.user) { setUser(res.user); setPlayerName(res.user.username); } });
  }, []);

  const updateSettings = (newSettings: Partial<GameSettings>) => {
      setSettings(prev => {
          const updated = { ...prev, ...newSettings };
          localStorage.setItem('diep_clone_settings', JSON.stringify(updated));
          return updated;
      });
  };

  useEffect(() => { if (engine) { engine.setDarkMode(settings.darkMode); engine.sound.setVolume(settings.volume); } }, [engine, settings]);

  const handleMouseMove = (e: React.MouseEvent) => { 
    if (isPlaying) return; 
    setMenuMousePos({ x: e.clientX, y: e.clientY }); 
  };

  const handleLoginSuccess = (loggedInUser: User) => { setUser(loggedInUser); setPlayerName(loggedInUser.username); };
  const handleLogout = () => { playClick(); BackendService.logout(); setUser(null); setPlayerName(''); };

  const handleGameOver = useCallback(async (score: number, level: number, classType: TankClass) => {
      if (gameMode === GameMode.SANDBOX) return;
      const entry: HighScoreEntry = { name: playerName || 'Guest', score, level, classType, date: new Date().toISOString() };
      setHighScores(prev => {
          const newScores = [...prev, entry].sort((a, b) => b.score - a.score).slice(0, 20); 
          localStorage.setItem('diep_clone_highscores', JSON.stringify(newScores));
          return newScores;
      });
      const kills = Math.floor(score / 1500);
      setMissions(prev => prev.map(m => {
          if (m.claimed) return m;
          let newProgress = m.progress;
          if (m.text.includes("Play")) newProgress += 1;
          else if (m.text.includes("Score")) newProgress += score;
          else if (m.text.includes("Reach Level")) { if (level > newProgress) newProgress = level; }
          return { ...m, progress: Math.min(newProgress, m.total) };
      }));
      if (user) {
          const updatedUser = await BackendService.updateUserStats(user.username, { totalGames: 1, totalScore: score, highScore: score, maxLevel: level, totalKills: kills, totalDeaths: 1 });
          if (updatedUser) setUser(updatedUser);
      }
  }, [playerName, user, gameMode]);

  const handleStateUpdate = useCallback((newState: GameState) => setGameState(newState), []);
  const handleUpgradeStat = (stat: StatType) => engine?.upgradeStat(engine.player, stat);
  const handleUpgradeClass = (cls: TankClass) => engine?.upgradeClass(cls);

  const handleStartGame = (e: React.FormEvent) => {
    e.preventDefault();
    playClick();
    if (engine) {
        engine.setPlayerName(playerName || 'Guest');
        engine.setGameMode(gameMode);
        if (gameMode !== GameMode.TEAMS) engine.setPlayerColor(activeColor);
        else engine.setPlayerTeam(selectedTeam);
        engine.resetPlayer(false);
        setIsPlaying(true);
    }
  };

  const handleRestart = () => { playClick(); if (engine) { engine.resetPlayer(true); setIsPlaying(true); } };
  const handleBackToMenu = () => { playClick(); setIsPlaying(false); engine?.setAttractMode(true); };
  const handleModeSelect = (mode: GameMode) => { playClick(); setGameMode(mode); };

  const handleClaimMission = (id: number) => {
      playClick();
      const mission = missions.find(m => m.id === id);
      if (!mission || mission.claimed || mission.progress < mission.total) return;
      setMissions(prev => prev.map(m => {
          if (m.id === id) return { ...m, claimed: true };
          return m;
      }));
      if (user) BackendService.updateUserStats(user.username, {}, mission.rewardValue).then(updatedUser => { if (updatedUser) setUser(updatedUser); });
  };

  const currentStats = user ? user.stats : { totalScore: 0, totalGames: 0, maxLevel: 1, totalKills: 0, totalDeaths: 0 };
  const kdRatio = currentStats.totalDeaths > 0 ? (currentStats.totalKills / currentStats.totalDeaths).toFixed(2) : currentStats.totalKills.toFixed(2);
  const tankColor = gameMode === GameMode.TEAMS ? (selectedTeam === Team.BLUE ? COLORS.player : COLORS.enemy) : activeColor;

  const getRotationToMouse = () => {
      if (!containerRef.current) return 0;
      const rect = containerRef.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      const angle = Math.atan2(menuMousePos.y - centerY, menuMousePos.x - centerX);
      return angle * (180 / Math.PI);
  };

  return (
    <div 
        ref={containerRef} 
        onMouseMove={handleMouseMove} 
        className={`relative w-screen h-screen overflow-hidden font-ubuntu transition-colors duration-1000 ${settings.darkMode ? 'bg-[#020202]' : 'bg-[#e5e5e5]'}`}
    >
      <GameCanvas onStateUpdate={handleStateUpdate} onEngineInit={setEngine} onGameOver={handleGameOver} gameMode={gameMode} />

      {isPlaying && gameState && (
        <UIOverlay gameState={gameState} onUpgradeStat={handleUpgradeStat} onUpgradeClass={handleUpgradeClass} onRestart={handleRestart} onExit={handleBackToMenu} highScores={highScores} playHover={playHover} engine={engine} />
      )}

      {/* Main UI Container with dynamic blur and fade */}
      <div className={`absolute inset-0 z-50 flex flex-col items-center justify-between py-8 px-6 md:px-12 bg-gradient-to-b from-black/80 via-transparent to-black/90 backdrop-blur-[2px] transition-all duration-1000 ease-in-out transform ${isPlaying ? 'opacity-0 scale-105 pointer-events-none filter blur-3xl' : 'opacity-100 scale-100'}`}>

             {/* Background Animated Grid Overlay */}
             <div 
                className="absolute inset-0 pointer-events-none opacity-[0.05] transition-transform duration-500 ease-out"
                style={{ transform: `translate(${parallax.x * 20}px, ${parallax.y * 20}px) scale(1.1)` }}
             >
                <div className="w-full h-full border-white/20 border-[1px] grid grid-cols-12 grid-rows-12">
                    {[...Array(144)].map((_, i) => <div key={i} className="border-white/5 border-[0.5px]"></div>)}
                </div>
                <div className="absolute inset-0 w-full h-[2px] bg-cyan-500/20 animate-[scan_8s_linear_infinite]" />
             </div>

             {/* Header */}
             <div className="w-full max-w-[1600px] flex justify-between items-center animate-in slide-in-from-top-12 duration-1000 z-10 shrink-0">
                <div className="flex items-center gap-4 group">
                    <div className="flex items-center gap-4 p-2 pl-4 pr-3 rounded-2xl bg-black/80 border border-white/10 backdrop-blur-3xl hover:border-cyan-500/50 hover:shadow-[0_0_30px_rgba(34,211,238,0.2)] transition-all duration-500 transform hover:-translate-y-1">
                        <div className="w-12 h-12 rounded-xl bg-[#111] border border-white/10 flex items-center justify-center text-cyan-400 font-black text-xl shadow-inner relative overflow-hidden">
                            <div className="absolute inset-0 bg-cyan-400/5 animate-pulse-glow"></div>
                            <span className="relative z-10">{user ? user.username.charAt(0).toUpperCase() : '?'}</span>
                        </div>
                        <div className="flex flex-col">
