                                <div className="flex justify-between items-end">
                                    <div className="flex flex-col">
                                        <span className="font-black text-lg uppercase text-white tracking-[0.2em] group-hover:text-cyan-400 transition-colors">Audio_Array</span>
                                        <span className="text-[10px] font-bold text-gray-500 mt-2 tracking-[0.3em] uppercase">Master Gain Level</span>
                                    </div>
                                    <span className="text-3xl font-black text-cyan-400 font-mono transition-all duration-500 group-hover:scale-110 shadow-cyan-500/20 drop-shadow-xl">{Math.round(settings.volume * 100)}%</span>
                                </div>
                                <div className="relative h-4 flex items-center">
                                    <div className="absolute inset-0 bg-black/40 rounded-full border border-white/10"></div>
                                    <input 
                                        type="range" min="0" max="1" step="0.01" 
                                        value={settings.volume} 
                                        onChange={(e) => updateSettings({ volume: parseFloat(e.target.value) })} 
                                        className="relative w-full h-full bg-transparent accent-cyan-500 appearance-none cursor-pointer z-10" 
                                    />
                                    <div className="absolute left-0 h-full bg-cyan-500 rounded-full pointer-events-none shadow-[0_0_15px_#06b6d4]" style={{ width: `${settings.volume * 100}%` }}></div>
                                </div>
                            </div>
                        </div>

                        <button 
                            onClick={() => { playClick(); setShowSettings(false); }} 
                            className="group sweep-container w-full mt-16 py-8 bg-gradient-to-r from-cyan-600 to-blue-800 text-white font-black rounded-[2.5rem] shadow-2xl hover:from-cyan-500 hover:to-blue-700 transition-all duration-700 uppercase tracking-[0.6em] text-sm border-b-8 border-blue-950 active:border-b-4 active:translate-y-2 active:scale-95"
                        >
                            <div className="sweep-effect"></div>
                            SYNC_SYSTEM_STATE
                        </button>
                     </div>
                 </div>
             )}
        </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameMode, GameState, HighScoreEntry, StatType, TankClass, User, Team } from './types';
import { GameEngine } from './services/GameEngine';
import { BackendService } from './services/BackendService';
import { LoginModal } from './components/LoginModal';
import { ShopModal } from './components/ShopModal';
import { AlmanacModal } from './components/AlmanacModal';
import { COLORS, SHOP_ITEMS } from './constants';
