                        </button>
                    )}
                </div>

                {/* Center Main Panel */}
                <div className="lg:col-span-3 flex flex-col items-center justify-center gap-12 h-full overflow-hidden">
                    <div className="relative text-center select-none group transition-transform duration-700 ease-out animate-in zoom-in-95 fade-in duration-1000" style={{ transform: `translate(${parallax.x * -20}px, ${parallax.y * -20}px)` }}>
