                            ))}
                        </div>

                        <form onSubmit={handleStartGame} className="w-full space-y-10 relative z-10 animate-in fade-in delay-[1200ms] duration-1000">
                            <div className="relative group/input">
                                <input type="text" placeholder="COMMAND_ID" value={playerName} onChange={(e) => setPlayerName(e.target.value)} disabled={!!user} className={`w-full px-8 py-6 border-4 rounded-[2rem] text-center font-black text-2xl md:text-3xl focus:outline-none transition-all duration-500 uppercase tracking-[0.3em] shadow-inner ${settings.darkMode ? 'bg-black/60 border-white/5 text-cyan-400 focus:border-cyan-400 focus:bg-cyan-400/5' : 'bg-gray-100 border-gray-300 text-gray-900 focus:border-blue-500'} ${user ? 'opacity-50 cursor-not-allowed grayscale' : 'group-hover/input:border-white/20 group-hover/input:scale-[1.02]'}`} maxLength={15} />
                                {!user && <div className="absolute inset-0 rounded-[2rem] bg-cyan-400/5 opacity-0 group-hover/input:opacity-100 transition-opacity pointer-events-none blur-xl"></div>}
                            </div>

                            <div className="flex flex-col items-center justify-center py-6 h-48 relative">
                                {gameMode === GameMode.TEAMS ? (
                                    <button type="button" onClick={() => { playClick(); setSelectedTeam(prev => prev === Team.BLUE ? Team.RED : Team.BLUE); }} className={`group relative flex items-center gap-10 px-12 py-7 rounded-[2.5rem] border-4 transition-all duration-700 hover:scale-105 active:scale-95 ${selectedTeam === Team.BLUE ? 'bg-blue-500/10 border-blue-500/50 text-blue-400 shadow-[0_0_50px_rgba(59,130,246,0.3)]' : 'bg-red-500/10 border-red-500/50 text-red-400 shadow-[0_0_50px_rgba(239,68,68,0.3)]'}`}>
                                        <div className={`w-16 h-16 rounded-2xl flex items-center justify-center ${selectedTeam === Team.BLUE ? 'bg-blue-500 shadow-[0_0_20px_#3b82f6]' : 'bg-red-500 shadow-[0_0_20px_#ef4444]'} transform group-hover:rotate-[360deg] transition-transform duration-1000`}>
                                            <div style={{ transform: `rotate(${getRotationToMouse()}deg)` }} className="transition-transform duration-150"><TankPreview tankClass={TankClass.BASIC} color={selectedTeam === Team.BLUE ? COLORS.player : COLORS.enemy} size={50} /></div>
                                        </div>
                                        <div className="text-left flex flex-col"><span className="text-[10px] font-black opacity-40 uppercase tracking-[0.5em] mb-1">Target Sector</span><div className="text-3xl font-black uppercase italic tracking-tighter group-hover:tracking-widest transition-all duration-700">{selectedTeam} FORCE</div></div>
                                    </button>
                                ) : (
                                    <div className="relative group cursor-pointer animate-float" onClick={() => user && setShowShop(true)}>
                                        <div className="absolute inset-0 flex items-center justify-center opacity-20 animate-[rotate-slow_20s_linear_infinite]">
                                            <div className="w-56 h-56 border-[1px] border-cyan-400 rounded-[3rem] transform rotate-45 scale-125"></div>
                                            <div className="absolute w-48 h-48 border-[1px] border-indigo-400 rounded-full animate-[rotate-slow_15s_linear_infinite_reverse]"></div>
                                        </div>
                                        <div className="absolute -inset-16 bg-cyan-500/10 rounded-full blur-[60px] opacity-0 group-hover:opacity-100 group-hover:bg-cyan-500/20 transition-all duration-1000"></div>
                                        <div style={{ transform: `rotate(${getRotationToMouse()}deg)` }} className="relative z-10 transition-transform duration-150 group-hover:scale-125 drop-shadow-[0_0_25px_rgba(0,178,225,0.4)]"><TankPreview tankClass={TankClass.BASIC} color={activeColor} size={130} /></div>
                                        <div className="absolute -bottom-12 left-1/2 -translate-x-1/2 text-[9px] font-black text-cyan-400 uppercase tracking-[0.6em] opacity-40 group-hover:opacity-100 translate-y-4 group-hover:translate-y-0 transition-all duration-700 whitespace-nowrap">CUSTOM_CHASSIS_ACTIVE</div>
                                    </div>
                                )}
                            </div>

                            <button type="submit" onMouseEnter={() => playHover()} className="group sweep-container relative w-full py-8 md:py-9 rounded-[2.5rem] bg-gradient-to-b from-cyan-400 to-blue-800 overflow-hidden transition-all duration-700 hover:scale-[1.03] hover:shadow-[0_30px_100px_-10px_rgba(0,178,225,0.7)] active:scale-[0.96] shadow-[0_20px_60px_-15px_rgba(0,178,225,0.4)] border-b-[10px] border-blue-950 active:border-b-4 active:translate-y-1 animate-shake-power">
                                <div className="sweep-effect"></div>
                                <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                                <span className="relative z-10 text-4xl md:text-5xl font-black text-white italic tracking-[0.4em] drop-shadow-2xl group-hover:tracking-[0.5em] transition-all duration-700 uppercase">{gameMode === GameMode.SANDBOX ? 'DEBUG_BOOT' : 'ENGAGE_LINK'}</span>
                            </button>
                        </form>
                    </div>
                </div>

                {/* Right Sidebar */}
                <div className="hidden lg:flex flex-col gap-6 animate-in slide-in-from-right-20 duration-1000 delay-300">
                    <div className="flex items-center gap-3 px-2 justify-end">
                        <div className="h-px flex-1 bg-gradient-to-l from-orange-500/50 to-transparent"></div>
                        <span className="text-[11px] font-black text-orange-500 uppercase tracking-[0.5em] italic">Combat_Logs</span>
                    </div>
                    <div className="space-y-6">
                        {missions.map((m, idx) => (
                            <div key={m.id} style={{ animationDelay: `${600 + idx * 150}ms` }} className="p-6 rounded-[2rem] bg-white/[0.02] border border-white/5 backdrop-blur-2xl group hover:bg-white/[0.08] hover:border-orange-500/40 hover:translate-x-2 transition-all duration-500 shadow-2xl animate-in fade-in slide-in-from-right-12 relative">
                                <div className="tactical-corner -top-2 -right-2 border-t border-r"></div>
                                <div className="tactical-corner -bottom-2 -left-2 border-b border-l"></div>
                                <div className="flex justify-between items-center mb-4">
                                    <span className="text-[10px] font-black text-white/70 uppercase tracking-tighter group-hover:text-orange-400 transition-colors">{m.text}</span>
                                    <span className="text-[10px] font-mono text-white/30 tracking-widest">{m.progress}/{m.total}</span>
                                </div>
                                <div className="h-[4px] w-full bg-black/60 rounded-full overflow-hidden border border-white/5">
                                    <div className="h-full bg-gradient-to-r from-orange-600 to-orange-400 shadow-[0_0_15px_#ea580c] transition-all duration-1000 ease-out" style={{ width: `${(m.progress/m.total)*100}%` }}></div>
                                </div>
                                {m.progress >= m.total && !m.claimed && <button onClick={() => handleClaimMission(m.id)} className="w-full mt-4 py-3 rounded-xl bg-orange-600 text-white text-[10px] font-black uppercase tracking-widest transition-all duration-300 shadow-[0_10px_20px_rgba(234,88,12,0.3)] hover:scale-105 active:scale-95">RECLAIM_DATA</button>}
                            </div>
                        ))}
                    </div>
                    <div className="mt-8 p-6 rounded-[2.5rem] border-2 border-white/5 bg-black/60 backdrop-blur-3xl flex items-center gap-8 group hover:border-cyan-500/50 hover:bg-cyan-500/5 transition-all duration-1000 animate-in fade-in slide-in-from-right-12 delay-[800ms] shadow-2xl relative overflow-hidden">
                        <div className="absolute -top-10 -right-10 w-32 h-32 bg-cyan-500/5 rounded-full blur-3xl group-hover:bg-cyan-500/10"></div>
                        <div className="p-4 rounded-2xl bg-white/5 border border-white/10 group-hover:rotate-12 group-hover:scale-125 transition-all duration-700 shadow-inner"><TankPreview tankClass={featuredClass} size={50} color={activeColor} /></div>
                        <div className="flex flex-col relative z-10"><span className="text-[10px] font-black text-cyan-500 uppercase tracking-[0.4em] mb-2 opacity-60">Prototype_SDR</span><span className="text-2xl font-black text-white italic truncate leading-none transition-all group-hover:tracking-widest duration-700">{featuredClass.replace(' Tank', '').toUpperCase()}</span></div>
                    </div>
                </div>
             </div>

             {/* Bottom Bar */}
             <div className="w-full max-w-[1600px] flex flex-col md:flex-row justify-between items-center gap-10 animate-in slide-in-from-bottom-12 duration-1000 delay-[1000ms] z-10 shrink-0">
                <div className="flex items-center gap-6 px-10 py-4 rounded-full bg-black/80 border border-white/10 backdrop-blur-3xl hover:border-white/30 transition-all duration-1000 shadow-2xl group cursor-help">
                    <div className="w-2.5 h-2.5 rounded-full bg-cyan-400 animate-pulse shadow-[0_0_15px_#22d3ee]"></div>
                    <span className="text-[11px] font-black text-white/50 tracking-[0.3em] uppercase italic group-hover:text-white transition-colors duration-500">{TIPS[currentTipIndex]}</span>
                </div>
                <div className="flex gap-12 px-10">
                    {['Discord', 'GitHub', 'Wiki'].map(link => (
                        <a key={link} href="#" className="text-[11px] font-black text-white/10 hover:text-cyan-400 uppercase tracking-[0.6em] transition-all duration-500 hover:scale-110 hover:-translate-y-1 relative group">{link}<span className="absolute -bottom-2 left-0 w-0 h-0.5 bg-cyan-500 transition-all duration-500 group-hover:w-full shadow-[0_0_10px_#06b6d4]"></span></a>
                    ))}
                </div>
             </div>

             {/* Modals */}
             {showLogin && <LoginModal onClose={() => setShowLogin(false)} onLoginSuccess={handleLoginSuccess} darkMode={settings.darkMode} />}
             {showShop && <ShopModal user={user} onClose={() => setShowShop(false)} onUpdateUser={setUser} darkMode={settings.darkMode} playSound={playClick} />}
             {showAlmanac && <AlmanacModal onClose={() => setShowAlmanac(false)} darkMode={settings.darkMode} playSound={playClick} />}

             {showSettings && (
                 <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-2xl animate-in fade-in duration-700 p-6" onClick={() => setShowSettings(false)}>
                     <div className={`w-full max-w-xl p-12 md:p-16 rounded-[4rem] shadow-[0_0_150px_rgba(0,0,0,1)] border-[4px] relative animate-in zoom-in-95 duration-700 ${settings.darkMode ? 'bg-[#050505] border-white/5' : 'bg-white border-black/10'}`} onClick={e => e.stopPropagation()} style={{ transform: `translate(${parallax.x * 10}px, ${parallax.y * 10}px)` }}>
                        <button onClick={() => setShowSettings(false)} className="absolute top-12 right-12 p-4 hover:bg-white/10 rounded-2xl transition-all group active:scale-75 hover:rotate-90"><svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-gray-600 group-hover:text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
                        <h2 className="text-5xl font-black mb-16 text-center tracking-tighter italic uppercase text-white animate-in slide-in-from-top-4 duration-1000">Core_System<div className="h-1 w-24 bg-cyan-500 mx-auto mt-4 rounded-full shadow-[0_0_20px_#06b6d4]"></div></h2>
                        <div className="space-y-10">
                            <div className="flex items-center justify-between p-8 rounded-[2.5rem] bg-white/[0.03] border border-white/5 group hover:bg-white/[0.08] hover:border-cyan-500/30 transition-all duration-500"><div className="flex flex-col"><span className="font-black text-lg uppercase text-white tracking-[0.2em] group-hover:text-cyan-400 transition-colors">Protocol_Dark</span><span className="text-[10px] font-bold text-gray-500 uppercase mt-2 tracking-[0.3em]">Neural Interface Theme</span></div><button onClick={() => { playClick(); updateSettings({ darkMode: !settings.darkMode }); }} className={`w-20 h-10 rounded-full p-2 transition-all duration-700 ${settings.darkMode ? 'bg-cyan-500 shadow-[0_0_30px_#22d3ee]' : 'bg-gray-800'}`}><div className={`w-6 h-6 rounded-full bg-white transition-all transform duration-700 shadow-xl ${settings.darkMode ? 'translate-x-10' : ''}`} /></button></div>
                            <div className="space-y-8 p-8 rounded-[2.5rem] bg-white/[0.03] border border-white/5 group hover:bg-white/[0.08] hover:border-cyan-500/30 transition-all duration-500"><div className="flex justify-between items-end"><div className="flex flex-col"><span className="font-black text-lg uppercase text-white tracking-[0.2em] group-hover:text-cyan-400 transition-colors">Audio_Array</span><span className="text-[10px] font-bold text-gray-500 mt-2 tracking-[0.3em] uppercase">Master Gain Level</span></div><span className="text-3xl font-black text-cyan-400 font-mono transition-all duration-500 group-hover:scale-110 shadow-cyan-500/20 drop-shadow-xl">{Math.round(settings.volume * 100)}%</span></div><div className="relative h-4 flex items-center"><div className="absolute inset-0 bg-black/40 rounded-full border border-white/10"></div><input type="range" min="0" max="1" step="0.01" value={settings.volume} onChange={(e) => updateSettings({ volume: parseFloat(e.target.value) })} className="relative w-full h-full bg-transparent accent-cyan-500 appearance-none cursor-pointer z-10" /><div className="absolute left-0 h-full bg-cyan-500 rounded-full pointer-events-none shadow-[0_0_15px_#06b6d4]" style={{ width: `${settings.volume * 100}%` }}></div></div></div>
                        </div>
                        <button onClick={() => { playClick(); setShowSettings(false); }} className="group sweep-container w-full mt-16 py-8 bg-gradient-to-r from-cyan-600 to-blue-800 text-white font-black rounded-[2.5rem] shadow-2xl hover:from-cyan-500 hover:to-blue-700 transition-all duration-700 uppercase tracking-[0.6em] text-sm border-b-8 border-blue-950 active:border-b-4 active:translate-y-2 active:scale-95"><div className="sweep-effect"></div>SYNC_SYSTEM_STATE</button>
                     </div>
                 </div>
             )}
        </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameMode, GameState, HighScoreEntry, StatType, TankClass, User, Team } from './types';
import { GameEngine } from './services/GameEngine';
import { BackendService } from './services/BackendService';
import { LoginModal } from './components/LoginModal';
import { ShopModal } from './components/ShopModal';
import { AlmanacModal } from './components/AlmanacModal';
import { COLORS, SHOP_ITEMS } from './constants';
import { TankPreview } from './components/TankPreview';

interface GameSettings {
    volume: number;
    darkMode: boolean;
}

const DEFAULT_SETTINGS: GameSettings = {
    volume: 0.15,
    darkMode: true
};

interface Mission {
    id: number;
    text: string;
    progress: number;
    total: number;
    reward: string;
    rewardValue: number;
    claimed: boolean;
}

const INITIAL_MISSIONS: Mission[] = [
    { id: 1, text: "Play 3 Games", progress: 0, total: 3, reward: "250 DC", rewardValue: 250, claimed: false },
    { id: 2, text: "Reach Level 20", progress: 0, total: 20, reward: "350 DC", rewardValue: 350, claimed: false },
    { id: 3, text: "Earn 10k Score", progress: 0, total: 10000, reward: "750 DC", rewardValue: 750, claimed: false },
];

const TIPS = [
    "Press 'E' for Auto-Fire",
    "Pentagon Nest is high-risk, high-reward",
    "Body Damage protects against collisions",
    "Recoil can be used as a speed boost",
    "Sandbox Mode allows instant class switching"
];

const NEWS = [
    { id: 1, title: "SANDBOX MODE", date: "NEW", content: "Test mechanics in a private dev sector." },
    { id: 2, title: "Remaster v1.6", date: "Today", content: "Physics and console commands synced." },
];

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [engine, setEngine] = useState<GameEngine | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [playerName, setPlayerName] = useState(() => localStorage.getItem('diep_remix_name') || '');
  const [highScores, setHighScores] = useState<HighScoreEntry[]>([]);
  const [settings, setSettings] = useState<GameSettings>(DEFAULT_SETTINGS);
  const [missions, setMissions] = useState<Mission[]>(INITIAL_MISSIONS);

  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showShop, setShowShop] = useState(false);
  const [showAlmanac, setShowAlmanac] = useState(false);

  const [featuredClass, setFeaturedClass] = useState<TankClass>(TankClass.BASIC);
  const [selectedServer] = useState("US East");
  const [currentTipIndex, setCurrentTipIndex] = useState(0);
  const [gameMode, setGameMode] = useState<GameMode>(GameMode.FFA);
  const [selectedTeam, setSelectedTeam] = useState<Team>(Team.BLUE);

  const [menuMousePos, setMenuMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  // Parallax Calculation
  const parallax = useMemo(() => {
    const x = (menuMousePos.x / window.innerWidth - 0.5) * 2;
    const y = (menuMousePos.y / window.innerHeight - 0.5) * 2;
    return { x, y };
  }, [menuMousePos]);

  const activeColor = useMemo(() => {
      if (user && user.equippedItem) {
          const item = SHOP_ITEMS.find(i => i.id === user.equippedItem);
          if (item) return item.value;
      }
      return COLORS.player;
  }, [user]);

  const playHover = useCallback(() => engine?.sound.playUIHover(), [engine]);
  const playClick = useCallback(() => engine?.sound.playUIClick(), [engine]);

  useEffect(() => {
    if (playerName) localStorage.setItem('diep_remix_name', playerName);
  }, [playerName]);

  useEffect(() => {
      const interval = setInterval(() => setCurrentTipIndex(prev => (prev + 1) % TIPS.length), 6000);
      return () => clearInterval(interval);
  }, []);

  useEffect(() => {
      const classes = Object.values(TankClass);
      const interval = setInterval(() => {
          setFeaturedClass(prev => {
              const idx = classes.indexOf(prev);
              return classes[(idx + 1) % classes.length];
          });
      }, 5000);
      return () => clearInterval(interval);
  }, []);

  useEffect(() => {
      const storedScores = localStorage.getItem('diep_clone_highscores');
      if (storedScores) { try { setHighScores(JSON.parse(storedScores)); } catch (e) {} }
      const storedSettings = localStorage.getItem('diep_clone_settings');
      if (storedSettings) { try { setSettings({ ...DEFAULT_SETTINGS, ...JSON.parse(storedSettings) }); } catch (e) {} }
      BackendService.getSession().then(res => { if (res.success && res.user) { setUser(res.user); setPlayerName(res.user.username); } });
  }, []);

  const updateSettings = (newSettings: Partial<GameSettings>) => {
      setSettings(prev => {
          const updated = { ...prev, ...newSettings };
          localStorage.setItem('diep_clone_settings', JSON.stringify(updated));
          return updated;
      });
  };

  useEffect(() => { if (engine) { engine.setDarkMode(settings.darkMode); engine.sound.setVolume(settings.volume); } }, [engine, settings]);

  const handleMouseMove = (e: React.MouseEvent) => { 
    if (isPlaying) return; 
    setMenuMousePos({ x: e.clientX, y: e.clientY }); 
  };

  const handleLoginSuccess = (loggedInUser: User) => { setUser(loggedInUser); setPlayerName(loggedInUser.username); };
  const handleLogout = () => { playClick(); BackendService.logout(); setUser(null); setPlayerName(''); };

  const handleGameOver = useCallback(async (score: number, level: number, classType: TankClass) => {
      if (gameMode === GameMode.SANDBOX) return;
      const entry: HighScoreEntry = { name: playerName || 'Guest', score, level, classType, date: new Date().toISOString() };
      setHighScores(prev => {
          const newScores = [...prev, entry].sort((a, b) => b.score - a.score).slice(0, 20); 
          localStorage.setItem('diep_clone_highscores', JSON.stringify(newScores));
          return newScores;
      });
      const kills = Math.floor(score / 1500);
      setMissions(prev => prev.map(m => {
          if (m.claimed) return m;
          let newProgress = m.progress;
          if (m.text.includes("Play")) newProgress += 1;
          else if (m.text.includes("Score")) newProgress += score;
          else if (m.text.includes("Reach Level")) { if (level > newProgress) newProgress = level; }
          return { ...m, progress: Math.min(newProgress, m.total) };
      }));
      if (user) {
          const updatedUser = await BackendService.updateUserStats(user.username, { totalGames: 1, totalScore: score, highScore: score, maxLevel: level, totalKills: kills, totalDeaths: 1 });
          if (updatedUser) setUser(updatedUser);
      }
  }, [playerName, user, gameMode]);

  const handleStateUpdate = useCallback((newState: GameState) => setGameState(newState), []);
  const handleUpgradeStat = (stat: StatType) => engine?.upgradeStat(engine.player, stat);
  const handleUpgradeClass = (cls: TankClass) => engine?.upgradeClass(cls);

  const handleStartGame = (e: React.FormEvent) => {
    e.preventDefault();
    playClick();
    if (engine) {
        engine.setPlayerName(playerName || 'Guest');
        engine.setGameMode(gameMode);
        if (gameMode !== GameMode.TEAMS) engine.setPlayerColor(activeColor);
        else engine.setPlayerTeam(selectedTeam);
        engine.resetPlayer(false);
        setIsPlaying(true);
    }
  };

  const handleRestart = () => { playClick(); if (engine) { engine.resetPlayer(true); setIsPlaying(true); } };
  const handleBackToMenu = () => { playClick(); setIsPlaying(false); engine?.setAttractMode(true); };
  const handleModeSelect = (mode: GameMode) => { playClick(); setGameMode(mode); };

  const handleClaimMission = (id: number) => {
      playClick();
      const mission = missions.find(m => m.id === id);
      if (!mission || mission.claimed || mission.progress < mission.total) return;
      setMissions(prev => prev.map(m => {
          if (m.id === id) return { ...m, claimed: true };
          return m;
      }));
      if (user) BackendService.updateUserStats(user.username, {}, mission.rewardValue).then(updatedUser => { if (updatedUser) setUser(updatedUser); });
  };

  const currentStats = user ? user.stats : { totalScore: 0, totalGames: 0, maxLevel: 1, totalKills: 0, totalDeaths: 0 };
  const kdRatio = currentStats.totalDeaths > 0 ? (currentStats.totalKills / currentStats.totalDeaths).toFixed(2) : currentStats.totalKills.toFixed(2);

  // Fix: Corrected unintentional comparison between GameMode and Team types
  const tankColor = gameMode === GameMode.TEAMS ? (selectedTeam === Team.BLUE ? COLORS.player : COLORS.enemy) : activeColor;

  const getRotationToMouse = () => {
      if (!containerRef.current) return 0;
      const rect = containerRef.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      const angle = Math.atan2(menuMousePos.y - centerY, menuMousePos.x - centerX);
      return angle * (180 / Math.PI);
  };

  return (
    <div 
        ref={containerRef} 
        onMouseMove={handleMouseMove} 
        className={`relative w-screen h-screen overflow-hidden font-ubuntu transition-colors duration-1000 ${settings.darkMode ? 'bg-[#020202]' : 'bg-[#e5e5e5]'}`}
    >
      <GameCanvas onStateUpdate={handleStateUpdate} onEngineInit={setEngine} onGameOver={handleGameOver} gameMode={gameMode} />

      {isPlaying && gameState && (
        <UIOverlay gameState={gameState} onUpgradeStat={handleUpgradeStat} onUpgradeClass={handleUpgradeClass} onRestart={handleRestart} onExit={handleBackToMenu} highScores={highScores} playHover={playHover} engine={engine} />
      )}

      {/* Main UI Container */}
      <div className={`absolute inset-0 z-50 flex flex-col items-center justify-between py-8 px-6 md:px-12 bg-gradient-to-b from-black/90 via-transparent to-black/95 backdrop-blur-[1px] transition-all duration-1000 ease-in-out transform ${isPlaying ? 'opacity-0 scale-105 pointer-events-none filter blur-3xl' : 'opacity-100 scale-100'}`}>

             {/* Interactive Background Elements */}
             <div className="absolute inset-0 pointer-events-none overflow-hidden">
                {/* Floating Shards */}
                {[...Array(6)].map((_, i) => (
                    <div 
                        key={i}
                        className="absolute bg-cyan-500/5 border border-cyan-500/10 rounded-lg animate-float-heavy"
                        style={{
                            width: `${20 + i * 15}px`,
                            height: `${20 + i * 15}px`,
                            left: `${15 + i * 14}%`,
                            top: `${20 + (i % 3) * 20}%`,
                            animationDelay: `${i * 1.2}s`,
                            transform: `translate(${parallax.x * (10 + i * 5)}px, ${parallax.y * (10 + i * 5)}px)`
                        }}
                    />
                ))}

                {/* Grid Overlay */}
                <div 
