    { id: 1, title: "SANDBOX MODE", date: "NEW", content: "Test mechanics in a private dev sector." },
    { id: 2, title: "Remaster v1.6", date: "Today", content: "Physics and console commands synced." },
];

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [engine, setEngine] = useState<GameEngine | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
