    if (engine) {
        engine.setPlayerName(playerName || 'Guest');
        engine.setGameMode(gameMode);
        if (gameMode !== GameMode.TEAMS) engine.setPlayerColor(activeColor);
        else engine.setPlayerTeam(selectedTeam);
        engine.resetPlayer(false);
        setIsPlaying(true);
    }
  };

  const handleRestart = () => { playClick(); if (engine) { engine.resetPlayer(true); setIsPlaying(true); } };
  const handleBackToMenu = () => { playClick(); setIsPlaying(false); engine?.setAttractMode(true); };
  const handleModeSelect = (mode: GameMode) => { playClick(); setGameMode(mode); };

  const handleClaimMission = (id: number) => {
      playClick();
      const mission = missions.find(m => m.id === id);
      if (!mission || mission.claimed || mission.progress < mission.total) return;
      setMissions(prev => prev.map(m => {
          if (m.id === id) return { ...m, claimed: true };
          return m;
      }));
      if (user) BackendService.updateUserStats(user.username, {}, mission.rewardValue).then(updatedUser => { if (updatedUser) setUser(updatedUser); });
  };

  const currentStats = user ? user.stats : { totalScore: 0, totalGames: 0, maxLevel: 1, totalKills: 0, totalDeaths: 0 };
  const kdRatio = currentStats.totalDeaths > 0 ? (currentStats.totalKills / currentStats.totalDeaths).toFixed(2) : currentStats.totalKills.toFixed(2);

  // Fix: Corrected unintentional comparison between GameMode and Team types
  const tankColor = gameMode === GameMode.TEAMS ? (selectedTeam === Team.BLUE ? COLORS.player : COLORS.enemy) : activeColor;

  const getRotationToMouse = () => {
      if (!containerRef.current) return 0;
      const rect = containerRef.current.getBoundingClientRect();
      const centerX = rect.left + rect.width / 2;
      const centerY = rect.top + rect.height / 2;
      const angle = Math.atan2(menuMousePos.y - centerY, menuMousePos.x - centerX);
      return angle * (180 / Math.PI);
  };

  return (
    <div 
        ref={containerRef} 
        onMouseMove={handleMouseMove} 
        className={`relative w-screen h-screen overflow-hidden font-ubuntu transition-colors duration-1000 ${settings.darkMode ? 'bg-[#020202]' : 'bg-[#e5e5e5]'}`}
    >
