        <UIOverlay gameState={gameState} onUpgradeStat={handleUpgradeStat} onUpgradeClass={handleUpgradeClass} onRestart={handleRestart} onExit={handleBackToMenu} highScores={highScores} playHover={playHover} engine={engine} />
      )}

      {/* Main UI Container */}
      <div className={`absolute inset-0 z-50 flex flex-col items-center justify-between py-6 px-6 md:px-12 bg-gradient-to-b from-black/90 via-transparent to-black/95 backdrop-blur-[1px] transition-all duration-1000 ease-in-out transform ${isPlaying ? 'opacity-0 scale-105 pointer-events-none filter blur-3xl' : 'opacity-100 scale-100'}`}>

             {/* Interactive Background Elements */}
             <div className="absolute inset-0 pointer-events-none overflow-hidden">
                {/* Floating Shards */}
                {[...Array(6)].map((_, i) => (
                    <div 
                        key={i}
                        className="absolute bg-cyan-500/5 border border-cyan-500/10 rounded-lg animate-float-heavy"
                        style={{
                            width: `${20 + i * 15}px`,
                            height: `${20 + i * 15}px`,
                            left: `${15 + i * 14}%`,
                            top: `${20 + (i % 3) * 20}%`,
                            animationDelay: `${i * 1.2}s`,
                            transform: `translate(${parallax.x * (10 + i * 5)}px, ${parallax.y * (10 + i * 5)}px)`
                        }}
                    />
                ))}

                {/* Grid Overlay */}
                <div 
                    className="absolute inset-0 pointer-events-none opacity-[0.03] transition-transform duration-700 ease-out"
                    style={{ transform: `translate(${parallax.x * 25}px, ${parallax.y * 25}px) scale(1.1)` }}
                >
                    <div className="w-full h-full border-white/20 border-[1px] grid grid-cols-12 grid-rows-12">
                        {[...Array(144)].map((_, i) => <div key={i} className="border-white/5 border-[0.5px]"></div>)}
                    </div>
                </div>
                <div className="absolute inset-0 w-full h-[2px] bg-cyan-500/10 animate-[scan_10s_linear_infinite]" />
             </div>

             {/* Header */}
             <div className="w-full max-w-[1600px] flex justify-between items-center animate-in slide-in-from-top-12 duration-1000 z-10 shrink-0">
