                    <div className="flex items-center gap-4 p-2 pl-4 pr-3 rounded-2xl bg-black/80 border border-white/10 backdrop-blur-3xl hover:border-cyan-500/50 hover:shadow-[0_0_30px_rgba(34,211,238,0.2)] transition-all duration-700 transform hover:-translate-y-1">
