             {showAlmanac && <AlmanacModal onClose={() => setShowAlmanac(false)} darkMode={settings.darkMode} playSound={playClick} />}

             {showSettings && (
                 <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 backdrop-blur-2xl animate-in fade-in duration-700 p-6" onClick={() => setShowSettings(false)}>
                     <div className={`w-full max-w-md p-10 md:p-12 rounded-[3.5rem] shadow-[0_0_150px_rgba(0,0,0,1)] border-[4px] relative animate-in zoom-in-95 duration-700 ${settings.darkMode ? 'bg-[#050505] border-white/5' : 'bg-white border-black/10'}`} onClick={e => e.stopPropagation()} style={{ transform: `translate(${parallax.x * 10}px, ${parallax.y * 10}px)` }}>
                        <button onClick={() => setShowSettings(false)} className="absolute top-10 right-10 p-3 hover:bg-white/10 rounded-2xl transition-all group active:scale-75 hover:rotate-90"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-600 group-hover:text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
                        <h2 className="text-4xl font-black mb-12 text-center tracking-tighter italic uppercase text-white animate-in slide-in-from-top-4 duration-1000">Core_System<div className="h-1 w-20 bg-cyan-500 mx-auto mt-3 rounded-full shadow-[0_0_15px_#06b6d4]"></div></h2>
