                        </div>
                        <button onClick={() => { playClick(); setShowSettings(false); }} className="group sweep-container w-full mt-12 py-6 bg-gradient-to-r from-cyan-600 to-blue-800 text-white font-black rounded-[2rem] shadow-xl hover:from-cyan-500 hover:to-blue-700 transition-all duration-700 uppercase tracking-[0.5em] text-xs border-b-6 border-blue-950 active:border-b-2 active:translate-y-1 active:scale-95"><div className="sweep-effect"></div>SYNC_SYSTEM_STATE</button>
                     </div>
                 </div>
             )}
        </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect, useMemo, useRef } from 'react';
import GameCanvas from './components/GameCanvas';
import UIOverlay from './components/UIOverlay';
import { GameMode, GameState, HighScoreEntry, StatType, TankClass, User, Team } from './types';
import { GameEngine } from './services/GameEngine';
import { BackendService } from './services/BackendService';
import { LoginModal } from './components/LoginModal';
import { ShopModal } from './components/ShopModal';
import { AlmanacModal } from './components/AlmanacModal';
import { COLORS, SHOP_ITEMS } from './constants';
import { TankPreview } from './components/TankPreview';

interface GameSettings {
    volume: number;
    darkMode: boolean;
}

const DEFAULT_SETTINGS: GameSettings = {
    volume: 0.15,
    darkMode: true
};

const NEWS = [
    { id: 1, title: "SANDBOX MODE", date: "NEW", content: "Test mechanics in private dev sector." },
    { id: 2, title: "REMASTER V4.2", date: "LIVE", content: "Balanced proportions & enhanced UI." },
];

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [engine, setEngine] = useState<GameEngine | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [playerName, setPlayerName] = useState(() => localStorage.getItem('diep_remix_name') || '');
  const [highScores, setHighScores] = useState<HighScoreEntry[]>([]);
  const [settings, setSettings] = useState<GameSettings>(DEFAULT_SETTINGS);

  const [user, setUser] = useState<User | null>(null);
  const [showLogin, setShowLogin] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showShop, setShowShop] = useState(false);
  const [showAlmanac, setShowAlmanac] = useState(false);

  const [gameMode, setGameMode] = useState<GameMode>(GameMode.FFA);
  const [selectedTeam, setSelectedTeam] = useState<Team>(Team.BLUE);
  const [menuMousePos, setMenuMousePos] = useState({ x: 0, y: 0 });

  const parallax = useMemo(() => {
    const x = (menuMousePos.x / window.innerWidth - 0.5) * 2;
    const y = (menuMousePos.y / window.innerHeight - 0.5) * 2;
    return { x, y };
  }, [menuMousePos]);

  const activeColor = useMemo(() => {
      if (user && user.equippedItem) {
          const item = SHOP_ITEMS.find(i => i.id === user.equippedItem);
          if (item) return item.value;
      }
      return COLORS.player;
  }, [user]);

  const playHover = useCallback(() => engine?.sound.playUIHover(), [engine]);
  const playClick = useCallback(() => engine?.sound.playUIClick(), [engine]);

  useEffect(() => {
    if (playerName) localStorage.setItem('diep_remix_name', playerName);
  }, [playerName]);

  useEffect(() => {
      BackendService.getSession().then(res => { if (res.success && res.user) { setUser(res.user); setPlayerName(res.user.username); } });
  }, []);

  const handleMouseMove = (e: React.MouseEvent) => { if (!isPlaying) setMenuMousePos({ x: e.clientX, y: e.clientY }); };
  const handleStartGame = (e: React.FormEvent) => {
    e.preventDefault();
    playClick();
    if (engine) {
        engine.setPlayerName(playerName || 'GUEST_PILOT');
        engine.setGameMode(gameMode);
        if (gameMode !== GameMode.TEAMS) engine.setPlayerColor(activeColor);
        else engine.setPlayerTeam(selectedTeam);
        engine.resetPlayer(false);
        setIsPlaying(true);
    }
  };

  const getRotationToMouse = () => {
      const centerX = window.innerWidth / 2;
      const centerY = window.innerHeight * 0.6; // Panel offset
      const angle = Math.atan2(menuMousePos.y - centerY, menuMousePos.x - centerX);
      return angle * (180 / Math.PI);
  };

  const currentStats = user ? user.stats : { maxLevel: 1, totalKills: 0, totalDeaths: 0 };
  const kdRatio = currentStats.totalDeaths > 0 ? (currentStats.totalKills / currentStats.totalDeaths).toFixed(2) : '0.00';
  const tankColor = gameMode === GameMode.TEAMS ? (selectedTeam === Team.BLUE ? COLORS.player : COLORS.enemy) : activeColor;

  return (
    <div onMouseMove={handleMouseMove} className="relative w-screen h-screen overflow-hidden bg-[#020202] font-ubuntu">
      <div className="scanline" />
      <GameCanvas onStateUpdate={setGameState} onEngineInit={setEngine} onGameOver={() => {}} gameMode={gameMode} />

      {isPlaying && gameState && (
        <UIOverlay gameState={gameState} onUpgradeStat={(s) => engine?.upgradeStat(engine.player, s)} onUpgradeClass={(c) => engine?.upgradeClass(c)} onRestart={() => engine?.resetPlayer(true)} onExit={() => { setIsPlaying(false); engine?.setAttractMode(true); }} highScores={highScores} playHover={playHover} engine={engine} />
      )}

      {/* Main Menu Overlay */}
      <div className={`absolute inset-0 z-50 flex flex-col items-center justify-between py-12 px-12 bg-gradient-to-b from-black/80 via-transparent to-black/90 transition-all duration-1000 ease-[cubic-bezier(0.19,1,0.22,1)] ${isPlaying ? 'opacity-0 translate-y-12 pointer-events-none filter blur-2xl' : 'opacity-100 translate-y-0'}`}>

        {/* Header - Balanced & Tactical */}
        <div className="w-full max-w-[1600px] flex justify-between items-center animate-in slide-in-from-top-8 duration-1000">
            <div className="group flex items-center gap-5 p-1.5 pl-5 pr-3 rounded-2xl bg-white/[0.02] border border-white/10 backdrop-blur-md hover:border-cyan-500/30 transition-all duration-500">
                <div className="flex flex-col text-right">
                    <span className="text-[10px] font-black text-white/40 tracking-[0.2em] uppercase">Pilot_Identity</span>
                    <span className="text-sm font-black text-white uppercase tracking-widest">{user?.username || playerName || 'GUEST_SIGNAL'}</span>
                </div>
                <div className="w-10 h-10 rounded-xl bg-cyan-500/10 border border-cyan-500/30 flex items-center justify-center text-cyan-400 font-black shadow-inner">
                    {user ? user.username.charAt(0).toUpperCase() : '?'}
                </div>
                <button onClick={() => user ? BackendService.logout().then(() => setUser(null)) : setShowLogin(true)} className="p-2.5 rounded-lg hover:bg-red-500/20 text-white/20 hover:text-red-500 transition-all">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17 16l4-4m0 0l-4-4m4 4H7" /></svg>
                </button>
            </div>

            <div className="flex gap-4">
                <div className="hidden sm:flex items-center gap-4 px-6 py-2.5 rounded-2xl bg-white/[0.02] border border-white/10 backdrop-blur-md">
                    <div className="text-right">
                        <span className="block text-[8px] font-black text-white/20 uppercase tracking-[0.4em]">Node_Status</span>
                        <span className="text-[10px] font-black text-green-400 font-mono tracking-widest uppercase italic">Latency_Stable</span>
                    </div>
                    <div className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse shadow-[0_0_10px_#4ade80]"></div>
                </div>
                <button onClick={() => setShowAlmanac(true)} className="p-3.5 rounded-2xl bg-white/5 border border-white/10 text-white/20 hover:text-indigo-400 hover:border-indigo-500/30 transition-all hover:scale-105 active:scale-95"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253" /></svg></button>
                <button onClick={() => setShowSettings(true)} className="p-3.5 rounded-2xl bg-white/5 border border-white/10 text-white/20 hover:text-cyan-400 hover:border-cyan-500/30 transition-all hover:scale-105 active:scale-95"><svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg></button>
            </div>
        </div>

        {/* Center Section - Standardized Proportions */}
        <div className="flex-1 w-full max-w-[1400px] grid grid-cols-1 lg:grid-cols-5 gap-16 items-center overflow-hidden">

            {/* Left Sidebar - Information */}
            <div className="hidden lg:flex flex-col gap-6 animate-in slide-in-from-left-8 duration-1000 delay-200">
                <div className="flex items-center gap-3 px-2">
                    <span className="text-[10px] font-black text-cyan-500 uppercase tracking-[0.4em] italic">Intel_Feed</span>
                    <div className="h-px flex-1 bg-white/10"></div>
                </div>
                <div className="space-y-4">
                    {NEWS.map((item, idx) => (
