            <div className="group flex items-center gap-5 p-1.5 pl-5 pr-3 rounded-2xl bg-white/[0.02] border border-white/10 backdrop-blur-md hover:border-cyan-500/30 transition-all duration-500 shadow-xl">
                <div className="flex flex-col text-right">
                    <span className="text-[10px] font-black text-white/40 tracking-[0.2em] uppercase">Pilot_Identity</span>
                    <span className="text-sm font-black text-white uppercase tracking-widest">{user?.username || playerName || 'GUEST_SIGNAL'}</span>
                </div>
                <div className="w-10 h-10 rounded-xl bg-cyan-500/10 border border-cyan-500/30 flex items-center justify-center text-cyan-400 font-black shadow-inner">
                    {user ? user.username.charAt(0).toUpperCase() : '?'}
