                <button onClick={() => user ? BackendService.logout().then(() => setUser(null)) : setShowLogin(true)} className="p-2.5 rounded-lg hover:bg-red-500/20 text-white/20 hover:text-red-500 transition-all active:scale-90">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17 16l4-4m0 0l-4-4m4 4H7" /></svg>
                </button>
            </div>

            <div className="flex gap-4">
