              this.addNotification("ENTITY LIMIT REACHED", "#ff4444");
          }
      } else if (type === 'BOSS') {
          const boss = new Boss(this.nextId());
          boss.pos = { x: worldX, y: worldY };
          this.entities.push(boss);
          this.addNotification("GRAND SINGULARITY DEPLOYED", "#00ffff");
      } else if (type === 'ALPHA_PENTAGON') {
          const shape = new Shape(this.nextId(), worldX, worldY, ShapeType.PENTAGON, false, ShapeRarity.LEGENDARY);
          shape.radius *= 4;
          shape.maxHealth *= 10;
          shape.health = shape.maxHealth;
          shape.xpValue *= 5;
          this.entities.push(shape);
          this.addNotification("ALPHA PENTAGON FABRICATED", "#768dfc");
      } else if (type === 'VOID_PORTAL') {
          this.entities.push(new VoidPortal(this.nextId(), worldX, worldY));
          this.addNotification("VOID RIFT OPENED", COLORS.voidPortal);
      } else if (type === 'DUMMY') {
          this.entities.push(new TestDummy(this.nextId(), worldX, worldY));
          this.addNotification("TARGET DUMMY DEPLOYED", "#ffbb00");
      }

      this.sound.playLevelUp();
      this.spawnParticles({ x: worldX, y: worldY }, "#fff", 20, 4);
  }

  setSandboxFlag(key: keyof SandboxConfig, val: any) { 
      (this.sandboxConfig as any)[key] = val; 
      this.addNotification(`${key.toUpperCase()} UPDATED`, "#00e16e");
      if (key === 'spawningEnabled' && !val) {
          this.primedSpawn = null;
      }
  }
  teleportPlayer() { const mouseOffset = Vector.sub(this.mouse, { x: window.innerWidth / 2, y: window.innerHeight / 2 }); const targetPos = Vector.add(this.player.pos, Vector.div(mouseOffset, this.player.fov)); this.player.pos = targetPos; this.addNotification("PHASE SHIFTED", "#00ffff"); }
  maxAllStats() { Object.values(StatType).forEach(s => this.player.stats[s] = 8); this.player.updateStats(); this.player.availableStatPoints = 0; this.addNotification("STATS OVERCLOCKED", "#ffd700"); }
  resetAllStats() { Object.values(StatType).forEach(s => this.player.stats[s] = 0); this.player.updateStats(); this.player.availableStatPoints = Math.min(this.level, 60) - 1; this.addNotification("STATS FLUSHED", "#333"); }
  instantLevel(level: number) { 
      this.level = level; 
      this.player.level = level; 
      this.player.availableStatPoints = Math.min(level, 60) - 1; 
      this.player.updateStats(); 
      this.addNotification(`SYNCED TO LVL ${level}`, "#33ccff"); 
  }

  spawnElite() {
      const pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT);
      const classes = [TankClass.TWIN, TankClass.DESTROYER, TankClass.SNIPER, TankClass.OVERLORD, TankClass.MACHINE_GUN];
      const chosenClass = classes[Math.floor(Math.random() * classes.length)];
      const elite = new EliteTank(this.nextId(), pos.x, pos.y, chosenClass);
      this.entities.push(elite);
      this.addNotification(`⚠️ ELITE ${chosenClass.toUpperCase()} DETECTED ⚠️`, "#ff4444");
      this.sound.playLevelUp();
  }

  spawnGuardians() {
    this.entities = this.entities.filter(e => e.type !== EntityType.GUARDIAN);
    if (this.gameMode === GameMode.TEAMS) {
        for(let i=0; i<3; i++) {
            this.entities.push(new Guardian(this.nextId(), 300, CANVAS_HEIGHT / 2 + (i - 1) * 800, Team.BLUE));
            this.entities.push(new Guardian(this.nextId(), CANVAS_WIDTH - 300, CANVAS_HEIGHT / 2 + (i - 1) * 800, Team.RED));
        }
    }
  }

  spawnBoss() {
    if (this.entities.find(e => e.type === EntityType.BOSS)) return;
    this.entities.push(new Boss(this.nextId()));
    this.addNotification("⚠️ THE GRAND SINGULARITY HAS ARRIVED ⚠️", "#00ffff");
    this.sound.playLevelUp();
  }

  handleTransformation() {
      if (this.transformationReadyTimer > 0 && this.transformationReadyClass) {
          this.player.isTransformed = true;
          this.player.transformationTimer = 180; 
          this.player.classType = this.transformationReadyClass;
          this.player.barrels = TANK_CONFIGS[this.transformationReadyClass];
          this.player.updateStats();
          this.player.health = this.player.maxHealth;
          this.transformationReadyTimer = 0;
          this.addNotification("YOU HAVE ASCENDED!", "#ff4444");
          this.sound.playLevelUp();
          this.spawnParticles(this.player.pos, "#ff4444", 50, 6);
      }
  }

  resetPlayer(preserveWorld: boolean = false) {
    this.player.isDead = false; this.gameOverSignaled = false; 
    this.player.isTransformed = false;
    this.player.transformationTimer = 0;
    this.player.radius = 20;
    this.player.activeBuffs = [];
    this.transformationReadyTimer = 0;
    this.primedSpawn = null;
    this.isTransitioning = false;

    if (preserveWorld) { 
        const newLevel = Math.max(1, Math.floor(this.level * 0.7)); 
        this.level = newLevel; 
        this.player.level = newLevel; 
        this.player.score = 0; 
        this.xp = 0; 
        this.player.availableStatPoints = Math.max(0, Math.min(newLevel, 60) - 1); 
        if (newLevel > 1) this.addNotification(`RESPAWNED AT LEVEL ${newLevel}`, "#33ccff"); 
    }
    else { 
        this.player.score = 0; 
        this.level = 1; 
        this.player.level = 1; 
        this.xp = 0; 
        this.player.availableStatPoints = 0; 
    }
    this.player.autoFire = false; this.player.autoSpin = false; this.uiNotifications = [];
    if (this.gameMode === GameMode.TEAMS) { this.player.team = this.preferredTeam; this.player.color = (this.preferredTeam === Team.BLUE) ? COLORS.player : COLORS.enemy; if (this.preferredTeam === Team.BLUE) this.player.pos = { x: Vector.randomRange(50, BASE_ZONE_WIDTH - 50), y: Vector.randomRange(50, CANVAS_HEIGHT - 50) }; else this.player.pos = { x: Vector.randomRange(CANVAS_WIDTH - BASE_ZONE_WIDTH + 50, CANVAS_WIDTH - 50), y: Vector.randomRange(50, CANVAS_HEIGHT - 50) }; }
    else { this.player.team = Team.BLUE; this.player.pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT); }
    this.player.vel = { x: 0, y: 0 }; this.player.stats = { [StatType.REGEN]: 0, [StatType.MAX_HEALTH]: 0, [StatType.MAX_SHIELD]: 0, [StatType.BODY_DAMAGE]: 0, [StatType.BULLET_SPEED]: 0, [StatType.BULLET_PENETRATION]: 0, [StatType.BULLET_DAMAGE]: 0, [StatType.RELOAD]: 0, [StatType.MOVEMENT_SPEED]: 0, [StatType.BULLET_SPREAD]: 0 }; this.player.updateStats(); this.player.health = this.player.maxHealth; this.player.displayHealth = this.player.maxHealth; this.player.shield = 0; this.player.invulnerableTime = 3000; this.upgradeClass(TankClass.BASIC);
    if (!this.entities.includes(this.player)) this.entities.push(this.player);
    if (!preserveWorld) { 
        this.entities = this.entities.filter(e => e.type === EntityType.SHAPE || e === this.player); 
        this.currentShapeCount = this.entities.filter(e => e.type === EntityType.SHAPE).length;
        this.killFeed = []; this.floatingTexts = []; this.particles = []; this.bossSpawnTimer = 0; this.eliteSpawnTimer = 0; if (this.gameMode === GameMode.TEAMS) this.spawnGuardians(); 
    }
    if (this.gameMode !== GameMode.TEAMS) this.entities = this.entities.filter(e => e.type !== EntityType.GUARDIAN);
    this.attractMode = false;
    this.inVoid = false;
    this.voidTimer = 0;

    if (this.gameMode === GameMode.SANDBOX) {
        this.instantLevel(MAX_LEVEL);
        this.addNotification("SANDBOX INITIALIZED", "#00ffff");
    }
  }

  start() { this.lastTime = performance.now(); this.loop(); }
  loop = () => { const now = performance.now(); const dt = Math.min((now - this.lastTime) / 1000, 0.1) * this.sandboxConfig.gameSpeed; this.lastTime = now; this.update(dt); this.draw(); requestAnimationFrame(this.loop); };
  handleInput(keys: Set<string>, mouse: Vector2, mouseDown: boolean) { 
    this.keys = keys; this.mouse = mouse; this.mouseDown = mouseDown; 
    if (keys.has('t') || keys.has('T')) {
        this.handleTransformation();
    }
    if (keys.has('Escape') && this.primedSpawn) {
        this.primedSpawn = null;
        this.addNotification("SPAWN CANCELLED", "#ff4444");
    }
  }

  private transitionToDimension(toVoid: boolean) {
      if (this.isTransitioning) return;
      this.isTransitioning = true;
      this.addNotification(toVoid ? "ENTERING THE VOID" : "EXITING THE VOID", COLORS.voidPortal);
      setTimeout(() => {
          this.inVoid = toVoid;
          this.voidTimer = toVoid ? 300 : 0;
          this.entities = this.entities.filter(e => e.type === EntityType.PLAYER || e.type === EntityType.ENEMY || e.type === EntityType.BULLET);
          this.currentShapeCount = 0;
          if (toVoid) {
              const exitPos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT);
              this.entities.push(new VoidPortal(this.nextId(), exitPos.x, exitPos.y, true));
          } else {
              if (this.gameMode === GameMode.TEAMS) this.spawnGuardians();
          }
          for (let i = 0; i < 150; i++) this.spawnShape();
          this.isTransitioning = false;
      }, 1000);
  }

  private updateAutoTurrets(dt: number) {
      this.entities.forEach(e => {
          if (e instanceof Tank && e.classType === TankClass.AUTO_GUNNER && !e.isDead) {
              const tank = e as Tank;
              const range = 650;

              // 1. Target Selection
              const neighbors = this.spatialGrid.getNeighbors(tank);
              const potentialTargets = neighbors.filter(target => {
                  if (target.id === tank.id || target.isDead) return false;
                  if (Vector.dist(tank.pos, target.pos) > range) return false;

                  if (target.type === EntityType.PLAYER || target.type === EntityType.ENEMY || target.type === EntityType.ELITE_TANK) {
                      return this.gameMode === GameMode.FFA || target.team !== tank.team;
                  }
                  return target.type === EntityType.SHAPE || target.type === EntityType.BOSS;
              });

              const prioritizedTarget = potentialTargets.sort((a, b) => {
                  const getScore = (ent: Entity) => {
                      if (ent.type === EntityType.PLAYER || ent.type === EntityType.ENEMY || ent.type === EntityType.ELITE_TANK) return 0;
                      if (ent.type === EntityType.BOSS) return 1;
                      return 2;
                  };
                  const scoreDiff = getScore(a) - getScore(b);
                  if (scoreDiff !== 0) return scoreDiff;
                  return Vector.dist(tank.pos, a.pos) - Vector.dist(tank.pos, b.pos);
              })[0];

              if (prioritizedTarget) {
                  // 2. Turret Rotation
                  const bSpeed = (BASE_STATS.bulletSpeed + tank.stats[StatType.BULLET_SPEED] * 0.8) * 1.65;
                  const aimPoint = this.getInterceptPoint(tank.pos, bSpeed, prioritizedTarget.pos, prioritizedTarget.vel || {x:0, y:0});
                  const targetRot = Math.atan2(aimPoint.y - tank.pos.y, aimPoint.x - tank.pos.x);

                  let diff = targetRot - tank.autoTurretRotation;
                  while (diff > Math.PI) diff -= Math.PI * 2;
                  while (diff < -Math.PI) diff += Math.PI * 2;
                  tank.autoTurretRotation += diff * 0.15;

                  // 3. Independent Firing
                  if (tank.autoTurretCooldown <= 0 && Math.abs(diff) < 0.4) {
                      const baseReloadTimeMs = (BASE_STATS.reload - (tank.stats[StatType.RELOAD] * 2.5)) * 16;
                      const cooldownVal = Math.max(80, baseReloadTimeMs * 0.8);
                      tank.autoTurretCooldown = cooldownVal;

                      const forward = Vector.fromAngle(tank.autoTurretRotation);
                      const tip = Vector.add(tank.pos, Vector.mult(forward, tank.radius * 0.9));

                      const bulletSpeedMult = 1.65;
                      const bulletDamageMult = 0.7;
                      const bulletSizeMult = 0.65;

                      this.entities.push(new Bullet(
                          this.nextId(), 
                          tip.x, 
                          tip.y, 
                          Vector.mult(forward, (BASE_STATS.bulletSpeed + tank.stats[StatType.BULLET_SPEED] * 0.8) * bulletSpeedMult), 
                          tank, 
                          bulletDamageMult, 
                          1.0, 
                          bulletSizeMult
                      ));

                      // Muzzle Flash Effect
                      if (tank === this.player || this.isOnScreen(tank.pos)) {
                          this.particles.push(new Particle(tip.x, tip.y, 'rgba(255, 200, 50, 0.6)', 8, 5, 'FLASH'));
                          this.sound.playShoot(TankClass.GUNNER);
                      }
                  }
              } else {
                  tank.autoTurretRotation += dt * 0.5;
              }
          }
      });
  }

  update(dt: number) {
    if (this.isTransitioning) {
        this.transitionAlpha = Math.min(1, this.transitionAlpha + dt * 2);
    } else {
        this.transitionAlpha = Math.max(0, this.transitionAlpha - dt * 2);
    }

    if (!this.inVoid) {
        this.portalSpawnTimer += dt;
        if (this.portalSpawnTimer > 300 && this.gameMode !== GameMode.SANDBOX) {
            const pos = Vector.randomRange(2000, CANVAS_WIDTH - 2000);
            const pos2 = Vector.randomRange(2000, CANVAS_HEIGHT - 2000);
            this.entities.push(new VoidPortal(this.nextId(), pos, pos2));
            this.addNotification("⚠️ VOID RIFT DETECTED ⚠️", COLORS.voidPortal);
            this.portalSpawnTimer = 0;
        }

        this.eliteSpawnTimer += dt;
        if (this.eliteSpawnTimer > 600 && this.gameMode !== GameMode.SANDBOX) { 
            this.spawnElite();
            this.eliteSpawnTimer = 0;
        }
    } else {
        this.voidTimer -= dt;
        if (this.voidTimer <= 0) {
            this.transitionToDimension(false);
        }
    }

    if (this.transformationReadyTimer > 0) {
        this.transformationReadyTimer -= dt;
    }

    this.bossSpawnTimer += dt;
    if (this.bossSpawnTimer > 120 && !this.inVoid && this.gameMode !== GameMode.SANDBOX) { this.spawnBoss(); this.bossSpawnTimer = 0; }

    this.crasherSpawnTimer += dt;
    if (this.crasherSpawnTimer > 5 && !this.inVoid && this.gameMode !== GameMode.SANDBOX) {
        const nestRadius = 1500;
        const count = 3 + Math.floor(Math.random() * 3);
        for(let i=0; i<count; i++) {
            const angle = Math.random() * Math.PI * 2;
            const dist = Math.random() * nestRadius;
            this.entities.push(new Crasher(this.nextId(), CANVAS_WIDTH/2 + Math.cos(angle)*dist, CANVAS_HEIGHT/2 + Math.sin(angle)*dist));
        }
        this.crasherSpawnTimer = 0;
    }

    const currentBoss = this.entities.find(e => e.type === EntityType.BOSS) as Boss | undefined;
    if (currentBoss) {
        this.bossDefenseTimer += dt;
        if (this.bossDefenseTimer > 4) {
            const playersNearby = this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && Vector.dist(e.pos, currentBoss.pos) < 1200);
            if (playersNearby.length > 0) {
                const angle = Math.random() * Math.PI * 2;
                const spawnPos = Vector.add(currentBoss.pos, Vector.mult(Vector.fromAngle(angle), currentBoss.radius + 50));
                this.entities.push(new Crasher(this.nextId(), spawnPos.x, spawnPos.y, true));
            }
            this.bossDefenseTimer = 0;
        }
    }

    if (!this.attractMode) {
        const distToCenter = Vector.dist(this.player.pos, {x: CANVAS_WIDTH/2, y: CANVAS_HEIGHT/2});
        if (distToCenter < 1450 && !this.inNest && !this.inVoid) {
            this.inNest = true;
            this.addNotification("ENTERING THE PENTAGON NEST", "#768dfc");
        } else if (distToCenter >= 1550 && this.inNest) {
            this.inNest = false;
        }
    }

    if (this.attractMode) {
        if (!this.spectateTarget || this.spectateTarget.isDead || Math.random() < 0.005) {
            const bots = this.entities.filter(e => e.type === EntityType.ENEMY) as Tank[];
            this.spectateTarget = bots.length > 0 ? bots[Math.floor(Math.random() * bots.length)] : null;
        }
        let targetPos = this.spectateTarget ? this.spectateTarget.pos : {x: CANVAS_WIDTH/2, y: CANVAS_HEIGHT/2};
        this.cameraPos.x += (targetPos.x - this.cameraPos.x) * 0.05;
        this.cameraPos.y += (targetPos.y - this.cameraPos.y) * 0.05;
        this.cameraZoom = 0.6;
        this.player.pos = { x: -1000, y: -1000 };
    } else {
        this.cameraPos.x += (this.player.pos.x - this.cameraPos.x) * 0.1;
        this.cameraPos.y += (this.player.pos.y - this.cameraPos.y) * 0.1;
        this.cameraZoom = this.player.fov;
    }

    if (!this.attractMode && this.player.isDead && !this.gameOverSignaled) { this.gameOverSignaled = true; this.onGameOver(this.player.score, this.level, this.player.classType); }

    if (this.currentShapeCount < this.maxShapes) {
      if (Math.random() < 0.35) this.spawnShape();
    }

    let enemyLimit = this.gameMode === GameMode.TEAMS ? 59 : 30;
    if (this.attractMode) enemyLimit += 10;
    if (this.gameMode === GameMode.SANDBOX) enemyLimit = 0; 

    if (this.entities.filter(e => e.type === EntityType.ENEMY).length < enemyLimit) { if(Math.random() < 0.05) this.spawnEnemy(); }

    if (!this.attractMode && !this.player.isDead) this.updatePlayerControl(dt);

    if (!this.sandboxConfig.freezeAll) {
        this.entities.forEach(e => {
            if (e.type === EntityType.ENEMY && !e.isDead && this.sandboxConfig.botsEnabled) this.updateBotAI(e as Tank, dt);
            else if (e.type === EntityType.ELITE_TANK && !e.isDead) this.updateEliteAI(e as EliteTank, dt);
            else if (e.type === EntityType.GUARDIAN) this.updateGuardianAI(e as Guardian, dt);
            else if (e.type === EntityType.CRASHER) this.updateCrasherAI(e as Crasher, dt);

            if (e.type === EntityType.SHAPE && (e as Shape).rarity !== ShapeRarity.COMMON) {
                if (Math.random() < 0.005) {
                    const rarityColor = (this.inVoid ? VOID_RARITY_CONFIG : RARITY_CONFIG)[(e as Shape).rarity].color || e.color;
                    this.particles.push(new Particle(e.pos.x + Vector.randomRange(-e.radius, e.radius), e.pos.y + Vector.randomRange(-e.radius, e.radius), rarityColor, 2, 40));
                }
            }

            if (e.type === EntityType.BOSS) {
                if (Math.random() < 0.1) {
                    this.particles.push(new Particle(e.pos.x + Vector.randomRange(-e.radius, e.radius), e.pos.y + Vector.randomRange(-e.radius, e.radius), '#00ffff', 4, 80));
                }
            }
        });

        this.updateAutoTurrets(dt);
    }

    if (this.gameMode === GameMode.TEAMS && !this.inVoid) {
        this.entities.forEach(e => {
            if (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) {
                if (e.team === Team.RED && e.pos.x < BASE_ZONE_WIDTH) e.vel.x += 1500 * dt;
                if (e.team === Team.BLUE && e.pos.x > CANVAS_WIDTH - BASE_ZONE_WIDTH) e.vel.x -= 1500 * dt;
            }
            if (e.type === EntityType.BULLET) {
                if (e.team === Team.RED && e.pos.x < BASE_ZONE_WIDTH) e.isDead = true;
                if (e.team === Team.BLUE && e.pos.x > CANVAS_WIDTH - BASE_ZONE_WIDTH) e.isDead = true;
            }
        });
    }

    this.entities.forEach(e => {
        if (this.sandboxConfig.freezeAll && e.type !== EntityType.PLAYER) return;
        e.update(dt);
    });

    this.handleCollisions();

    this.particles.forEach(p => p.update());
    this.particles = this.particles.filter(p => p.life > 0);
    this.floatingTexts.forEach(ft => ft.update());
    this.floatingTexts = this.floatingTexts.filter(ft => ft.life > 0);
    this.uiNotifications.forEach(n => n.life -= dt);
    this.uiNotifications = this.uiNotifications.filter(n => n.life > 0);

    let removedShapes = 0;
    this.entities = this.entities.filter(e => {
        const dead = e.isDead;
        if (dead && e.type === EntityType.SHAPE) removedShapes++;
        return !dead;
    });
    this.currentShapeCount -= removedShapes;

    this.killFeed = this.killFeed.filter(k => Date.now() - k.timestamp < 5000).slice(0, 6);

    const leaderboard: LeaderboardEntry[] = (this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && !e.isDead) as Tank[])
        .sort((a, b) => b.score - a.score).slice(0, 10).map(e => ({ id: e.id, name: e.name || 'Unknown', score: e.score, classType: e.classType, isPlayer: e.id === this.player.id, team: e.team }));

    const minimapMarkers: MinimapMarker[] = [];
    this.entities.forEach(e => {
        const isPriority = e.type === EntityType.BOSS || e.type === EntityType.ELITE_TANK || e.type === EntityType.VOID_PORTAL || e.type === EntityType.DUMMY;
        const isAlly = (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && (this.gameMode === GameMode.FFA ? e.id === this.player.id : e.team === this.player.team);

        if (isPriority || isAlly) {
            minimapMarkers.push({
                type: e.type,
                pos: { x: e.pos.x, y: e.pos.y },
                team: e.team,
                rotation: e.rotation,
                isPlayer: e.id === this.player.id
            });
        }
    });

    this.onStateUpdate({ 
        score: this.player.score, 
        level: this.level, 
        xp: this.xp, 
        maxXp: this.getLevelXp(this.level), 
        stats: this.player.stats, 
        availableStatPoints: this.player.availableStatPoints, 
        currentClass: this.player.classType, 
        isDead: this.player.isDead, 
        fps: Math.round(1/dt), 
        killFeed: this.killFeed, 
        leaderboard: leaderboard, 
        notifications: this.uiNotifications, 
        health: this.player.displayHealth, 
        maxHealth: this.player.maxHealth, 
        shield: this.player.shield, 
        maxShield: this.player.maxShield, 
        playerPos: this.player.pos, 
        playerRotation: this.player.rotation, 
        camera: { x: this.cameraPos.x, y: this.cameraPos.y, zoom: this.cameraZoom }, 
        mapSize: { width: CANVAS_WIDTH, height: CANVAS_HEIGHT }, 
        gameMode: this.gameMode, 
        autoFire: this.player.autoFire, 
        autoSpin: this.player.autoSpin, 
        minimapMarkers,
        inVoid: this.inVoid, 
        voidTimeRemaining: this.voidTimer,
        isTransformed: this.player.isTransformed,
        transformationTime: this.player.transformationTimer,
        transformationReady: this.transformationReadyTimer > 0,
        activeBuffs: this.player.activeBuffs,
        sandboxConfig: this.sandboxConfig,
        primedSpawn: this.primedSpawn
    });
  }

  updatePlayerControl(dt: number) {
    const dir = { x: 0, y: 0 };
    if (this.keys.has('w') || this.keys.has('W') || this.keys.has('ArrowUp')) dir.y -= 1;
    if (this.keys.has('s') || this.keys.has('S') || this.keys.has('ArrowDown')) dir.y += 1;
    if (this.keys.has('a') || this.keys.has('A') || this.keys.has('ArrowLeft')) dir.x -= 1;
    if (this.keys.has('d') || this.keys.has('D') || this.keys.has('ArrowRight')) dir.x += 1;

    this.applyTankMovement(this.player, dir);

    if (!this.player.autoSpin) {
      const screenX = (this.player.pos.x - this.cameraPos.x) * this.cameraZoom + window.innerWidth / 2;
      const screenY = (this.player.pos.y - this.cameraPos.y) * this.cameraZoom + window.innerHeight / 2;
      this.player.rotation = Math.atan2(this.mouse.y - screenY, this.mouse.x - screenX);
    } else {
      this.player.rotation += dt * 3;
    }

    if (this.mouseDown || this.player.autoFire) {
      this.attemptShoot(this.player);
    }
  }

  updateGuardianAI(guardian: Guardian, dt: number) {
    const vision = 1200;
    const targets = this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && e.team !== guardian.team && Vector.dist(e.pos, guardian.pos) < vision);
    const nearest = this.findNearest(guardian, targets);

    if (nearest) {
      const dir = Vector.normalize(Vector.sub(nearest.pos, guardian.pos));
      guardian.acc = Vector.mult(dir, 2.5);
      guardian.rotation = Math.atan2(dir.y, dir.x);
    } else {
      const orbitDist = 400;
      guardian.orbitAngle += dt * 0.5;
      const targetPos = {
          x: guardian.homePos.x + Math.cos(guardian.orbitAngle) * orbitDist,
          y: guardian.homePos.y + Math.sin(guardian.orbitAngle) * orbitDist
      };
      const toTarget = Vector.sub(targetPos, guardian.pos);
      if (Vector.mag(toTarget) > 10) {
          guardian.acc = Vector.mult(Vector.normalize(toTarget), 1.0);
      }
      guardian.rotation += dt * 2;
    }
  }

  updateCrasherAI(crasher: Crasher, dt: number) {
    const vision = 700;
    if (!crasher.target || crasher.target.isDead || Vector.dist(crasher.pos, crasher.target.pos) > vision + 200) {
        const potential = this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && Vector.dist(e.pos, crasher.pos) < vision);
        crasher.target = this.findNearest(crasher, potential);
    }

    if (crasher.target) {
        const dir = Vector.normalize(Vector.sub(crasher.target.pos, crasher.pos));
        crasher.acc = Vector.mult(dir, 1.5);
    } else {
        const center = { x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2 };
        const toCenter = Vector.sub(center, crasher.pos);
        if (Vector.mag(toCenter) > 1500) {
            crasher.acc = Vector.mult(Vector.normalize(toCenter), 0.4);
        } else if (Math.random() < 0.01) {
            crasher.vel = Vector.add(crasher.vel, Vector.mult(Vector.fromAngle(Math.random() * Math.PI * 2), 0.5));
        }
    }
  }

  updateEliteAI(elite: EliteTank, dt: number) {
      const targets = this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && Vector.dist(e.pos, elite.pos) < elite.visionRange);
      const nearest = this.findNearest(elite, targets) as Tank | null;

      const steering = { x: 0, y: 0 };
      if (nearest) {
          const dirToNearest = Vector.sub(nearest.pos, elite.pos);
          const distToNearest = Vector.mag(dirToNearest);

          const incomingBullets = this.entities.filter(e => e.type === EntityType.BULLET && (e as Bullet).ownerId !== elite.id && Vector.dist(e.pos, elite.pos) < 500);
          incomingBullets.forEach(b => {
              const toBot = Vector.sub(elite.pos, b.pos);
              const bulletVelNorm = Vector.normalize(b.vel);
              const toBotNorm = Vector.normalize(toBot);

              if (Vector.dot(bulletVelNorm, toBotNorm) > 0.7) {
                  const sideForce = { x: -b.vel.y, y: b.vel.x };
                  const dotProduct = Vector.dot(sideForce, toBot);
                  const avoidDir = Vector.mult(Vector.normalize(sideForce), dotProduct > 0 ? 6.0 : -6.0);
                  steering.x += avoidDir.x; steering.y += avoidDir.y;
              }
          });

          const bSpeed = (BASE_STATS.bulletSpeed + elite.stats[StatType.BULLET_SPEED] * 0.8) * 1.5;
          const interceptPoint = this.getInterceptPoint(elite.pos, bSpeed, nearest.pos, nearest.vel);
          elite.rotation = Math.atan2(interceptPoint.y - elite.pos.y, interceptPoint.x - elite.pos.x);

          let targetForce = 0;
          if (distToNearest > 450) targetForce = 2.0;
          else if (distToNearest < 300) targetForce = -1.5;
          else targetForce = 0.6; 

          const approach = Vector.mult(Vector.normalize(dirToNearest), targetForce);
          steering.x += approach.x; steering.y += approach.y;

          const strafeAngle = Date.now() / 800;
          const strafeDir = Vector.normalize({ x: -dirToNearest.y, y: dirToNearest.x });
          const strafe = Vector.mult(strafeDir, Math.sin(strafeAngle) * 2.5);
          steering.x += strafe.x; steering.y += strafe.y;

          this.attemptShoot(elite);
      } else {
          const distToPatrol = Vector.dist(elite.pos, elite.patrolPos);
          if (distToPatrol > 200) {
              const patrol = Vector.mult(Vector.normalize(Vector.sub(elite.patrolPos, elite.pos)), 0.8);
              steering.x += patrol.x; steering.y += patrol.y;
          } else if (Math.random() < 0.01) {
              elite.vel = Vector.add(elite.vel, Vector.mult(Vector.fromAngle(Math.random() * Math.PI * 2), 0.5));
          }
      }

      elite.acc = Vector.limit(steering, 2.5);
  }

  getInterceptPoint(shooterPos: Vector2, bulletSpeed: number, targetPos: Vector2, targetVel: Vector2): Vector2 {
      const relPos = Vector.sub(targetPos, shooterPos);
      const dist = Vector.mag(relPos);
      const timeToHit = dist / bulletSpeed;
      const predictionFactor = Math.min(1.2, 0.5 + dist / 1000); 
      return Vector.add(targetPos, Vector.mult(targetVel, timeToHit * predictionFactor)); 
  }

  updateBotAI(bot: Tank, dt: number) {
      const hpRatio = bot.health / bot.maxHealth;
      const isLowHealth = hpRatio < 0.35;

      const vision = bot.visionRange;
      const neighbors = this.spatialGrid.getNeighbors(bot);

      const enemies = neighbors.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY || e.type === EntityType.ELITE_TANK) && (this.gameMode === GameMode.FFA || e.team !== bot.team));
      const friends = neighbors.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && e.team === bot.team);
      const shapes = neighbors.filter(e => e.type === EntityType.SHAPE || e.type === EntityType.BOSS || e.type === EntityType.CRASHER);
      const bullets = neighbors.filter(e => e.type === EntityType.BULLET && e.team !== bot.team);

      let target: Entity | null = this.findNearest(bot, enemies);
      if (!target && !isLowHealth) target = this.findNearest(bot, shapes);

      const steering = { x: 0, y: 0 };

      // Border Avoidance
      const borderVision = 800;
      const avoidanceStrength = 6.0;
      if (bot.pos.x < borderVision) steering.x += (Math.pow(1 - bot.pos.x / borderVision, 2)) * avoidanceStrength;
      if (bot.pos.x > CANVAS_WIDTH - borderVision) steering.x -= (Math.pow(1 - (CANVAS_WIDTH - bot.pos.x) / borderVision, 2)) * avoidanceStrength;
      if (bot.pos.y < borderVision) steering.y += (Math.pow(1 - bot.pos.y / borderVision, 2)) * avoidanceStrength;
      if (bot.pos.y > CANVAS_HEIGHT - borderVision) steering.y -= (Math.pow(1 - (CANVAS_HEIGHT - bot.pos.y) / borderVision, 2)) * avoidanceStrength;

      if ((bot.pos.x < 400 || bot.pos.x > CANVAS_WIDTH - 400) && (bot.pos.y < 400 || bot.pos.y > CANVAS_HEIGHT - 400)) {
          const centerDir = Vector.normalize(Vector.sub({x: CANVAS_WIDTH/2, y: CANVAS_HEIGHT/2}, bot.pos));
          steering.x += centerDir.x * 5.0; steering.y += centerDir.y * 5.0;
      }

      bullets.forEach(b => {
          const toBot = Vector.sub(bot.pos, b.pos);
          const dist = Vector.mag(toBot);
          const bulletVelNorm = Vector.normalize(b.vel);
          const toBotNorm = Vector.normalize(toBot);
          if (dist < 400 && Vector.dot(bulletVelNorm, toBotNorm) > 0.6) {
              const sideForce = { x: -b.vel.y, y: b.vel.x };
              const avoid = Vector.mult(Vector.normalize(sideForce), Vector.dot(sideForce, toBot) > 0 ? 4.5 : -4.5);
              steering.x += avoid.x; steering.y += avoid.y;
          }
      });

      friends.forEach(f => {
          const dist = Vector.dist(bot.pos, f.pos);
          if (dist < 200) {
              const sep = Vector.mult(Vector.normalize(Vector.sub(bot.pos, f.pos)), (200 - dist) / 30);
              steering.x += sep.x; steering.y += sep.y;
          }
      });

      if (isLowHealth && enemies.length > 0) {
          bot.aiState = 'FLEE';
          const nearestEnemy = this.findNearest(bot, enemies);
          if (nearestEnemy) {
              const fleeDir = Vector.normalize(Vector.sub(bot.pos, nearestEnemy.pos));
              steering.x += fleeDir.x * 4.0; steering.y += fleeDir.y * 4.0;
          }
      } else if (target) {
          const dist = Vector.dist(target.pos, bot.pos);
          const isEnemy = enemies.includes(target as any);
          bot.aiState = isEnemy ? 'COMBAT' : 'FARM';

          let idealRange = 350;
          let aggressiveness = 1.5;

          if (bot.classType === TankClass.SNIPER || bot.classType === TankClass.RANGER || bot.classType === TankClass.ASSASSIN || bot.classType === TankClass.STALKER) { 
              idealRange = vision * 0.75; aggressiveness = 1.1; 
          } else if (bot.classType === TankClass.DESTROYER || bot.classType === TankClass.ANNIHILATOR) { 
              idealRange = 220; aggressiveness = 1.8; 
          } else if (bot.classType === TankClass.BOOSTER || bot.classType === TankClass.TRI_ANGLE || bot.classType === TankClass.FIGHTER) { 
              idealRange = 60; aggressiveness = 2.5; 
          }

          const dir = Vector.sub(target.pos, bot.pos);
          const moveDir = Vector.normalize(dir);
          if (dist > idealRange + 100) { 
              steering.x += moveDir.x * aggressiveness; steering.y += moveDir.y * aggressiveness; 
          } else if (dist < idealRange - 50) { 
              steering.x -= moveDir.x * (aggressiveness * 1.5); steering.y -= moveDir.y * (aggressiveness * 1.5); 
          }

          if (isEnemy) {
              const timeFactor = Date.now() / 700;
              const strafeOsc = (Math.sin(timeFactor + bot.id) * 2.5) + (Math.cos(timeFactor * 0.5) * 1.5);
              const strafeDir = { x: -moveDir.y, y: moveDir.x };
              steering.x += strafeDir.x * strafeOsc; steering.y += strafeDir.y * strafeOsc;
          } else if (dist < 150) {
                 const orbitDir = { x: -moveDir.y, y: moveDir.x };
                 steering.x += orbitDir.x * 2.0; steering.y += orbitDir.y * 2.0;
          }

          const bSpeed = (BASE_STATS.bulletSpeed + bot.stats[StatType.BULLET_SPEED] * 0.8);
          const aimPos = this.getInterceptPoint(bot.pos, bSpeed, target.pos, target.vel || {x:0, y:0});
          const targetRot = Math.atan2(aimPos.y - bot.pos.y, aimPos.x - bot.pos.x);
          let diff = targetRot - bot.rotation;
          while (diff > Math.PI) diff -= Math.PI * 2;
          while (diff < -Math.PI) diff += Math.PI * 2;
          bot.rotation += diff * 0.25; 
          if (Math.abs(diff) < 0.6) this.attemptShoot(bot);
      } else {
          bot.aiState = 'IDLE';
          if (Math.random() < 0.01) {
              const wander = Vector.fromAngle(Math.random() * Math.PI * 2);
              bot.vel = Vector.add(bot.vel, Vector.mult(wander, 1.2));
          }
      }

      this.applyTankMovement(bot, Vector.limit(steering, 2.5));
      if (bot.availableStatPoints > 0) {
          const priorities = BOT_STAT_PRIORITIES[bot.classType] || Object.values(StatType);
          this.upgradeStat(bot, priorities[Math.floor(Math.random() * (priorities.length / 2))]);
      }
  }

  awardXP(tank: Tank, amount: number) {
      if (this.gameMode === GameMode.SANDBOX) return;
      const xpBuff = tank.activeBuffs.find(b => b.type === 'XP_MULT');
      let finalAmount = amount * (xpBuff ? 2.0 : 1.0);
      if (tank.isTransformed) finalAmount *= 2.0;

      tank.score += finalAmount;
      if (tank === this.player) {
          this.xp += finalAmount;
          while (this.level < MAX_LEVEL && this.xp >= this.getLevelXp(this.level)) {
              this.xp -= this.getLevelXp(this.level);
              this.level++;
              this.player.level = this.level;
              if (this.level <= 60) this.player.availableStatPoints++;
              this.player.updateStats(); 
              this.sound.playLevelUp();
          }
      } else {
          let nextLevelXp = this.getLevelXp(tank.level);
          while (tank.level < MAX_LEVEL && tank.score >= nextLevelXp) {
              tank.level++;
              if (tank.level <= 60) tank.availableStatPoints++;
              tank.updateStats();
              nextLevelXp = this.getLevelXp(tank.level);
              if (tank.level % 15 === 0 && CLASS_TREE[tank.classType]?.length > 0) {
                  const choices = CLASS_TREE[tank.classType];
                  this.upgradeClassForTank(tank, choices[Math.floor(Math.random() * choices.length)]);
              }
          }
      }
  }

  attemptShoot(tank: Tank) {
    const baseReloadTimeMs = (BASE_STATS.reload - (tank.stats[StatType.RELOAD] * 2.5)) * 16.67; 
    let shotFired = false;

    // SEQUENTIAL BARREL SELECTION
    const idx = tank.nextBarrelIndex % tank.barrels.length;
    const barrel = tank.barrels[idx];

    // Handle Hybrid special: Spawner barrel should be independent or skipped in sequential cycle?
    // Let's treat it as a standard barrel for simplicity in sequential logic.
    const droneBarrelIndex = (tank.classType === TankClass.HYBRID) ? 1 : -1;
    const isDroneSpawner = (tank.classType === TankClass.OVERLORD || tank.classType === TankClass.OVERSEER || (tank.classType === TankClass.HYBRID && idx === droneBarrelIndex));

    if (isDroneSpawner) {
        const droneLimit = (tank.classType === TankClass.OVERLORD) ? 12 : (tank.classType === TankClass.OVERSEER) ? 8 : 4;
        let currentDrones = this.entities.filter(e => e.type === EntityType.DRONE && (e as Drone).owner === tank).length;

        if (currentDrones < droneLimit && (tank.barrelCooldowns[idx] <= 0 || this.sandboxConfig.infiniteAmmo)) {
            const [length, width, xOff, angleOff] = barrel;
            const angle = tank.rotation + angleOff;
            const tip = Vector.add(tank.pos, Vector.mult(Vector.fromAngle(angle), tank.radius * length));

            const drone = new Drone(this.nextId(), tip.x, tip.y, tank);
            this.entities.push(drone);

            const cooldownVal = Math.max(250, baseReloadTimeMs * (tank.classType === TankClass.HYBRID ? 2.5 : 4.0)); 
            if (!this.sandboxConfig.infiniteAmmo) {
                tank.barrelCooldowns[idx] = cooldownVal;
                tank.barrelMaxCooldowns[idx] = cooldownVal;
            }
            tank.nextBarrelIndex++;
            shotFired = true;
            if (tank.classType !== TankClass.HYBRID) this.sound.playShoot(tank.classType);
        }
    } else if (tank.barrelCooldowns[idx] <= 0 || this.sandboxConfig.infiniteAmmo) {
        // BULLET FIRING LOGIC
        const isHeavy = tank.classType === TankClass.DESTROYER || tank.classType === TankClass.HYBRID || tank.classType === TankClass.ANNIHILATOR;
        let bulletSpeedMult = 1.0, bulletDamageMult = 1.0, bulletLifeMult = 1.0, bulletSizeMult = 1.0;

        if (tank.classType === TankClass.SNIPER) { bulletSpeedMult = 1.15; bulletDamageMult = 1.35; bulletLifeMult = 1.25; }
        else if (tank.classType === TankClass.ASSASSIN) { bulletSpeedMult = 1.35; bulletDamageMult = 1.55; bulletLifeMult = 1.6; }
        else if (tank.classType === TankClass.RANGER || tank.classType === TankClass.STALKER) { bulletSpeedMult = 1.65; bulletDamageMult = 1.95; bulletLifeMult = 2.0; }
        else if (tank.classType === TankClass.DESTROYER || tank.classType === TankClass.HYBRID) { bulletSizeMult = 3.6; bulletDamageMult = 5.5; bulletLifeMult = 1.5; bulletSpeedMult = 0.85; }
        else if (tank.classType === TankClass.ANNIHILATOR) { bulletSizeMult = 5.0; bulletDamageMult = 6.5; bulletLifeMult = 1.8; bulletSpeedMult = 0.8; }
        else if (tank.classType === TankClass.GUNNER || tank.classType === TankClass.AUTO_GUNNER) { bulletSizeMult = 0.65; bulletDamageMult = 0.7; bulletSpeedMult = 1.65; }
        else if (tank.classType === TankClass.STREAMLINER) { bulletDamageMult = 0.45; bulletSizeMult = 0.6; bulletSpeedMult = 1.8; }

        const [length, width, xOff, angleOff, delayMultiplier, yOff = 0] = barrel;
        const accuracyFactor = Math.pow(0.82, tank.stats[StatType.BULLET_SPREAD]); 
        const angle = tank.rotation + angleOff + Vector.randomRange(-tank.spread * accuracyFactor, tank.spread * accuracyFactor);
        const forward = Vector.fromAngle(angle);

        const lateralAngle = tank.rotation + angleOff + Math.PI/2;
        const startPos = Vector.add(tank.pos, { 
            x: Math.cos(lateralAngle) * (yOff * tank.radius) + Math.cos(tank.rotation + angleOff) * (xOff * tank.radius), 
            y: Math.sin(lateralAngle) * (yOff * tank.radius) + Math.sin(tank.rotation + angleOff) * (xOff * tank.radius) 
        });
        const tip = Vector.add(startPos, Vector.mult(forward, tank.radius * length));

        this.entities.push(new Bullet(this.nextId(), tip.x, tip.y, Vector.mult(forward, (BASE_STATS.bulletSpeed + tank.stats[StatType.BULLET_SPEED] * 0.8) * bulletSpeedMult), tank, bulletDamageMult, bulletLifeMult, bulletSizeMult));

        // UNIQUE HEAVY ANIMATION TRIGGER
        if (isHeavy) {
            tank.barrelHeat[idx] = 1.0; // Trigger glow
            if (tank === this.player || this.isOnScreen(tank.pos)) {
                // Muzzle blast GAS particles
                for(let k=0; k<8; k++) this.particles.push(new Particle(tip.x, tip.y, 'rgba(50, 50, 50, 0.4)', 15, 30, 'GAS'));

                if (tank.classType === TankClass.ANNIHILATOR) {
                    // Shockwave ring for Annihilator
                    this.particles.push(new Particle(tip.x, tip.y, 'rgba(255, 255, 255, 0.3)', 20, 20, 'RING'));
                }
            }
        }

        if (tank === this.player || this.isOnScreen(tank.pos)) {
             this.particles.push(new Particle(tip.x, tip.y, 'rgba(255, 220, 100, 0.4)', (tank.radius * 0.4) * bulletSizeMult, 6, 'FLASH'));
        }

        // --- EXTREME RECOIL NERF FOR MULTI-BARREL CLASSES ---
        let recoilPower = 0.2; // Drastically lower default
        if (isHeavy) {
            recoilPower = (tank.classType === TankClass.ANNIHILATOR ? 4.5 : 3.2);
        } else if (tank.classType === TankClass.STREAMLINER) {
            recoilPower = 0.02; // Negligible recoil to prevent flash speed
        } else if (tank.classType === TankClass.TRI_ANGLE || tank.classType === TankClass.BOOSTER || tank.classType === TankClass.FIGHTER) {
            recoilPower = (angleOff === 0) ? 0.2 : 2.5; // Nerfed back-boosters slightly
        } else if (tank.barrels.length > 2) {
            recoilPower = 0.05; // Significant nerf for triple shots, spread shots etc
        }

        if (this.sandboxConfig.knockbackEnabled) tank.vel = Vector.sub(tank.vel, Vector.mult(forward, recoilPower)); 

        const cooldownVal = Math.max(40, baseReloadTimeMs * delayMultiplier);
        if (!this.sandboxConfig.infiniteAmmo) {
            tank.barrelCooldowns[idx] = cooldownVal;
            tank.barrelMaxCooldowns[idx] = cooldownVal;
        }
        tank.nextBarrelIndex++;
        shotFired = true;
    }

    if (shotFired) { if (tank === this.player || this.isOnScreen(tank.pos)) this.sound.playShoot(tank.classType); }
  }

  applyTankMovement(tank: Tank, dir: Vector2) { 
    if (Vector.mag(dir) > 0) {
      const weightPenalty = tank.stats[StatType.BODY_DAMAGE] * 0.12;
      const speedBonus = tank.stats[StatType.MOVEMENT_SPEED] * 0.6;
      const effectiveSpeed = Math.max(1.8, BASE_STATS.speed + speedBonus - weightPenalty);
      tank.acc = Vector.mult(Vector.normalize(dir), effectiveSpeed * (1 - tank.friction) / tank.friction); 
    }
  }

  findNearest(origin: Entity, targets: Entity[]): Entity | null { let nearest = null; let minDst = Infinity; for (const t of targets) { const d = Vector.dist(origin.pos, t.pos); if (d < minDst) { minDst = d; nearest = t; } } return nearest; }
  isOnScreen(pos: Vector2, radius: number = 0) {
    const viewW = window.innerWidth / this.cameraZoom, viewH = window.innerHeight / this.cameraZoom;
    return (pos.x + radius > this.cameraPos.x - viewW / 2 && pos.x - radius < this.cameraPos.x + viewW / 2 && pos.y + radius > this.cameraPos.y - viewH / 2 && pos.y - radius < this.cameraPos.y + viewH / 2);
  }

  spawnEnemy() {
      let pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT), team = Team.RED;
      if (this.gameMode === GameMode.TEAMS) {
          const blueTanks = this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && e.team === Team.BLUE).length;
          const redTanks = this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && e.team === Team.RED).length;
          if (blueTanks < 30 && redTanks < 30) team = Math.random() < 0.5 ? Team.BLUE : Team.RED;
          else if (blueTanks < 30) team = Team.BLUE; else if (redTanks < 30) team = Team.RED; else return;
          pos.x = team === Team.BLUE ? Vector.randomRange(50, CANVAS_WIDTH / 2) : Vector.randomRange(CANVAS_WIDTH / 2, CANVAS_WIDTH - 50);
      }
      const bot = new Tank(this.nextId(), pos.x, pos.y, false, team);
      bot.name = BOT_NAMES[Math.floor(Math.random() * BOT_NAMES.length)];
      const targetLevel = Math.floor(Math.random() * 30) + 15; 
      bot.level = targetLevel;
      const classes = Object.values(TankClass).filter(c => c !== TankClass.BASIC);
      const chosenClass = classes[Math.floor(Math.random() * classes.length)];
      this.upgradeClassForTank(bot, chosenClass || TankClass.BASIC);
      let pointsToSpend = Math.min(targetLevel, 60) - 1; 
      const priorities = BOT_STAT_PRIORITIES[chosenClass || TankClass.BASIC] || BOT_STAT_PRIORITIES[TankClass.BASIC];
      while (pointsToSpend > 0) { for (const stat of priorities) { if (pointsToSpend <= 0) break; if (bot.stats[stat] < 8) { bot.stats[stat]++; pointsToSpend--; } } }
      bot.updateStats(); bot.health = bot.maxHealth; bot.score = 500 * targetLevel; this.entities.push(bot);
  }

  spawnShape() {
    const center = { x: CANVAS_WIDTH / 2, y: CANVAS_HEIGHT / 2 }, nestRadius = 1500, isNestSpawn = Math.random() < 0.2; 
    let pos: Vector2, type: ShapeType;
    if (this.inVoid) {
        pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT);
        const roll = Math.random();
        if (roll < 0.10) type = ShapeType.OCTAGON; else if (roll < 0.30) type = ShapeType.HEXAGON; else if (roll < 0.60) type = ShapeType.PENTAGON; else if (roll < 0.85) type = ShapeType.TRIANGLE; else type = ShapeType.SQUARE;
    } else if (isNestSpawn) {
        const angle = Math.random() * Math.PI * 2, dist = Math.sqrt(Math.random()) * nestRadius;
        pos = { x: center.x + Math.cos(angle) * dist, y: center.y + Math.sin(angle) * dist };
        const roll = Math.random();
        if (roll < 0.1) type = ShapeType.OCTAGON; else if (roll < 0.3) type = ShapeType.HEXAGON; else if (roll < 0.7) type = ShapeType.PENTAGON; else type = ShapeType.TRIANGLE;
    } else {
        pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT);
        const roll = Math.random();
        if (roll < 0.02) type = ShapeType.OCTAGON; else if (roll < 0.05) type = ShapeType.HEXAGON; else if (roll < 0.15) type = ShapeType.PENTAGON; else if (roll < 0.45) type = ShapeType.TRIANGLE; else type = ShapeType.SQUARE;
    }
    if (Vector.dist(pos, this.player.pos) < 250) return;
    this.entities.push(new Shape(this.nextId(), pos.x, pos.y, type, this.inVoid));
    this.currentShapeCount++;
  }

  handleCollisions() {
    this.spatialGrid.clear();
    this.entities.forEach(e => this.spatialGrid.add(e));
    this.entities.forEach(a => {
        if (a.isDead) return;
        const neighbors = this.spatialGrid.getNeighbors(a);
        neighbors.forEach(b => {
            if (a === b || b.isDead) return;
            const minDist = a.radius + b.radius;
            const d2 = (a.pos.x - b.pos.x) ** 2 + (a.pos.y - b.pos.y) ** 2;
            if (d2 < minDist * minDist) {
                if (a.type === EntityType.VOID_PORTAL || b.type === EntityType.VOID_PORTAL) {
                    const portal = (a.type === EntityType.VOID_PORTAL ? a : b) as VoidPortal, other = (a.type === EntityType.VOID_PORTAL ? b : a);
                    if (other.type === EntityType.PLAYER || other.type === EntityType.ENEMY) {
                        const toPortal = Vector.sub(portal.pos, other.pos), distToCenter = Vector.mag(toPortal);
                        other.vel = Vector.add(other.vel, Vector.mult(Vector.normalize(toPortal), 2.5));
                        if (distToCenter < portal.radius * 0.5) {
                            if (portal.isExit && this.inVoid) this.transitionToDimension(false);
                            else if (!portal.isExit && !this.inVoid) this.transitionToDimension(true);
                        }
                    }
                    return; 
                }
                if (this.gameMode === GameMode.TEAMS && a.team === b.team && a.team !== Team.NONE && !this.inVoid) {
                    if (a.type !== EntityType.BULLET && a.type !== EntityType.DRONE && a.type !== EntityType.MINI_TANK && b.type !== EntityType.BULLET && b.type !== EntityType.DRONE && b.type !== EntityType.MINI_TANK) this.resolveCollision(a, b, false);
                    return;
                }
                if (a.type === EntityType.BULLET && (a as Bullet).ownerId === b.id) return;
                if (b.type === EntityType.BULLET && (b as Bullet).ownerId === a.id) return;
                if (a.type === EntityType.DRONE && (a as Drone).owner.id === b.id) return;
                if (b.type === EntityType.DRONE && (b as Drone).owner.id === a.id) return;
                if (a.type === EntityType.MINI_TANK && (a as MiniTank).owner.id === b.id) return;
                if (b.type === EntityType.MINI_TANK && (b as MiniTank).owner.id === a.id) return;
                this.resolveCollision(a, b, true);
            }
        });
    });
  }

  resolveCollision(a: Entity, b: Entity, applyDamage: boolean = true) {
     const dir = Vector.normalize(Vector.sub(a.pos, b.pos)), distVal = Vector.dist(a.pos, b.pos), overlap = (a.radius + b.radius) - distVal;
     let ratioA = 0.5, ratioB = 0.5, pcf = 1.0; 
     if (a.type === EntityType.BULLET || b.type === EntityType.BULLET) pcf = 0.05; 
     if (a.type === EntityType.DRONE || b.type === EntityType.DRONE || a.type === EntityType.MINI_TANK || b.type === EntityType.MINI_TANK) pcf = 0.2;
     if (a.type === EntityType.BOSS || b.type === EntityType.BOSS || a.type === EntityType.DUMMY || b.type === EntityType.DUMMY) { if (a.type === EntityType.BOSS || a.type === EntityType.DUMMY) { ratioA = 0.0; ratioB = 1.0; } else { ratioA = 1.0; ratioB = 0.0; } }
     else if (a.type === EntityType.GUARDIAN || b.type === EntityType.GUARDIAN) { if (a.type === EntityType.GUARDIAN && b.type !== EntityType.GUARDIAN) { ratioA = 0.05; ratioB = 1.0; } else if (b.type === EntityType.GUARDIAN && a.type !== EntityType.GUARDIAN) { ratioA = 1.0; ratioB = 0.05; } }
     else if (a.type === EntityType.BULLET && b.type !== EntityType.BULLET) { ratioA = 0.01; ratioB = 0.99; }
     else if (b.type === EntityType.BULLET && a.type !== EntityType.BULLET) { ratioA = 0.99; ratioB = 0.01; }
     else { const totalMass = a.mass + b.mass; ratioA = b.mass / totalMass; ratioB = a.mass / totalMass; }
     const force = Vector.mult(dir, overlap * pcf);
     a.pos = Vector.add(a.pos, Vector.mult(force, ratioA)); b.pos = Vector.sub(b.pos, Vector.mult(force, ratioB));
     if (!applyDamage) return;
     let dmgA = b.damage, dmgB = a.damage;
     if (a.type === EntityType.PLAYER && this.sandboxConfig.invincible) dmgA = 0;
     if (b.type === EntityType.PLAYER && this.sandboxConfig.invincible) dmgB = 0;
     let sA: number | null = null, sB: number | null = null;
     if (b.type === EntityType.BULLET) sA = (b as Bullet).ownerId; else if (b.type === EntityType.DRONE) sA = (b as Drone).owner.id; else if (b.type === EntityType.MINI_TANK) sA = (b as MiniTank).owner.id; else if (b.type === EntityType.PLAYER || b.type === EntityType.ENEMY || b.type === EntityType.ELITE_TANK) sA = b.id;
     if (a.type === EntityType.BULLET) sB = (a as Bullet).ownerId; else if (a.type === EntityType.DRONE) sB = (a as Drone).owner.id; else if (a.type === EntityType.MINI_TANK) sB = (a as MiniTank).owner.id; else if (a.type === EntityType.PLAYER || a.type === EntityType.ENEMY || a.type === EntityType.ELITE_TANK) sB = a.id;
     a.takeDamage(dmgA, sA); b.takeDamage(dmgB, sB);
     if (dmgA > 1 && a.type !== EntityType.GUARDIAN && a.type !== EntityType.BULLET) this.spawnDamageText(a.pos, dmgA, a.id);
     if (dmgB > 1 && b.type !== EntityType.GUARDIAN && b.type !== EntityType.BULLET) this.spawnDamageText(b.pos, dmgB, b.id);
     if (a.type === EntityType.BULLET || b.type === EntityType.BULLET || a.type === EntityType.DRONE || b.type === EntityType.DRONE || a.type === EntityType.MINI_TANK || b.type === EntityType.MINI_TANK) { if ((a.type === EntityType.PLAYER || b.type === EntityType.PLAYER) || this.isOnScreen(a.pos)) this.sound.playHit(); }
     if (this.sandboxConfig.knockbackEnabled) { const baseKb = 2.0; if ((a.type === EntityType.BULLET || a.type === EntityType.DRONE || a.type === EntityType.MINI_TANK) && b.type !== EntityType.BULLET && b.type !== EntityType.DUMMY) { const mMult = Math.min(1.0, 35 / b.mass); b.vel = Vector.add(b.vel, Vector.mult(dir, -(baseKb * mMult * (b.type === EntityType.SHAPE ? 0.8 : 1.0)))); } else if ((b.type === EntityType.BULLET || b.type === EntityType.DRONE || b.type === EntityType.MINI_TANK) && a.type !== EntityType.BULLET && a.type !== EntityType.DUMMY) { const mMult = Math.min(1.0, 35 / a.mass); a.vel = Vector.add(a.vel, Vector.mult(dir, baseKb * mMult * (a.type === EntityType.SHAPE ? 0.8 : 1.0))); } }
     if (a.isDead) this.handleDeath(a, b); if (b.isDead) this.handleDeath(b, a);
  }

  spawnDamageText(pos: Vector2, amount: number, entityId: number | null = null) { const val = Math.floor(amount); if (val === 0) return; if (entityId !== null) { const existing = this.floatingTexts.find(ft => ft.type === 'DAMAGE' && ft.entityId === entityId); if (existing) { existing.stack(val); existing.pos.x = pos.x; existing.pos.y = pos.y - 25; return; } } this.floatingTexts.push(new FloatingText(pos.x, pos.y - 20, val, 'DAMAGE', val > 20 ? 26 : 18, val > 20, entityId)); }
  spawnScoreText(pos: Vector2, amount: number) { this.floatingTexts.push(new FloatingText(pos.x, pos.y - 25, amount, 'SCORE', 22)); }
  spawnParticles(pos: Vector2, color: string, count: number, size: number = 3) { for(let i=0; i<count; i++) this.particles.push(new Particle(pos.x, pos.y, color, size + Math.random() * 2)); }

  handleDeath(victim: Entity, killer: Entity) {
      if (victim.type === EntityType.DUMMY) return; 
      if (this.isOnScreen(victim.pos)) { this.sound.playExplosion(victim.radius > 20); this.spawnParticles(victim.pos, victim.color, victim.radius > 20 ? 12 : 6, victim.radius / 5); }
      if (victim.type === EntityType.ELITE_TANK) {
          const v = victim as EliteTank; this.addNotification(`${v.name.toUpperCase()} DEFEATED!`, "#ff4444");
          const contributors = Array.from(v.damageDealtBy.entries()), totalDmg = contributors.reduce((acc, curr) => acc + curr[1], 0);
          v.damageDealtBy.forEach((dmg, id) => {
              const tank = this.entities.find(e => e.id === id) as Tank | undefined;
              if (tank) {
                  const contrib = dmg / totalDmg, xpReward = Math.floor(Vector.randomRange(50000, 100000) * contrib);
                  this.awardXP(tank, xpReward); if (tank === this.player) this.spawnScoreText(tank.pos, xpReward);
                  const roll = Math.random(); if (roll < 0.1) this.addNotification("LEGENDARY SIGNAL DETECTED!", "#ff5e00"); else if (roll < 0.3) { tank.activeBuffs.push({ type: 'POWER_TOKEN', timeLeft: 300, totalTime: 300 }); tank.updateStats(); } else if (roll < 0.6) tank.activeBuffs.push({ type: 'XP_MULT', timeLeft: 600, totalTime: 600 });
              }
          });
      }
      if (victim.type === EntityType.PLAYER || victim.type === EntityType.ENEMY || victim.type === EntityType.BOSS || victim.type === EntityType.ELITE_TANK) {
            let killerName = killer.name;
            if (killer.type === EntityType.BULLET) { const owner = this.entities.find(e => e.id === (killer as Bullet).ownerId); killerName = owner ? owner.name : "Unknown"; }
            else if (killer.type === EntityType.DRONE) killerName = (killer as Drone).owner.name;
            else if (killer.type === EntityType.MINI_TANK) killerName = `${(killer as MiniTank).owner.name}'s Unit`;
            this.addToKillFeed(killerName || 'Unknown', victim.name || 'Unknown');
      }
      if (victim.type === EntityType.SHAPE || victim.type === EntityType.BOSS) {
          const v = victim as (Shape | Boss), totalXp = victim.type === EntityType.SHAPE ? (v as Shape).xpValue : (v as Boss).xpValue;
          let totalDmg = 0; v.damageDealtBy.forEach(val => totalDmg += val);
          if (totalDmg > 0) {
              v.damageDealtBy.forEach((dmg, id) => {
                  const tank = this.entities.find(e => e.id === id) as Tank | undefined;
                  if (tank) { const share = Math.floor(totalXp * (dmg / totalDmg)); if (share > 0) { this.awardXP(tank, share); if (tank === this.player) this.spawnScoreText(victim.pos, share); } }
              });
              return; 
          }
      }
      let killerTank: Tank | null = null;
      if (killer.type === EntityType.PLAYER || killer.type === EntityType.ENEMY) killerTank = killer as Tank;
      else if (killer.type === EntityType.BULLET) { const owner = this.entities.find(e => e.id === (killer as Bullet).ownerId); if (owner instanceof Tank) killerTank = owner; }
      else if (killer.type === EntityType.DRONE) killerTank = (killer as Drone).owner;
      else if (killer.type === EntityType.MINI_TANK) killerTank = (killer as MiniTank).owner;
      if (killerTank) {
          const xp = (victim.type === EntityType.ENEMY || victim.type === EntityType.PLAYER) ? ((victim as Tank).score / 2 || 500) : 10;
          this.awardXP(killerTank, xp); if (killerTank === this.player) this.spawnScoreText(victim.pos, xp);
      }
  }

  addToKillFeed(k: string, v: string) { this.killFeed.unshift({ id: `${Date.now()}-${Math.random()}`, killerName: k, victimName: v, timestamp: Date.now() }); if (this.killFeed.length > 6) this.killFeed.pop(); }
  getLevelXp(l: number) { return Math.floor(100 * Math.pow(XP_CURVE_MULTIPLIER, l - 1)); }
  upgradeStat(t: Tank, s: StatType) { if (t.availableStatPoints > 0 && t.stats[s] < 8) { t.stats[s]++; t.availableStatPoints--; t.updateStats(); if (t.id === this.player.id) this.sound.playStatUpgrade(); } }
  upgradeClass(nc: TankClass) { this.upgradeClassForTank(this.player, nc); this.sound.playClassUpgrade(); }
  upgradeClassForTank(tank: Tank, newClass: TankClass) {
      tank.classType = newClass; tank.barrels = TANK_CONFIGS[newClass];
      tank.barrelCooldowns = new Array(tank.barrels.length).fill(0);
      tank.barrelMaxCooldowns = new Array(tank.barrels.length).fill(100);
      tank.barrelHeat = new Array(tank.barrels.length).fill(0);
      tank.nextBarrelIndex = 0;

      const baseReloadMs = (BASE_STATS.reload - (tank.stats[StatType.RELOAD] * 2.5)) * 16.67;

      const continuousFireClasses = [TankClass.TWIN, TankClass.TRIPLE_SHOT, TankClass.QUAD_TANK, TankClass.OCTO_TANK, TankClass.TRIPLE_TANK, TankClass.PENTA_SHOT, TankClass.GUNNER, TankClass.AUTO_GUNNER, TankClass.STREAMLINER, TankClass.SPREAD_SHOT];
      if (continuousFireClasses.includes(newClass)) {
          tank.barrels.forEach((_, i) => tank.barrelCooldowns[i] = (i / tank.barrels.length) * baseReloadMs);
      }

      // SPECIAL BURST STAGGER FOR HUNTER TYPES
      if (newClass === TankClass.HUNTER || newClass === TankClass.X_HUNTER) {
           const burstDelay = 120; // Fast sequence
           tank.barrels.forEach((_, i) => {
               tank.barrelCooldowns[i] = i * burstDelay;
           });
      }
  }

  draw() {
    this.ctx.fillStyle = this.inVoid ? COLORS.voidBackground : (this.darkMode ? '#0f0f0f' : '#b4b4b4'); this.ctx.fillRect(0, 0, window.innerWidth, window.innerHeight); 
    this.ctx.save(); this.ctx.translate(window.innerWidth / 2, window.innerHeight / 2); this.ctx.scale(this.cameraZoom, this.cameraZoom); this.ctx.translate(-this.cameraPos.x, -this.cameraPos.y);
    this.drawGrid(this.ctx); 
    this.ctx.strokeStyle = '#555'; this.ctx.lineWidth = 10; this.ctx.strokeRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
    const sorted = [...this.entities].sort((a, b) => { const order = { [EntityType.VOID_PORTAL]: 1, [EntityType.SHAPE]: 2, [EntityType.CRASHER]: 2, [EntityType.BULLET]: 3, [EntityType.DRONE]: 3, [EntityType.MINI_TANK]: 3, [EntityType.ENEMY]: 4, [EntityType.DUMMY]: 5, [EntityType.PLAYER]: 6, [EntityType.GUARDIAN]: 7, [EntityType.ELITE_TANK]: 8, [EntityType.BOSS]: 9 }; return (order[a.type] || 0) - (order[b.type] || 0); });
    sorted.forEach(e => { if (this.isOnScreen(e.pos, e.radius)) e.draw(this.ctx); });
    this.particles.forEach(p => { if (this.isOnScreen(p.pos, p.size)) p.draw(this.ctx); });
    this.floatingTexts.forEach(ft => ft.draw(this.ctx)); 
    if (this.inVoid) this.drawDarkness(this.ctx);
    this.ctx.restore();
    if (this.transitionAlpha > 0) { this.ctx.fillStyle = `rgba(0, 0, 0, ${this.transitionAlpha})`; this.ctx.fillRect(0, 0, window.innerWidth, window.innerHeight); }
  }

  private drawDarkness(ctx: CanvasRenderingContext2D) {
      this.lightingCanvas.width = window.innerWidth; this.lightingCanvas.height = window.innerHeight;
      this.lightingCtx.fillStyle = 'rgba(0, 0, 0, 0.96)'; this.lightingCtx.fillRect(0, 0, window.innerWidth, window.innerHeight);
      this.lightingCtx.globalCompositeOperation = 'destination-out';
      this.entities.forEach(e => {
          if (!this.isOnScreen(e.pos, 500)) return;
          const sx = (e.pos.x - this.cameraPos.x) * this.cameraZoom + window.innerWidth / 2, sy = (e.pos.y - this.cameraPos.y) * this.cameraZoom + window.innerHeight / 2;
          const grad = this.lightingCtx.createRadialGradient(sx, sy, 0, sx, sy, (e.type === EntityType.PLAYER ? 300 : 100) * this.cameraZoom);
          grad.addColorStop(0, 'rgba(255, 255, 255, 1.0)'); grad.addColorStop(1, 'rgba(255, 255, 255, 0)');
          this.lightingCtx.fillStyle = grad; this.lightingCtx.beginPath(); this.lightingCtx.arc(sx, sy, (e.type === EntityType.PLAYER ? 300 : 100) * this.cameraZoom, 0, Math.PI * 2); this.lightingCtx.fill();
      });
      this.lightingCtx.globalCompositeOperation = 'source-over'; ctx.setTransform(1, 0, 0, 1, 0, 0); ctx.drawImage(this.lightingCanvas, 0, 0);
  }

  drawGrid(ctx: CanvasRenderingContext2D) {
      const viewW = window.innerWidth / this.cameraZoom, viewH = window.innerHeight / this.cameraZoom;
      const startX = Math.max(0, Math.floor((this.cameraPos.x - viewW/2) / GRID_SIZE) * GRID_SIZE), endX = Math.min(CANVAS_WIDTH, Math.ceil((this.cameraPos.x + viewW/2) / GRID_SIZE) * GRID_SIZE);
      const startY = Math.max(0, Math.floor((this.cameraPos.y - viewH/2) / GRID_SIZE) * GRID_SIZE), endY = Math.min(CANVAS_WIDTH, Math.ceil((this.cameraPos.y + viewH/2) / GRID_SIZE) * GRID_SIZE);
      ctx.strokeStyle = this.inVoid ? '#151515' : (this.darkMode ? '#222222' : COLORS.background); ctx.lineWidth = 1; ctx.beginPath();
      for (let x = startX; x <= endX; x += GRID_SIZE) { ctx.moveTo(x, startY); ctx.lineTo(x, endY); }
      for (let y = startY; y <= endY; y += GRID_SIZE) { ctx.moveTo(startX, y); ctx.lineTo(endX, y); }
      ctx.stroke();
  }
}

import { TankClass } from '../types';

export class SoundEngine {
  ctx: AudioContext;
  masterGain: GainNode;
  noiseBuffer: AudioBuffer | null = null;
  volume: number = 0.15;

  // Throttle tracking to prevent audio clipping during high fire rates
  private lastPlayed: Record<string, number> = {};

  constructor() {
    // @ts-ignore
    const AudioContextClass = window.AudioContext || window.webkitAudioContext;
    this.ctx = new AudioContextClass();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = this.volume;

    // Add a master limiter to prevent clipping when many sounds play simultaneously
    const limiter = this.ctx.createDynamicsCompressor();
    limiter.threshold.setValueAtTime(-1, this.ctx.currentTime);
    limiter.knee.setValueAtTime(40, this.ctx.currentTime);
    limiter.ratio.setValueAtTime(12, this.ctx.currentTime);
    limiter.attack.setValueAtTime(0, this.ctx.currentTime);
    limiter.release.setValueAtTime(0.25, this.ctx.currentTime);

    this.masterGain.connect(limiter);
    limiter.connect(this.ctx.destination);

    this.noiseBuffer = this.createNoiseBuffer();
  }

  private throttle(key: string, cooldownMs: number): boolean {
    const now = Date.now();
    if (this.lastPlayed[key] && now - this.lastPlayed[key] < cooldownMs) {
      return false;
    }
    this.lastPlayed[key] = now;
    return true;
  }

  async resume() {
    if (this.ctx.state === 'suspended') {
      await this.ctx.resume();
    }
  }

  setVolume(value: number) {
      this.volume = Math.max(0, Math.min(1, value));
      if (this.masterGain) {
          this.masterGain.gain.setTargetAtTime(this.volume, this.ctx.currentTime, 0.05);
      }
  }

  /**
   * REMASTERED SHOOT SOUNDS
   * Uses three layers: 
   * 1. TRANSIENT (The mechanical click/pop)
   * 2. BODY (The frequency swept tone)
   * 3. EXHAUST (Noise-based boom/air release)
   */
  playShoot(type: TankClass = TankClass.BASIC) {
    this.resume();
    if (this.volume <= 0.001) return;

    // Throttle shoots to prevent "machine gun" overlapping artifacts for extremely fast tanks
    const minCooldown = (type === TankClass.STREAMLINER || type === TankClass.GUNNER) ? 20 : 35;
    if (!this.throttle(`shoot-${type}`, minCooldown)) return;

    const t = this.ctx.currentTime;

    // --- Randomized Pitch Control ---
    // Wider variance range (+/- 15%) for more life
    const pitchVariance = 0.85 + Math.random() * 0.3;

    let baseFreq = 220;
    let sweepDepth = 0.2; // How much of the freq remains at end
    let duration = 0.15;
    let amplitude = 0.35;
    let waveType: OscillatorType = 'triangle';
    let attackTime = 0.005;
    let noiseIntensity = 0.5;
    let noiseDecay = 0.05;

    // --- Class-Specific Remaster Profiles ---
    switch (type) {
        case TankClass.SNIPER:
        case TankClass.ASSASSIN:
        case TankClass.RANGER:
        case TankClass.STALKER:
            baseFreq = 580; sweepDepth = 0.05; duration = 0.4; amplitude = 0.5; waveType = 'sawtooth';
            noiseIntensity = 0.8; noiseDecay = 0.1;
            break;
        case TankClass.MACHINE_GUN:
        case TankClass.SPRAYER:
            baseFreq = 160; sweepDepth = 0.4; duration = 0.1; amplitude = 0.25; waveType = 'square';
            noiseIntensity = 0.4; noiseDecay = 0.03;
            break;
        case TankClass.STREAMLINER:
        case TankClass.GUNNER:
        case TankClass.AUTO_GUNNER:
            baseFreq = 340; sweepDepth = 0.6; duration = 0.06; amplitude = 0.18; waveType = 'triangle';
            noiseIntensity = 0.2; noiseDecay = 0.02;
            break;
        case TankClass.DESTROYER:
        case TankClass.HYBRID:
        case TankClass.ANNIHILATOR:
            baseFreq = 90; sweepDepth = 0.1; duration = 0.6; amplitude = 0.7; waveType = 'sine';
            attackTime = 0.015; noiseIntensity = 1.2; noiseDecay = 0.4;
            break;
        case TankClass.HUNTER:
        case TankClass.X_HUNTER:
            baseFreq = 420; sweepDepth = 0.3; duration = 0.25; amplitude = 0.4; waveType = 'sawtooth';
            noiseIntensity = 0.6; noiseDecay = 0.08;
            break;
        default: // BASIC / TWIN etc
            baseFreq = 240; sweepDepth = 0.2; duration = 0.15; amplitude = 0.35; waveType = 'triangle';
            break;
    }

    const finalBaseFreq = baseFreq * pitchVariance;

    // --- LAYER 1: TRANSIENT (Click) ---
    const transOsc = this.ctx.createOscillator();
    const transGain = this.ctx.createGain();
    transOsc.type = 'square';
    transOsc.frequency.setValueAtTime(finalBaseFreq * 2, t);
    transGain.gain.setValueAtTime(0, t);
    transGain.gain.linearRampToValueAtTime(amplitude * 0.5, t + 0.002);
    transGain.gain.linearRampToValueAtTime(0, t + 0.01);
    transOsc.connect(transGain);
    transGain.connect(this.masterGain);
    transOsc.start(t);
    transOsc.stop(t + 0.015);

    // --- LAYER 2: BODY (Tone) ---
    const bodyOsc = this.ctx.createOscillator();
    const bodyGain = this.ctx.createGain();
    bodyOsc.type = waveType;
    bodyOsc.frequency.setValueAtTime(finalBaseFreq, t);
    bodyOsc.frequency.exponentialRampToValueAtTime(Math.max(10, finalBaseFreq * sweepDepth), t + duration);

    bodyGain.gain.setValueAtTime(0, t);
    bodyGain.gain.linearRampToValueAtTime(amplitude, t + attackTime);
    bodyGain.gain.exponentialRampToValueAtTime(0.001, t + duration);

    bodyOsc.connect(bodyGain);
    bodyGain.connect(this.masterGain);
    bodyOsc.start(t);
    bodyOsc.stop(t + duration + 0.1);

    // --- LAYER 3: EXHAUST (Noise) ---
    if (this.noiseBuffer) {
        const noiseSrc = this.ctx.createBufferSource();
        noiseSrc.buffer = this.noiseBuffer;
        const noiseGain = this.ctx.createGain();
        const noiseFilter = this.ctx.createBiquadFilter();

        noiseFilter.type = 'bandpass';
        // Higher pitch = sharper air crack, Lower pitch = heavy boom
        noiseFilter.frequency.setValueAtTime(finalBaseFreq * 4, t);
        noiseFilter.Q.value = 1.2;

        noiseGain.gain.setValueAtTime(0, t);
        noiseGain.gain.linearRampToValueAtTime(amplitude * noiseIntensity, t + 0.005);
        noiseGain.gain.exponentialRampToValueAtTime(0.001, t + noiseDecay);

        noiseSrc.connect(noiseFilter);
        noiseFilter.connect(noiseGain);
        noiseGain.connect(this.masterGain);
        noiseSrc.start(t);
        noiseSrc.stop(t + noiseDecay + 0.1);
    }
  }

  playHit() {
    this.resume();
    if (this.volume <= 0.001) return;

    if (!this.throttle('hit', 60)) return;

    const t = this.ctx.currentTime;
    const pitch = 0.8 + Math.random() * 0.4;

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    osc.type = 'square';
    osc.frequency.setValueAtTime(180 * pitch, t);
    osc.frequency.linearRampToValueAtTime(40, t + 0.05);

    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(0.15, t + 0.002);
    gain.gain.linearRampToValueAtTime(0, t + 0.05);

    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start(t);
    osc.stop(t + 0.06);
  }

  playExplosion(isLarge: boolean = false) {
    this.resume();
    if (this.volume <= 0.001) return;
    if (!this.noiseBuffer) return;

    if (!this.throttle(isLarge ? 'explosion-large' : 'explosion-small', 150)) return;

    const t = this.ctx.currentTime;
    const duration = isLarge ? 0.85 : 0.4;
    const vol = isLarge ? 0.55 : 0.3;

    const src = this.ctx.createBufferSource();
    src.buffer = this.noiseBuffer;

    const lowpass = this.ctx.createBiquadFilter();
    lowpass.type = 'lowpass';
    lowpass.frequency.setValueAtTime(isLarge ? 350 : 900, t);
    lowpass.frequency.exponentialRampToValueAtTime(25, t + duration);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(vol, t + 0.015);
    gain.gain.exponentialRampToValueAtTime(0.001, t + duration);

    src.connect(lowpass);
    lowpass.connect(gain);
    gain.connect(this.masterGain);
    src.start(t);
    src.stop(t + duration + 0.1);

    if (isLarge) {
        const rumble = this.ctx.createOscillator();
        const rumbleG = this.ctx.createGain();
        rumble.type = 'sine';
        rumble.frequency.setValueAtTime(55, t);
        rumble.frequency.exponentialRampToValueAtTime(15, t + duration * 1.6);

        rumbleG.gain.setValueAtTime(0, t);
        rumbleG.gain.linearRampToValueAtTime(0.3, t + 0.06);
        rumbleG.gain.exponentialRampToValueAtTime(0.001, t + duration * 1.6);

        rumble.connect(rumbleG);
        rumbleG.connect(this.masterGain);
        rumble.start(t);
        rumble.stop(t + duration * 1.6);
    }
  }

  playLevelUp() {
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const notes = [523.25, 659.25, 783.99, 1046.50]; 

    notes.forEach((freq, i) => {
        const osc = this.ctx.createOscillator();
        const gain = this.ctx.createGain();
        const start = t + i * 0.06;
        osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, start);
        gain.gain.setValueAtTime(0, start);
        gain.gain.linearRampToValueAtTime(0.12, start + 0.02);
        gain.gain.exponentialRampToValueAtTime(0.001, start + 0.4);
        osc.connect(gain);
        gain.connect(this.masterGain);
        osc.start(start);
        osc.stop(start + 0.5);
    });
  }

  playUIHover() {
    this.resume();
    if (this.volume <= 0.001) return;
    if (!this.throttle('ui-hover', 50)) return;

    const t = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(1200, t);
    osc.frequency.exponentialRampToValueAtTime(1600, t + 0.04);
    gain.gain.setValueAtTime(0.015, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.04);
    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start(t);
    osc.stop(t + 0.05);
  }

  playUIClick() {
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(440, t);
    osc.frequency.exponentialRampToValueAtTime(110, t + 0.06);
    gain.gain.setValueAtTime(0.18, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.06);
    osc.connect(gain);
    gain.connect(this.masterGain);
    osc.start(t);
    osc.stop(t + 0.07);
  }

  playStatUpgrade() {
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    [1046.50, 1318.51].forEach((f, i) => {
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        const s = t + i * 0.04;
        o.type = 'sine';
        o.frequency.setValueAtTime(f, s);
        g.gain.setValueAtTime(0, s);
        g.gain.linearRampToValueAtTime(0.1, s + 0.01);
        g.gain.exponentialRampToValueAtTime(0.001, s + 0.15);
        o.connect(g);
        g.connect(this.masterGain);
        o.start(s);
        o.stop(s + 0.2);
    });
  }

  playClassUpgrade() {
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const notes = [523.25, 659.25, 783.99]; 
    notes.forEach((f) => {
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        o.type = 'triangle';
        o.frequency.setValueAtTime(f, t);
        g.gain.setValueAtTime(0, t);
        g.gain.linearRampToValueAtTime(0.12, t + 0.03);
        g.gain.exponentialRampToValueAtTime(0.001, t + 0.5);
        o.detune.value = (Math.random() - 0.5) * 15;
        o.connect(g);
        g.connect(this.masterGain);
        o.start(t);
        o.stop(t + 0.6);
    });
  }

  private createNoiseBuffer() {
    const bufferSize = this.ctx.sampleRate * 2.0;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
        data[i] = Math.random() * 2 - 1;
    }
    return buffer;
  }
}

