                        <span className="text-[10px] font-black text-green-400 font-mono tracking-widest uppercase italic">Latency_Stable</span>
                    </div>
                    <div className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse shadow-[0_0_10px_#4ade80]"></div>
                </div>

                {/* REMASTERED ALMANAC ICON - BOOK SVG */}
                <button onClick={() => { playClick(); setShowAlmanac(true); }} className="p-3.5 rounded-2xl bg-white/5 border border-white/10 text-white/20 hover:text-indigo-400 hover:border-indigo-500/30 transition-all hover:scale-105 active:scale-95 shadow-lg group">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M12 6.042A8.967 8.967 0 0 0 6 3.75c-1.052 0-2.062.18-3 .512v14.25A8.987 8.987 0 0 1 6 18c2.305 0 4.408.867 6 2.292m0-14.25a8.966 8.966 0 0 1 6-2.292c1.052 0 2.062.18 3 .512v14.25A8.987 8.987 0 0 0 18 18c-2.305 0-4.408.867-6 2.292m0-14.25v14.25" />
                    </svg>
                </button>

                {/* REMASTERED SETTINGS ICON - IMPROVED GEAR SVG */}
                <button onClick={() => { playClick(); setShowSettings(true); }} className="p-3.5 rounded-2xl bg-white/5 border border-white/10 text-white/20 hover:text-cyan-400 hover:border-cyan-500/30 transition-all hover:scale-105 active:scale-95 shadow-lg group">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 0 0 2.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 0 0 1.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 0 0-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 0 0-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 0 0-2.573-1.066-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 0 0-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 0 0 1.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
                        <path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 1 1-6 0 3 3 0 0 1 6 0z" />
                    </svg>
                </button>
            </div>
        </div>

        {/* Center Section */}
        <div className="flex-1 w-full max-w-[1400px] grid grid-cols-1 lg:grid-cols-5 gap-16 items-center overflow-hidden">

            {/* Left Sidebar */}
            <div className="hidden lg:flex flex-col gap-6 animate-in slide-in-from-left-8 duration-1000 delay-200">
                <div className="flex items-center gap-3 px-2">
                    <span className="text-[10px] font-black text-cyan-500 uppercase tracking-[0.4em] italic">Intel_Feed</span>
                    <div className="h-px flex-1 bg-white/10"></div>
