                    </h1>
                    <div className="flex items-center justify-center gap-4 mt-1 opacity-40">
                        <div className="h-px w-16 bg-white/50"></div>
                        <span className="text-xl font-black italic tracking-[0.6em] text-white uppercase">REMIX</span>
                        <div className="h-px w-16 bg-white/50"></div>
                    </div>
                </div>

                {/* Tactical Panel */}
                <div className="w-full max-w-[480px] p-8 md:p-10 rounded-[3rem] bg-black/40 border border-white/10 backdrop-blur-3xl panel-breathe relative animate-in slide-in-from-bottom-12 duration-1000 delay-300 shadow-2xl" style={{ transform: `translate(${parallax.x * 10}px, ${parallax.y * 10}px)` }}>

                    {/* Mode Selector */}
                    <div className="w-full mb-10 flex p-1.5 rounded-2xl bg-black/60 border border-white/5">
