                                <TankPreview tankClass={TankClass.BASIC} color={tankColor} size={110} />
                            </div>
                            <div className="absolute -bottom-6 text-[9px] font-black text-white/20 uppercase tracking-[0.5em] whitespace-nowrap">Chassis_Integrity_Optimum</div>
                        </div>

                        {/* ENGAGE BUTTON - Balanced Size */}
                        <button 
                            type="submit" 
                            className="group btn-charge relative w-full h-[76px] px-8 rounded-2xl bg-gradient-to-b from-cyan-400 to-blue-700 overflow-hidden transition-all duration-500 hover:scale-[1.02] active:scale-98 shadow-[0_15px_50px_-10px_rgba(0,178,225,0.5)] border-b-[8px] border-blue-900 active:border-b-0 active:translate-y-2 flex items-center justify-center"
                        >
                            <span className="relative z-10 text-3xl font-black text-white italic tracking-[0.3em] drop-shadow-lg uppercase whitespace-nowrap">
