                            </span>
                        </button>
                    </form>
                </div>
            </div>

            {/* Right Sidebar */}
            <div className="hidden lg:flex flex-col gap-6 animate-in slide-in-from-right-8 duration-1000 delay-200">
                <div className="flex items-center gap-3 px-2 justify-end">
                    <div className="h-px flex-1 bg-white/10"></div>
                    <span className="text-[10px] font-black text-orange-500 uppercase tracking-[0.4em] italic">Combat_Logs</span>
                </div>
                <div className="space-y-4">
                    <div className="p-8 rounded-[2rem] bg-white/[0.02] border border-white/5 backdrop-blur-md shadow-lg">
