        </div>

        {/* Modals */}
        {showLogin && <LoginModal onClose={() => setShowLogin(false)} onLoginSuccess={(u) => { setUser(u); setPlayerName(u.username); }} darkMode={settings.darkMode} />}
        {showShop && <ShopModal user={user} onClose={() => setShowShop(false)} onUpdateUser={setUser} darkMode={settings.darkMode} playSound={playClick} />}
        {showAlmanac && <AlmanacModal onClose={() => setShowAlmanac(false)} darkMode={settings.darkMode} playSound={playClick} />}

        {/* Settings Modal (Simplified Trigger) */}
        {showSettings && (
            <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/95 backdrop-blur-3xl animate-in fade-in duration-300 p-6" onClick={() => setShowSettings(false)}>
                <div className={`w-full max-w-lg p-12 rounded-[4rem] border-4 transition-all duration-500 ${settings.darkMode ? 'bg-[#050505] border-white/5 shadow-[0_0_100px_rgba(0,0,0,1)]' : 'bg-white border-black/5 shadow-2xl'}`} onClick={e => e.stopPropagation()}>
                    <h2 className="text-5xl font-black mb-12 text-center tracking-tighter italic uppercase text-white">System_Core</h2>
                    <div className="space-y-10">
                        <div className="flex items-center justify-between p-8 rounded-[2.5rem] bg-white/[0.02] border border-white/5 hover:border-cyan-500/30 transition-all">
                            <span className="font-black text-lg uppercase text-white tracking-[0.2em]">Dark_Protocol</span>
                            <button onClick={() => { playClick(); setSettings({...settings, darkMode: !settings.darkMode}); }} className={`w-20 h-10 rounded-full p-1.5 transition-all ${settings.darkMode ? 'bg-cyan-500 shadow-lg shadow-cyan-500/20' : 'bg-gray-800'}`}>
                                <div className={`w-7 h-7 rounded-full bg-white transition-all transform ${settings.darkMode ? 'translate-x-10' : ''}`} />
                            </button>
                        </div>
                        <div className="p-8 rounded-[2.5rem] bg-white/[0.02] border border-white/5">
                            <div className="flex justify-between items-center mb-6">
                                <span className="font-black text-lg uppercase text-white tracking-[0.2em]">Audio_Gain</span>
                                <span className="text-3xl font-black text-cyan-400 font-mono">{Math.round(settings.volume * 100)}%</span>
                            </div>
                            <input 
                                type="range" min="0" max="1" step="0.01" 
                                value={settings.volume} 
                                onChange={(e) => setSettings({...settings, volume: parseFloat(e.target.value)})} 
                                className="w-full h-3 bg-black/60 rounded-full accent-cyan-500 cursor-pointer" 
                            />
                        </div>
                    </div>
                    <button onClick={() => setShowSettings(false)} className="w-full mt-12 py-8 bg-gradient-to-r from-cyan-600 to-blue-800 text-white font-black rounded-[2.5rem] shadow-2xl hover:scale-[1.02] active:scale-95 transition-all uppercase tracking-[0.5em] text-sm border-b-8 border-blue-950">Confirm_Changes</button>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

