        this.name = `Elite ${cls}`;
        this.level = 45; 
        this.maxHealth = 100000;
        this.health = 100000;
        this.displayHealth = 100000;
        this.color = '#1a1a1a';
        this.damage = 60;
        this.mass = 500;
        this.patrolPos = { x, y };
        this.visionRange = 1200;
        this.barrels = TANK_CONFIGS[cls];
        this.barrelCooldowns = new Array(this.barrels.length).fill(0);
