                                <button onClick={() => engine.resetAllStats()} className="flex items-center justify-between px-6 py-5 rounded-2xl bg-white/5 hover:bg-white/10 border border-white/10 text-white/60 transition-all group">
                                    <span className="text-[11px] font-black uppercase tracking-widest italic">FLUSH_CONFIGURATION</span>
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 opacity-40 group-hover:opacity-100" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                                </button>
                                <button onClick={() => engine.clearEntities()} className="flex items-center justify-between px-6 py-5 mt-4 rounded-2xl bg-red-500/10 hover:bg-red-500/20 border border-red-500/20 text-red-500 transition-all group">
                                    <span className="text-[11px] font-black uppercase tracking-widest italic">PURGE_WORLD_STATE</span>
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                </button>
                            </div>
                        </div>
                    </div>
                  )}
                  {activeTab === 'RESEARCH' && (
                    <div className="space-y-12 pb-8">
                        <div className="bg-indigo-500/10 border-l-4 border-indigo-500 p-6 rounded-r-2xl mb-8">
                            <h4 className="text-xs font-black text-indigo-400 uppercase mb-1">Archetype Bypass</h4>
                            <p className="text-[10px] text-indigo-300/70 font-bold leading-relaxed tracking-wide uppercase">Select any high-tier chassis to execute an immediate hardware hot-swap. Experimental builds included.</p>
                        </div>
                        {CLASS_CATEGORIES.map(cat => (
                            <div key={cat.name} className="space-y-6">
                                <div className="flex items-center gap-4">
                                    <span className="text-xs font-black text-white/30 uppercase tracking-[0.5em] italic">{cat.name} Sector</span>
                                    <div className="h-px flex-1 bg-white/10"></div>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    {cat.classes.map(cls => (
                                        <button 
                                            key={cls} 
                                            onClick={() => { playHover?.(); onUpgradeClass(cls); }} 
                                            className={`group relative flex flex-col gap-6 p-6 rounded-[2.5rem] border-2 transition-all overflow-hidden ${currentClass === cls ? 'bg-indigo-600 border-indigo-400 shadow-2xl shadow-indigo-600/30' : 'bg-white/5 border-white/5 hover:border-indigo-500/30 hover:bg-white/8'}`}
                                        >
                                            <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none transform translate-x-4 -translate-y-4">
                                                <TankPreview tankClass={cls} size={120} />
                                            </div>
                                            <div className="shrink-0 transform group-hover:scale-110 transition-transform duration-500 relative z-10 w-fit">
                                                <div className="p-4 rounded-3xl bg-black/40 border border-white/10">
                                                    <TankPreview tankClass={cls} size={56} color={currentClass === cls ? '#fff' : undefined} />
                                                </div>
                                            </div>
                                            <div className="relative z-10 flex flex-col">
                                                <div className="flex items-center gap-2 mb-1">
                                                    <div className={`w-1.5 h-1.5 rounded-full ${currentClass === cls ? 'bg-white animate-pulse' : 'bg-indigo-500'}`}></div>
                                                    <span className={`text-[11px] font-black uppercase italic tracking-tighter ${currentClass === cls ? 'text-white' : 'text-white/80'}`}>{cls.replace(' Tank', '')}</span>
                                                </div>
                                                <span className={`text-[8px] font-black uppercase tracking-widest ${currentClass === cls ? 'text-white/60' : 'text-white/20'}`}>Ref_ID: {cls.toUpperCase().replace(/\s/g, '_')}</span>
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                  )}
                  {activeTab === 'SPAWN' && (
                    <div className="space-y-10">
