                            <div className="flex flex-col">
                                <span className="text-[12px] font-black text-white uppercase tracking-widest">Fabrication_System</span>
                                <span className={`text-[10px] font-black uppercase tracking-widest mt-1 ${sandboxConfig?.spawningEnabled ? 'text-green-500' : 'text-red-500/60'}`}>{sandboxConfig?.spawningEnabled ? 'ONLINE_READY' : 'OFFLINE_LOCKED'}</span>
                            </div>
                            <button onClick={() => engine.setSandboxFlag('spawningEnabled', !sandboxConfig?.spawningEnabled)} className={`w-20 h-10 rounded-full p-1.5 transition-all ${sandboxConfig?.spawningEnabled ? 'bg-green-500 shadow-[0_0_25px_rgba(34,197,94,0.4)]' : 'bg-white/10'}`}><div className={`w-7 h-7 rounded-full bg-white transition-all transform shadow-md ${sandboxConfig?.spawningEnabled ? 'translate-x-10' : 'translate-x-0'}`} /></button>
                        </div>

                        <div className={`transition-all duration-500 space-y-10 ${sandboxConfig?.spawningEnabled ? 'opacity-100' : 'opacity-30 pointer-events-none filter grayscale blur-[2px]'}`}>
                            <div className="space-y-4">
                                <span className="text-[10px] font-black text-cyan-400 uppercase tracking-[0.4em] px-2">Integrity_Rarity</span>
                                <div className="grid grid-cols-3 gap-2 bg-black/40 p-2 rounded-[1.5rem] border border-white/5">
                                    {[ShapeRarity.COMMON, ShapeRarity.RARE, ShapeRarity.EPIC, ShapeRarity.LEGENDARY, ShapeRarity.MYTHICAL, ShapeRarity.TRANSCENDENT].map(r => (
                                        <button key={r} onClick={() => { playHover?.(); setSelectedRarity(r); }} className={`py-3 rounded-xl text-[9px] font-black uppercase transition-all border-2 ${selectedRarity === r ? 'bg-cyan-500 border-cyan-400 text-black shadow-lg' : 'bg-transparent border-transparent text-white/20 hover:text-white/50'}`}>{r}</button>
                                    ))}
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <button onClick={() => handlePrimeSpawn({ type: 'BOSS', rarity: selectedRarity })} className={`p-8 rounded-[2.5rem] border-2 flex flex-col items-center gap-4 transition-all group ${primedSpawn?.type === 'BOSS' ? 'bg-red-500/20 border-red-500 shadow-2xl' : 'bg-white/5 border-white/5 hover:bg-white/10'}`}>
                                    <div className="shrink-0 flex items-center justify-center transform group-hover:scale-110 group-active:scale-95 transition-transform duration-300">
                                        <ShapePreview type="GRAND_SINGULARITY" rarity={ShapeRarity.COMMON} size={84} />
                                    </div>
                                    <span className="text-[11px] font-black text-white italic uppercase tracking-widest">GRAND_SINGULARITY</span>
                                </button>
                                <button onClick={() => handlePrimeSpawn({ type: 'ALPHA_PENTAGON', rarity: selectedRarity })} className={`p-8 rounded-[2.5rem] border-2 flex flex-col items-center gap-4 transition-all group ${primedSpawn?.type === 'ALPHA_PENTAGON' ? 'bg-blue-500/20 border-blue-500 shadow-2xl' : 'bg-white/5 border-white/5 hover:bg-white/10'}`}>
                                    <div className="shrink-0 flex items-center justify-center transform group-hover:scale-110 group-active:scale-95 transition-transform duration-300">
                                        <ShapePreview type="ALPHA_PENTAGON" rarity={ShapeRarity.COMMON} size={84} />
                                    </div>
                                    <span className="text-[11px] font-black text-white italic uppercase tracking-widest">ALPHA_PENTAGON</span>
                                </button>
                            </div>

                            <div className="space-y-4">
                                <span className="text-[10px] font-black text-white/20 uppercase tracking-[0.4em] px-2 italic">Standard_Materials</span>
                                <div className="grid grid-cols-3 gap-3">
                                    {Object.values(ShapeType).map(t => (
                                        <button key={t} onClick={() => handlePrimeSpawn({ type: 'SHAPE', shapeType: t, rarity: selectedRarity })} className={`py-10 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-5 group ${primedSpawn?.shapeType === t ? 'bg-cyan-500/20 border-cyan-400 shadow-2xl' : 'bg-white/5 border-white/5 hover:bg-white/8 hover:border-white/20'}`}>
                                            <div className="shrink-0 flex items-center justify-center transform group-hover:scale-110 transition-transform duration-500">
                                                <ShapePreview type={t} rarity={selectedRarity} size={54} />
                                            </div>
                                            <span className="text-[10px] font-black text-white/30 group-hover:text-white uppercase tracking-widest">{t}</span>
                                        </button>
                                    ))}
                                    <button onClick={() => handlePrimeSpawn({ type: 'DUMMY', rarity: ShapeRarity.COMMON })} className={`py-10 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-5 group ${primedSpawn?.type === 'DUMMY' ? 'bg-yellow-500/20 border-yellow-400 shadow-2xl' : 'bg-white/5 border-white/5 hover:bg-white/8 hover:border-white/20'}`}>
                                        <div className="shrink-0 flex items-center justify-center transform group-hover:scale-110 transition-transform duration-500">
                                            <ShapePreview type="DUMMY" rarity={ShapeRarity.COMMON} size={54} />
                                        </div>
                                        <span className="text-[10px] font-black text-white/30 group-hover:text-white uppercase tracking-widest italic">TARGET_DUMMY</span>
