                        </div>
                    </div>
                  )}
              </div>

              <div className="px-10 py-6 bg-cyan-400/[0.02] border-t border-white/5 shrink-0">
                 <div className="flex justify-between items-center opacity-40">
                    <span className="text-[8px] font-black text-cyan-500 uppercase tracking-[0.5em]">Terminal_Active // Build_09.25</span>
                    <span className="text-[8px] font-black text-white uppercase tracking-widest font-mono">0x2F_SECURE</span>
                 </div>
              </div>
          </div>
      )}

      {/* Bottom Interface */}
      <div className="w-full flex justify-between items-end mt-auto relative gap-8 z-[90]">

        {/* Stat Menu */}
        <div className={`
          absolute bottom-2 left-0 w-80 mb-2 pointer-events-auto transition-all duration-500 ease-[cubic-bezier(0.23,1,0.32,1)]
          ${showStatsMenu ? 'translate-x-0 opacity-100' : '-translate-x-full opacity-0'}
        `}>
           <div className={`bg-[#0a0a0a]/95 backdrop-blur-2xl p-5 rounded-r-[2rem] border-y-2 border-r-2 border-white/10 shadow-[20px_0_50px_rgba(0,0,0,0.5)] relative overflow-hidden`}>
               <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-cyan-500 via-blue-500 to-indigo-500"></div>

               <div className="flex items-center justify-between mb-5 pb-3 border-b border-white/5 px-2">
                    <div className="flex flex-col">
                      <span className="text-white font-black text-[11px] uppercase tracking-[0.2em] italic">Tactical_Upgrade</span>
                      <span className="text-[8px] font-bold text-cyan-400/60 uppercase tracking-widest mt-0.5">System_Integration_Active</span>
                    </div>
                    {availableStatPoints > 0 && (
                      <div className="flex items-center gap-2">
                        <span className="text-[9px] font-black text-white/40 uppercase tracking-widest">Points</span>
                        <div className="bg-cyan-500 text-black font-black text-[12px] px-2 py-0.5 rounded-md shadow-[0_0_15px_rgba(34,211,238,0.4)] animate-pulse">
                          x{availableStatPoints}
                        </div>
                      </div>
                    )}
               </div>

               <div className="space-y-1.5 px-1">
               {STAT_ORDER.map((stat, idx) => {
                 const currentVal = stats[stat];
                 const isMaxed = currentVal >= 8;
                 const canUpgrade = availableStatPoints > 0 && !isMaxed;
                 const hotkey = idx + 1 === 10 ? '0' : (idx + 1).toString();

                 // DYNAMIC STAT LABEL LOGIC
                 let displayLabel: string = stat;
                 if (isDroneClass) {
                   if (stat === StatType.BULLET_PENETRATION) displayLabel = "Drone Health";
                   if (stat === StatType.BULLET_DAMAGE) displayLabel = "Drone Damage";
                 }

                 return (
                   <div 
                    key={stat} 
                    className={`
                      group flex items-center gap-3 rounded-xl p-2 transition-all duration-300 border-2
                      ${canUpgrade 
                        ? 'bg-white/5 border-transparent hover:border-cyan-500/40 hover:bg-white/10 cursor-pointer scale-100 hover:scale-[1.03] active:scale-95' 
                        : 'bg-transparent border-transparent opacity-40'}
                      ${isMaxed ? 'border-yellow-500/20 bg-yellow-500/5' : ''}
                    `} 
                    onClick={() => canUpgrade && onUpgradeStat(stat)}
                    onMouseEnter={() => canUpgrade && playHover?.()}
                   >
                     <div className={`
                        w-6 h-6 rounded-lg flex items-center justify-center text-[10px] font-black font-mono shadow-inner border transition-all
                        ${canUpgrade 
                          ? 'bg-black/60 text-cyan-400 border-white/10 group-hover:border-cyan-400 group-hover:bg-cyan-400 group-hover:text-black' 
                          : 'bg-black/20 text-white/20 border-white/5'}
                     `}>
                       {hotkey}
                     </div>

                     <div className="flex flex-col flex-1">
                        <div className="flex justify-between items-end mb-1">
                          <span className={`text-[9px] font-black uppercase tracking-wider truncate leading-none ${canUpgrade ? 'text-white' : 'text-gray-500'}`}>
                            {displayLabel}
                          </span>
                          <span className={`text-[8px] font-mono ${isMaxed ? 'text-yellow-500' : 'text-gray-600'}`}>
                            {currentVal}/8
                          </span>
                        </div>
                        <div className="w-full h-2.5 flex gap-[1.5px] bg-black/60 rounded-full p-[1.5px] border border-white/5 overflow-hidden">
                          {[...Array(8)].map((_, i) => {
                            const active = i < currentVal;
                            return (
                              <div 
                                key={i} 
                                className={`flex-1 rounded-full transition-all duration-500 ${active ? 'opacity-100' : 'opacity-10'}`} 
                                style={{ 
                                  backgroundColor: active ? STAT_COLORS[stat] : 'rgba(255,255,255,0.1)', 
                                  boxShadow: active ? `0 0 8px ${STAT_COLORS[stat]}` : 'none' 
                                }} 
                              />
                            );
                          })}
                        </div>
                     </div>
                   </div>
                 );
               })}
               </div>

               <div className="mt-4 pt-3 border-t border-white/5 text-center">
                  <span className="text-[7px] font-black text-white/20 uppercase tracking-[0.5em]">Quick_Integrate // {level > 60 ? 'CAP_ENGAGED' : 'POINTS_ACTIVE'}</span>
               </div>
           </div>
        </div>

        {/* Center HUD */}
        <div className="absolute bottom-2 left-1/2 -translate-x-1/2 w-[40%] max-w-2xl flex flex-col items-center pointer-events-auto">
            <div className="mb-2 text-center">
               <div className="text-4xl font-black text-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] tracking-tighter leading-none">{score.toLocaleString()}</div>
               <div className="text-[10px] font-black text-white/60 uppercase tracking-[0.2em] mt-2">Lvl {level} {currentClass}</div>
            </div>
           <div className="w-full h-4 mb-1.5 bg-black/60 rounded-full border border-gray-600/50 relative shadow-lg overflow-hidden group">
               <div className={`h-full transition-all duration-200 ease-out relative ${isTransformed ? 'bg-red-500' : 'bg-[#00e16e]'}`} style={{ width: `${Math.max(0, (health / maxHealth) * 100)}%` }} />
               <div className="absolute inset-0 flex items-center justify-center text-[9px] font-black text-white drop-shadow-[0_1px_2px_rgba(0,0,0,0.8)] z-10 tracking-wider">{Math.ceil(health)} / {Math.ceil(maxHealth)}</div>
           </div>
           <div className="w-full h-4 bg-black/60 rounded-full border border-gray-600/50 relative shadow-xl overflow-hidden group">
              <div className="h-full bg-gradient-to-r from-yellow-400 to-orange-400 transition-all duration-700 ease-out relative" style={{ width: `${xpPercent}%` }}></div>
              <div className="absolute inset-0 flex items-center justify-center text-[9px] font-black text-white drop-shadow-[0_1px_2px_rgba(0,0,0,0.8)] z-10 tracking-wider"><span>{Math.floor(xpPercent)}%</span></div>
           </div>
        </div>
      </div>
    </div>
  );
};

