import { TankClass } from '../types';

export class SoundEngine {
  ctx: AudioContext;
  masterGain: GainNode;
  noiseBuffer: AudioBuffer | null = null;
  volume: number = 0.15;

  private lastPlayed: Record<string, number> = {};

  constructor() {
    // @ts-ignore
    const AudioContextClass = window.AudioContext || window.webkitAudioContext;
    this.ctx = new AudioContextClass();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = this.volume;

    const limiter = this.ctx.createDynamicsCompressor();
    limiter.threshold.setValueAtTime(-1, this.ctx.currentTime);
    limiter.knee.setValueAtTime(40, this.ctx.currentTime);
    limiter.ratio.setValueAtTime(12, this.ctx.currentTime);
    limiter.attack.setValueAtTime(0, this.ctx.currentTime);
    limiter.release.setValueAtTime(0.25, this.ctx.currentTime);

    this.masterGain.connect(limiter);
    limiter.connect(this.ctx.destination);

    this.noiseBuffer = this.createNoiseBuffer();
  }

  private throttle(key: string, cooldownMs: number): boolean {
    const now = Date.now();
    if (this.lastPlayed[key] && now - this.lastPlayed[key] < cooldownMs) {
      return false;
    }
    this.lastPlayed[key] = now;
    return true;
  }

  async resume() {
    if (this.ctx.state === 'suspended') {
      await this.ctx.resume();
    }
  }

  setVolume(value: number) {
    this.volume = Math.max(0, Math.min(1, value));
    if (this.masterGain) {
      this.masterGain.gain.setTargetAtTime(this.volume, this.ctx.currentTime, 0.05);
    }
  }

  private jitter(center = 1, amount = 0.1) {
    return center * (1 - amount + Math.random() * amount * 2);
  }

  private createPannedGain(panRange = 0.4): { gain: GainNode; panNode: StereoPannerNode } {
    const gain = this.ctx.createGain();
    const panNode = this.ctx.createStereoPanner();
    panNode.pan.value = (Math.random() - 0.5) * panRange;
    gain.connect(panNode);
    panNode.connect(this.masterGain);
    return { gain, panNode };
  }

  playRoar() {
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;

    // Sub Bass Layer
    const sub = this.ctx.createOscillator();
    const { gain: subG } = this.createPannedGain(0.1);
    sub.type = 'sine';
    sub.frequency.setValueAtTime(80, t);
    sub.frequency.exponentialRampToValueAtTime(30, t + 0.8);
    subG.gain.setValueAtTime(0, t);
    subG.gain.linearRampToValueAtTime(0.8, t + 0.05);
    subG.gain.exponentialRampToValueAtTime(0.001, t + 1.2);
    sub.connect(subG);
    sub.start(t);
    sub.stop(t + 1.3);

    // Growl Layer
    const growl = this.ctx.createOscillator();
    const { gain: growlG } = this.createPannedGain(0.2);
    growl.type = 'sawtooth';
    growl.frequency.setValueAtTime(140, t);
    growl.frequency.linearRampToValueAtTime(60, t + 0.5);
    growlG.gain.setValueAtTime(0, t);
    growlG.gain.linearRampToValueAtTime(0.4, t + 0.1);
    growlG.gain.exponentialRampToValueAtTime(0.001, t + 0.8);
    growl.connect(growlG);
    growl.start(t);
    growl.stop(t + 0.9);
  }

  playShoot(type: TankClass = TankClass.BASIC) {
    this.resume();
    if (this.volume <= 0.001) return;
    const minCooldown = (type === TankClass.STREAMLINER || type === TankClass.GUNNER) ? 20 : 35;
    if (!this.throttle(`shoot-${type}`, minCooldown)) return;
    const t = this.ctx.currentTime;
    const pitchVariance = 0.85 + Math.random() * 0.3;
    let baseFreq = 220;
    let sweepDepth = 0.2;
    let duration = 0.15;
    let amplitude = 0.35;
    let waveType: OscillatorType = 'triangle';
    let attackTime = 0.005;
    let noiseIntensity = 0.5;
    let noiseDecay = 0.05;
    let addSub = false;

    switch (type) {
      case TankClass.SNIPER:
      case TankClass.ASSASSIN:
      case TankClass.RANGER:
      case TankClass.STALKER:
        baseFreq = 580; sweepDepth = 0.05; duration = 0.4; amplitude = 0.5; waveType = 'sawtooth';
        noiseIntensity = 0.8; noiseDecay = 0.1;
        break;
      case TankClass.MACHINE_GUN:
      case TankClass.SPRAYER:
        baseFreq = 160; sweepDepth = 0.4; duration = 0.1; amplitude = 0.25; waveType = 'square';
        noiseIntensity = 0.4; noiseDecay = 0.03;
        break;
      case TankClass.STREAMLINER:
      case TankClass.GUNNER:
      case TankClass.AUTO_GUNNER:
        baseFreq = 340; sweepDepth = 0.6; duration = 0.06; amplitude = 0.18; waveType = 'triangle';
        noiseIntensity = 0.2; noiseDecay = 0.02;
        break;
      case TankClass.DESTROYER:
      case TankClass.HYBRID:
      case TankClass.ANNIHILATOR:
        baseFreq = 90; sweepDepth = 0.1; duration = 0.6; amplitude = 0.7; waveType = 'sine';
        attackTime = 0.015; noiseIntensity = 1.2; noiseDecay = 0.4;
        addSub = true;
        break;
      case TankClass.HUNTER:
      case TankClass.X_HUNTER:
        baseFreq = 420; sweepDepth = 0.3; duration = 0.25; amplitude = 0.4; waveType = 'sawtooth';
        noiseIntensity = 0.6; noiseDecay = 0.08;
        break;
      default:
        baseFreq = 240; sweepDepth = 0.2; duration = 0.15; amplitude = 0.35; waveType = 'triangle';
        break;
    }

    const finalBaseFreq = baseFreq * pitchVariance;
    const ampRand = amplitude * this.jitter(1, 0.12);
    const attackRand = attackTime * this.jitter(1, 0.15);
    const durationRand = duration * this.jitter(1, 0.1);
    const noiseDecayRand = noiseDecay * this.jitter(1, 0.15);

    {
      const transOsc = this.ctx.createOscillator();
      const { gain: transGain } = this.createPannedGain(0.25);
      transOsc.type = 'square';
      transOsc.frequency.setValueAtTime(finalBaseFreq * 2, t);
      transGain.gain.setValueAtTime(0, t);
      transGain.gain.linearRampToValueAtTime(ampRand * 0.5, t + 0.002);
      transGain.gain.linearRampToValueAtTime(0, t + 0.01);
      transOsc.connect(transGain);
      transOsc.start(t);
      transOsc.stop(t + 0.02);
    }
    {
      const bodyOsc = this.ctx.createOscillator();
      const { gain: bodyGain } = this.createPannedGain(0.35);
      bodyOsc.type = waveType;
      bodyOsc.frequency.setValueAtTime(finalBaseFreq, t);
      bodyOsc.frequency.exponentialRampToValueAtTime(Math.max(10, finalBaseFreq * sweepDepth), t + durationRand);
      bodyGain.gain.setValueAtTime(0, t);
      bodyGain.gain.linearRampToValueAtTime(ampRand, t + attackRand);
      bodyGain.gain.exponentialRampToValueAtTime(0.001, t + durationRand);
      bodyOsc.connect(bodyGain);
      bodyOsc.start(t);
      bodyOsc.stop(t + durationRand + 0.1);
    }
    if (this.noiseBuffer) {
      const noiseSrcHigh = this.ctx.createBufferSource();
      noiseSrcHigh.buffer = this.noiseBuffer;
      const { gain: noiseGainHigh } = this.createPannedGain(0.3);
      const noiseFilterHigh = this.ctx.createBiquadFilter();
      noiseFilterHigh.type = 'bandpass';
      noiseFilterHigh.frequency.setValueAtTime(finalBaseFreq * 4, t);
      noiseFilterHigh.Q.value = 1.2;
      noiseGainHigh.gain.setValueAtTime(0, t);
      noiseGainHigh.gain.linearRampToValueAtTime(ampRand * noiseIntensity, t + 0.005);
      noiseGainHigh.gain.exponentialRampToValueAtTime(0.001, t + noiseDecayRand);
      noiseSrcHigh.connect(noiseFilterHigh);
      noiseFilterHigh.connect(noiseGainHigh);
      noiseSrcHigh.start(t);
      noiseSrcHigh.stop(t + noiseDecayRand + 0.1);

      const noiseSrcLow = this.ctx.createBufferSource();
      noiseSrcLow.buffer = this.noiseBuffer;
      const { gain: noiseGainLow } = this.createPannedGain(0.2);
      const noiseFilterLow = this.ctx.createBiquadFilter();
      noiseFilterLow.type = 'lowpass';
      noiseFilterLow.frequency.setValueAtTime(220, t);
      noiseGainLow.gain.setValueAtTime(0, t);
      noiseGainLow.gain.linearRampToValueAtTime(ampRand * noiseIntensity * 0.6, t + 0.01);
      noiseGainLow.gain.exponentialRampToValueAtTime(0.001, t + noiseDecayRand * 1.4);
      noiseSrcLow.connect(noiseFilterLow);
      noiseFilterLow.connect(noiseGainLow);
      noiseSrcLow.start(t);
      noiseSrcLow.stop(t + noiseDecayRand * 1.4 + 0.1);
    }
    if (addSub) {
      const sub = this.ctx.createOscillator();
      const { gain: subG } = this.createPannedGain(0.1);
      sub.type = 'sine';
      sub.frequency.setValueAtTime(35, t);
      subG.gain.setValueAtTime(0.4 * ampRand, t);
      subG.gain.exponentialRampToValueAtTime(0.001, t + 0.09);
      sub.connect(subG);
      sub.start(t);
      sub.stop(t + 0.12);
    }
  }

  playHit() {
    this.resume();
    if (this.volume <= 0.001) return;
    if (!this.throttle('hit', 60)) return;
    const t = this.ctx.currentTime;
    const pitch = 0.8 + Math.random() * 0.4;
    const osc = this.ctx.createOscillator();
    const { gain } = this.createPannedGain(0.3);
    osc.type = 'square';
    osc.frequency.setValueAtTime(180 * pitch, t);
    osc.frequency.linearRampToValueAtTime(40, t + 0.05);
    const peak = 0.15 * this.jitter(1, 0.15);
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(peak, t + 0.002);
    gain.gain.linearRampToValueAtTime(0, t + 0.05);
    osc.connect(gain);
    osc.start(t);
    osc.stop(t + 0.07);
  }

  playExplosion(isLarge: boolean = false) {
    this.resume();
    if (this.volume <= 0.001) return;
    if (!this.noiseBuffer) return;
    if (!this.throttle(isLarge ? 'explosion-large' : 'explosion-small', 150)) return;
    const t = this.ctx.currentTime;
    const baseDuration = isLarge ? 0.85 : 0.4;
    const duration = baseDuration * this.jitter(1, 0.1);
    const vol = (isLarge ? 0.55 : 0.3) * this.jitter(1, 0.12);
    const src = this.ctx.createBufferSource();
    src.buffer = this.noiseBuffer;
    const lowpass = this.ctx.createBiquadFilter();
    lowpass.type = 'lowpass';
    lowpass.frequency.setValueAtTime(isLarge ? 350 : 900, t);
    lowpass.frequency.exponentialRampToValueAtTime(25, t + duration);
    const { gain } = this.createPannedGain(0.35);
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(vol, t + 0.015);
    gain.gain.exponentialRampToValueAtTime(0.001, t + duration);
    src.connect(lowpass);
    lowpass.connect(gain);
    src.start(t);
    src.stop(t + duration + 0.1);
    if (isLarge) {
      const shock = this.ctx.createBufferSource();
      shock.buffer = this.noiseBuffer;
      const { gain: shockG } = this.createPannedGain(0.25);
      const shockFilter = this.ctx.createBiquadFilter();
      shockFilter.type = 'bandpass';
      shockFilter.frequency.setValueAtTime(180, t + 0.12);
      shockFilter.Q.value = 0.7;
      shockG.gain.setValueAtTime(0, t + 0.12);
      shockG.gain.linearRampToValueAtTime(vol * 0.6, t + 0.16);
      shockG.gain.exponentialRampToValueAtTime(0.001, t + 0.6);
      shock.connect(shockFilter);
      shockFilter.connect(shockG);
      shock.start(t + 0.12);
      shock.stop(t + 0.65);
      const rumble = this.ctx.createOscillator();
      const { gain: rumbleG } = this.createPannedGain(0.15);
      rumble.type = 'sine';
      rumble.frequency.setValueAtTime(55, t);
      rumble.frequency.exponentialRampToValueAtTime(15, t + duration * 1.6);
      rumbleG.gain.setValueAtTime(0, t);
      rumbleG.gain.linearRampToValueAtTime(0.3, t + 0.06);
      rumbleG.gain.exponentialRampToValueAtTime(0.001, t + duration * 1.6);
      rumble.connect(rumbleG);
      rumble.start(t);
      rumble.stop(t + duration * 1.6);
    }
  }

  playLevelUp() {
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const notes = [523.25, 659.25, 783.99, 1046.50];
    notes.forEach((freq, i) => {
      const osc = this.ctx.createOscillator();
      const harm = this.ctx.createOscillator();
      const { gain } = this.createPannedGain(0.2);
      const start = t + i * 0.06;
      osc.type = 'sine';
      harm.type = 'sine';
      osc.frequency.setValueAtTime(freq, start);
      harm.frequency.setValueAtTime(freq * 1.5, start);
      const peak = 0.12 * this.jitter(1, 0.1);
      gain.gain.setValueAtTime(0, start);
      gain.gain.linearRampToValueAtTime(peak, start + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, start + 0.4);
      osc.connect(gain);
      harm.connect(gain);
      gain.connect(this.masterGain);
      osc.start(start);
      harm.start(start);
      osc.stop(start + 0.5);
      harm.stop(start + 0.5);
    });
  }

  playUIHover() {
    this.resume();
    if (this.volume <= 0.001) return;
    if (!this.throttle('ui-hover', 50)) return;
    const t = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const { gain } = this.createPannedGain(0.15);
    osc.type = 'sine';
    osc.frequency.setValueAtTime(1200, t);
    osc.frequency.exponentialRampToValueAtTime(1600, t + 0.04);
    gain.gain.setValueAtTime(0.015 * this.jitter(1, 0.15), t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.04);
    osc.connect(gain);
    osc.start(t);
    osc.stop(t + 0.05);
  }

  playUIClick() {
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const { gain } = this.createPannedGain(0.15);
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(440, t);
    osc.frequency.exponentialRampToValueAtTime(110, t + 0.06);
    const peak = 0.18 * this.jitter(1, 0.12);
    gain.gain.setValueAtTime(peak, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.06);
    osc.connect(gain);
    osc.start(t);
    osc.stop(t + 0.07);
  }

  playStatUpgrade() {
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    [1046.50, 1318.51].forEach((f, i) => {
      const o = this.ctx.createOscillator();
      const harm = this.ctx.createOscillator();
      const { gain } = this.createPannedGain(0.2);
      const s = t + i * 0.04;
      o.type = 'sine';
      harm.type = 'sine';
      o.frequency.setValueAtTime(f, s);
      harm.frequency.setValueAtTime(f * 1.5, s);
      const peak = 0.1 * this.jitter(1, 0.1);
      gain.gain.setValueAtTime(0, s);
      gain.gain.linearRampToValueAtTime(peak, s + 0.01);
      gain.gain.exponentialRampToValueAtTime(0.001, s + 0.15);
      o.connect(gain);
      harm.connect(gain);
      gain.connect(this.masterGain);
      o.start(s);
      harm.start(s);
      o.stop(s + 0.2);
      harm.stop(s + 0.2);
    });
  }

  playClassUpgrade() {
    this.resume();
    if (this.volume <= 0.001) return;
    const t = this.ctx.currentTime;
    const notes = [523.25, 659.25, 783.99];
    notes.forEach((f) => {
      const o = this.ctx.createOscillator();
      const harm = this.ctx.createOscillator();
      const { gain } = this.createPannedGain(0.25);
      o.type = 'triangle';
      harm.type = 'triangle';
      o.frequency.setValueAtTime(f, t);
      harm.frequency.setValueAtTime(f * 1.5, t);
      gain.gain.setValueAtTime(0, t);
      gain.gain.linearRampToValueAtTime(0.12 * this.jitter(1, 0.1), t + 0.03);
      gain.gain.exponentialRampToValueAtTime(0.001, t + 0.5);
      o.detune.value = (Math.random() - 0.5) * 15;
      harm.detune.value = (Math.random() - 0.5) * 10;
      o.connect(gain);
      harm.connect(gain);
      gain.connect(this.masterGain);
      o.start(t);
      harm.start(t);
      o.stop(t + 0.6);
      harm.stop(t + 0.6);
    });
  }

  private createNoiseBuffer() {
    const bufferSize = this.ctx.sampleRate * 2.0;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }
    return buffer;
  }
}

