class Boss extends Entity {
    damageDealtBy: Map<number, number> = new Map();
    phaseTimer: number = 0;
    xpValue: number = 500000;
    constructor(id: number) {
        super(id, EntityType.BOSS, CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2, 180, '#0055ff');
        this.maxHealth = 150000;
        this.health = this.maxHealth;
        this.displayHealth = this.maxHealth;
        this.damage = 150;
        this.mass = 15000;
        this.friction = 0.99;
        this.name = "GRAND SINGULARITY";
    }
    override takeDamage(amount: number, sourceId: number | null = null) {
        if (sourceId !== null && amount > 0) this.damageDealtBy.set(sourceId, (this.damageDealtBy.get(sourceId) || 0) + amount);
        super.takeDamage(amount, sourceId);
    }
    override update(dt: number) { 
        this.phaseTimer += dt;
        const hpRatio = this.health / this.maxHealth;
        this.rotation += (0.8 + (1 - hpRatio) * 1.2) * dt; 
        if (Date.now() - this.lastDamageTime > 10000) this.health = Math.min(this.health + 50 * dt * 60, this.maxHealth);
        super.update(dt); 
    }
    override drawBody(ctx: CanvasRenderingContext2D) {
        const t = Date.now() / 1000;
        const hpRatio = this.health / this.maxHealth;
        ctx.save();
        const auraSize = this.radius * (1.3 + Math.sin(t * 2) * 0.08);
        const grad = ctx.createRadialGradient(0, 0, this.radius * 0.8, 0, 0, auraSize);
        grad.addColorStop(0, 'rgba(0, 85, 255, 0.4)'); grad.addColorStop(1, 'rgba(0, 0, 0, 0)');
        ctx.fillStyle = grad; ctx.beginPath(); ctx.arc(0, 0, auraSize, 0, Math.PI * 2); ctx.fill();
        ctx.restore();
        for (let j = 0; j < 2; j++) {
            ctx.save(); ctx.rotate(j === 0 ? t * 0.5 : -t * 0.8);
            ctx.beginPath();
            for (let i = 0; i < 5; i++) {
                const angle = (i * 2 * Math.PI) / 5;
                const r = this.radius * (1.1 + j * 0.2);
                const x = Math.cos(angle) * r; const y = Math.sin(angle) * r;
                if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
            }
            ctx.closePath();
            ctx.lineWidth = 15; ctx.strokeStyle = j === 0 ? 'rgba(0, 178, 225, 0.6)' : 'rgba(118, 141, 252, 0.4)'; ctx.stroke();
            ctx.restore();
        }
        ctx.beginPath();
        for (let i = 0; i < 5; i++) {
            const angle = (i * 2 * Math.PI) / 5;
            const x = Math.cos(angle) * this.radius; const y = Math.sin(angle) * this.radius;
            if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
        }
        ctx.closePath();
        ctx.fillStyle = `rgb(${Math.floor((1 - hpRatio) * 150)}, ${Math.floor(hpRatio * 150)}, 255)`; ctx.fill();
        ctx.lineWidth = 15; ctx.strokeStyle = COLORS.border; ctx.stroke();
        ctx.beginPath(); ctx.arc(0, 0, this.radius * 0.3 * (1 + Math.sin(t * 10) * 0.1), 0, Math.PI * 2);
        ctx.fillStyle = '#fff'; ctx.shadowBlur = 40; ctx.shadowColor = '#0ff'; ctx.fill();
    }
}

class Shape extends Entity {
  shapeType: ShapeType;
  xpValue: number;
  driftVec: Vector2;
  rarity: ShapeRarity;
  damageDealtBy: Map<number, number> = new Map();
  pulseTimer: number = 0;
  constructor(id: number, x: number, y: number, type: ShapeType, isInVoid: boolean = false, forceRarity?: ShapeRarity) {
    const stats = SHAPE_STATS[type];
    const roll = Math.random();
    let rarity = forceRarity || ShapeRarity.COMMON;
    if (!forceRarity) {
        let accumulated = 0;
        const configSource = isInVoid ? VOID_RARITY_CONFIG : RARITY_CONFIG;
        for (const r of Object.values(ShapeRarity)) {
            accumulated += configSource[r].chance;
            if (roll < accumulated) { rarity = r; break; }
        }
    }
    const configSource = isInVoid ? VOID_RARITY_CONFIG : RARITY_CONFIG;
    const rarityConfig = configSource[rarity];
    super(id, EntityType.SHAPE, x, y, stats.radius * rarityConfig.sizeMult, rarityConfig.color || stats.color);
    this.friction = 0.95; this.shapeType = type; this.rarity = rarity;
    this.maxHealth = Math.floor(stats.health * rarityConfig.hpMult);
    this.health = this.maxHealth; this.displayHealth = this.maxHealth;
    this.xpValue = Math.floor(stats.xp * rarityConfig.xpMult);
    this.damage = stats.damage; this.mass = this.radius * 2.5;
    this.vel = { x: Vector.randomRange(-0.2, 0.2), y: Vector.randomRange(-0.2, 0.2) };
    this.driftVec = { x: Math.cos(Math.random()*Math.PI*2)*0.005, y: Math.sin(Math.random()*Math.PI*2)*0.005 };
  }
  override takeDamage(amount: number, sourceId: number | null = null) {
      if (sourceId !== null && amount > 0) this.damageDealtBy.set(sourceId, (this.damageDealtBy.get(sourceId) || 0) + amount);
      super.takeDamage(amount, sourceId);
  }
  override update(dt: number) {
    this.rotation += (this.shapeType === ShapeType.OCTAGON ? 0.008 : 0.015);
    this.acc.x += this.driftVec.x; this.acc.y += this.driftVec.y;
    this.pulseTimer += dt * 3; this.visualScale = 1.0 + Math.sin(this.pulseTimer) * 0.04;
    super.update(dt);
  }
  override drawBody(ctx: CanvasRenderingContext2D) {
    const sides = SHAPE_STATS[this.shapeType].sides;
    ctx.save();
    let fill = this.color; let stroke = COLORS.border; let gBlur = 0; let gCol = 'transparent';
    switch (this.rarity) {
        case ShapeRarity.UNCOMMON: stroke = '#4db8ff'; gCol = '#4db8ff'; gBlur = 12; break;
        case ShapeRarity.RARE: stroke = '#00ff80'; gCol = '#00ff80'; gBlur = 25; break;
        case ShapeRarity.EPIC: fill = '#ffd700'; stroke = '#ffaa00'; gCol = '#ffcc00'; gBlur = 40; break;
        case ShapeRarity.LEGENDARY: fill = '#ff5e00'; stroke = '#ff0000'; gCol = '#ff5e00'; gBlur = 55; break;
        case ShapeRarity.MYTHICAL: fill = '#1a002b'; stroke = '#a200ff'; gCol = '#a200ff'; gBlur = 70; break;
        case ShapeRarity.ETERNAL: fill = '#f0ffff'; stroke = '#00ffff'; gCol = '#00ffff'; gBlur = 95; break;
    }
    if (gBlur > 0) { ctx.shadowBlur = gBlur; ctx.shadowColor = gCol; }
    ctx.beginPath(); for(let i=0; i<sides; i++){const a=i*2*Math.PI/sides; ctx.lineTo(Math.cos(a)*this.radius, Math.sin(a)*this.radius);} ctx.closePath();
    ctx.fillStyle = fill; ctx.fill(); ctx.lineWidth = 3; ctx.strokeStyle = stroke; ctx.stroke();
    ctx.restore();
  }
}

class Bullet extends Entity {
  ownerId: number;
  lifeTime: number = 0;
  maxLifeTime: number = 3000;
  constructor(id: number, x: number, y: number, velocity: Vector2, owner: Tank, extraDamageMult: number = 1.0, extraLifeMult: number = 1.0, extraSizeMult: number = 1.0) {
    const size = (6 + (owner.stats[StatType.BULLET_DAMAGE] * 0.3)) * extraSizeMult;
    const color = (owner.team === Team.BLUE) ? COLORS.player : (owner.team === Team.RED) ? COLORS.enemy : COLORS.barrel;
    super(id, EntityType.BULLET, x, y, size, color);
    this.team = owner.team; this.friction = 1.0; this.vel = velocity;
    this.ownerId = owner.id; this.mass = size * 0.8; 
    let baseDamage = BASE_STATS.bulletDamage + (owner.stats[StatType.BULLET_DAMAGE] * 3);
    let basePenetration = BASE_STATS.bulletPenetration + (owner.stats[StatType.BULLET_PENETRATION] * 5);
    const isBuffed = owner.activeBuffs.some(b => b.type === 'SACRIFICIAL_GOAT');
    if (isBuffed) baseDamage *= 1.25;
    this.damage = baseDamage * extraDamageMult;
    this.maxHealth = (10 + basePenetration * 3) * extraLifeMult; 
    this.health = this.maxHealth; this.displayHealth = this.maxHealth;
  }
  override update(dt: number) { super.update(dt); this.lifeTime += dt * 1000; if (this.lifeTime > this.maxLifeTime) this.isDead = true; }
  override drawBody(ctx: CanvasRenderingContext2D) { let alpha = (this.maxLifeTime - this.lifeTime) < 300 ? Math.max(0, (this.maxLifeTime - this.lifeTime) / 300) : 1.0; ctx.globalAlpha = alpha; super.drawBody(ctx); ctx.globalAlpha = 1.0; }
}

class SpatialGrid {
    cellSize: number; cells: Map<string, Entity[]> = new Map();
    constructor(cellSize: number) { this.cellSize = cellSize; }
    clear() { this.cells.clear(); }
    add(entity: Entity) { const k = `${Math.floor(entity.pos.x/this.cellSize)},${Math.floor(entity.pos.y/this.cellSize)}`; if(!this.cells.has(k)) this.cells.set(k, []); this.cells.get(k)!.push(entity); }
    getNeighbors(entity: Entity): Entity[] {
        const cx = Math.floor(entity.pos.x / this.cellSize); const cy = Math.floor(entity.pos.y / this.cellSize);
        const neighbors: Entity[] = []; 
        for (let x = cx - 1; x <= cx + 1; x++) for (let y = cy - 1; y <= cy + 1; y++) { const k = `${x},${y}`; const c = this.cells.get(k); if(c) neighbors.push(...c); }
        return neighbors;
    }
}

export class GameEngine {
  canvas: HTMLCanvasElement; ctx: CanvasRenderingContext2D;
  entities: Entity[] = []; particles: Particle[] = [];
  floatingTexts: FloatingText[] = []; uiNotifications: UINotification[] = [];
  player: Tank;
  width: number; height: number;
  keys: Set<string> = new Set(); mouse: Vector2 = { x: 0, y: 0 };
  mouseDown: boolean = false; rightMouseDown: boolean = false;
  lastTime: number = 0; idCounter: number = 0;
  onStateUpdate: (state: GameState) => void;
  onGameOver: (score: number, level: number, classType: TankClass) => void;
  gameOverSignaled: boolean = false;
  sound: SoundEngine;
  darkMode: boolean = true; gameMode: GameMode = GameMode.FFA;
  preferredTeam: Team = Team.BLUE;
  xp: number = 0; level: number = 1;
  maxShapes = 1000; currentShapeCount = 0;
  killFeed: KillFeedEntry[] = [];
  attractMode: boolean = true;
  spectateTarget: Tank | null = null;
  cameraPos: Vector2 = { x: CANVAS_WIDTH/2, y: CANVAS_HEIGHT/2 };
  cameraZoom: number = 0.8;
  spatialGrid: SpatialGrid;

  inNest: boolean = false;
  sandboxConfig: SandboxConfig = { invincible: false, infiniteAmmo: false, knockbackEnabled: true, botsEnabled: true, gameSpeed: 1.0, showHitboxes: false, freezeAll: false, spawningEnabled: true };

  transformationReadyClass: TankClass | null = null;
  transformationReadyTimer: number = 0;
  primedSpawn: any = null;
  inVoid: boolean = false;
  voidTimer: number = 0;
  portalSpawnTimer: number = 0;
  transitionAlpha: number = 0;
  isTransitioning: boolean = false;
  lightingCanvas: HTMLCanvasElement;
  lightingCtx: CanvasRenderingContext2D;

  constructor(canvas: HTMLCanvasElement, onStateUpdate: (state: GameState) => void, onGameOver: (score: number, level: number, classType: TankClass) => void, gameMode: GameMode = GameMode.FFA) {
    this.canvas = canvas; this.ctx = canvas.getContext('2d')!;
    this.onStateUpdate = onStateUpdate; this.onGameOver = onGameOver; this.gameMode = gameMode;
    this.width = CANVAS_WIDTH; this.height = CANVAS_HEIGHT;
    this.sound = new SoundEngine();
    this.player = new Tank(this.nextId(), CANVAS_WIDTH / 2, CANVAS_HEIGHT / 2, true, Team.BLUE);
    this.entities.push(this.player);
    this.spatialGrid = new SpatialGrid(300);
    this.lightingCanvas = document.createElement('canvas'); this.lightingCtx = this.lightingCanvas.getContext('2d')!;
    (window as any).gameEngine = this;
    for (let i = 0; i < 150; i++) this.spawnShape();
  }

  nextId() { return ++this.idCounter; }
  setPlayerName(n: string) { this.player.name = n; }
  setPlayerColor(c: string) { if (this.gameMode !== GameMode.TEAMS) this.player.color = c; }
  setPlayerTeam(t: Team) { this.preferredTeam = t; }
  setGameMode(m: GameMode) { this.gameMode = m; }
  addNotification(t: string, c: string) { this.uiNotifications.push({ id: Math.random().toString(36), text: t, color: c, life: 2.5, maxLife: 2.5 }); }
  toggleAutoFire() { this.player.autoFire = !this.player.autoFire; this.addNotification(this.player.autoFire ? "AUTO FIRE ON" : "AUTO FIRE OFF", this.player.autoFire ? "#00e16e" : "#ff4444"); }
  toggleAutoSpin() { this.player.autoSpin = !this.player.autoSpin; this.addNotification(this.player.autoSpin ? "AUTO SPIN ON" : "AUTO SPIN OFF", this.player.autoSpin ? "#00e16e" : "#ff4444"); }

  clearEntities() { this.entities = this.entities.filter(e => e.type === EntityType.PLAYER); this.currentShapeCount = 0; this.addNotification("WORLD PURGED", "#ff4444"); }

  executePrimedSpawn(screenX: number, screenY: number) {
      if (!this.primedSpawn || !this.sandboxConfig.spawningEnabled) return;
      const vW = window.innerWidth; const vH = window.innerHeight;
      const wX = (screenX - vW/2) / this.cameraZoom + this.cameraPos.x; const wY = (screenY - vH/2) / this.cameraZoom + this.cameraPos.y;
      const { type, shapeType, rarity, classType } = this.primedSpawn;
      if (type === 'SHAPE' && shapeType) {
          this.entities.push(new Shape(this.nextId(), wX, wY, shapeType, this.inVoid, rarity));
          this.currentShapeCount++; this.addNotification(`${rarity.toUpperCase()} ${shapeType} FABRICATED`, "#fff");
      } else if (type === 'BOSS') {
          const b = new Boss(this.nextId()); b.pos = { x: wX, y: wY }; this.entities.push(b);
          this.addNotification("GRAND SINGULARITY DEPLOYED", "#00ffff");
      } else if (type === 'VOID_PORTAL') {
          this.entities.push(new VoidPortal(this.nextId(), wX, wY));
          this.addNotification("VOID RIFT OPENED", COLORS.voidPortal);
      } else if (type === 'DUMMY') {
          this.entities.push(new TestDummy(this.nextId(), wX, wY));
          this.addNotification("TARGET DUMMY DEPLOYED", "#ffbb00");
      } else if (type === 'BOT_TANK' && classType) {
          const bot = new Tank(this.nextId(), wX, wY, false, Team.RED);
          bot.name = `DANGER_BOT_${bot.id}`; this.upgradeClassForTank(bot, classType);
          Object.values(StatType).forEach(s => bot.stats[s] = 8); bot.updateStats(); bot.health = bot.maxHealth;
          this.entities.push(bot); this.addNotification(`BOT ${classType.toUpperCase()} SYNTHESIZED`, "#f14e54");
      }
      this.sound.playLevelUp(); this.spawnParticles({ x: wX, y: wY }, "#fff", 20, 4);
  }

  setSandboxFlag(k: keyof SandboxConfig, v: any) { (this.sandboxConfig as any)[k] = v; this.addNotification(`${k.toUpperCase()} UPDATED`, "#00e16e"); }
  instantLevel(l: number) { this.level = l; this.player.level = l; this.player.availableStatPoints = Math.min(l, 60) - 1; this.player.updateStats(); this.addNotification(`SYNCED TO LVL ${l}`, "#33ccff"); }

  spawnGuardians() {
    this.entities = this.entities.filter(e => e.type !== EntityType.GUARDIAN);
    if (this.gameMode === GameMode.TEAMS) {
        for(let i=0; i<3; i++) {
            this.entities.push(new Guardian(this.nextId(), 300, CANVAS_HEIGHT / 2 + (i - 1) * 800, Team.BLUE));
            this.entities.push(new Guardian(this.nextId(), CANVAS_WIDTH - 300, CANVAS_HEIGHT / 2 + (i - 1) * 800, Team.RED));
        }
    }
  }

  handleTransformation() {
      if (this.transformationReadyTimer > 0 && this.transformationReadyClass) {
          this.player.isTransformed = true; this.player.transformationTimer = 180; 
          this.player.classType = this.transformationReadyClass; this.player.barrels = TANK_CONFIGS[this.transformationReadyClass];
          this.player.updateStats(); this.player.health = this.player.maxHealth; this.transformationReadyTimer = 0;
          this.addNotification("YOU HAVE ASCENDED!", "#ff4444"); this.sound.playLevelUp();
          this.spawnParticles(this.player.pos, "#ff4444", 50, 6);
      }
  }

  resetPlayer(preserve: boolean = false) {
    this.player.isDead = false; this.gameOverSignaled = false; 
    this.player.isTransformed = false; this.player.activeBuffs = [];
    if (preserve) { 
        const nL = Math.max(1, Math.floor(this.level * 0.7)); this.level = nL; this.player.level = nL; this.player.score = 0; this.xp = 0; 
        this.player.availableStatPoints = Math.max(0, Math.min(nL, 60) - 1); 
    } else { this.player.score = 0; this.level = 1; this.player.level = 1; this.xp = 0; this.player.availableStatPoints = 0; }
    this.player.autoFire = false; this.player.autoSpin = false;
    if (this.gameMode === GameMode.TEAMS) { this.player.team = this.preferredTeam; this.player.color = (this.preferredTeam === Team.BLUE) ? COLORS.player : COLORS.enemy; }
    else { this.player.team = Team.BLUE; this.player.pos = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT); }
    this.player.stats = { [StatType.REGEN]: 0, [StatType.MAX_HEALTH]: 0, [StatType.MAX_SHIELD]: 0, [StatType.BODY_DAMAGE]: 0, [StatType.BULLET_SPEED]: 0, [StatType.BULLET_PENETRATION]: 0, [StatType.BULLET_DAMAGE]: 0, [StatType.RELOAD]: 0, [StatType.MOVEMENT_SPEED]: 0, [StatType.BULLET_SPREAD]: 0 }; 
    this.player.updateStats(); this.player.health = this.player.maxHealth; this.player.displayHealth = this.player.maxHealth; this.player.invulnerableTime = 3000; this.upgradeClass(TankClass.BASIC);
    if (!this.entities.includes(this.player)) this.entities.push(this.player);
    if (!preserve) { this.entities = this.entities.filter(e => e.type === EntityType.SHAPE || e === this.player); this.currentShapeCount = this.entities.filter(e => e.type === EntityType.SHAPE).length; if (this.gameMode === GameMode.TEAMS) this.spawnGuardians(); }
    this.attractMode = false; this.inVoid = false;
    if (this.gameMode === GameMode.SANDBOX) this.instantLevel(MAX_LEVEL);
  }

  start() { this.lastTime = performance.now(); this.loop(); }
  loop = () => { const now = performance.now(); const dt = Math.min((now - this.lastTime) / 1000, 0.1) * this.sandboxConfig.gameSpeed; this.lastTime = now; this.update(dt); this.draw(); requestAnimationFrame(this.loop); };

  handleInput(keys: Set<string>, mouse: Vector2, mouseDown: boolean, rightMouseDown: boolean = false) { 
    this.keys = keys; this.mouse = mouse; this.mouseDown = mouseDown; this.rightMouseDown = rightMouseDown;
    if (keys.has('t') || keys.has('T')) this.handleTransformation();
  }

  private transitionToDimension(toV: boolean) {
      if (this.isTransitioning) return; this.isTransitioning = true;
      setTimeout(() => { this.inVoid = toV; this.entities = this.entities.filter(e => e.type === EntityType.PLAYER || e.type === EntityType.ENEMY || e.type === EntityType.BULLET); this.currentShapeCount = 0; for (let i = 0; i < 150; i++) this.spawnShape(); this.isTransitioning = false; }, 1000);
  }

  update(dt: number) {
    if (this.isTransitioning) this.transitionAlpha = Math.min(1, this.transitionAlpha + dt * 2);
    else this.transitionAlpha = Math.max(0, this.transitionAlpha - dt * 2);

    if (this.attractMode) {
        if (!this.spectateTarget || this.spectateTarget.isDead) this.spectateTarget = (this.entities.filter(e => e.type === EntityType.ENEMY) as Tank[])[0] || null;
        let tP = this.spectateTarget ? this.spectateTarget.pos : {x: CANVAS_WIDTH/2, y: CANVAS_HEIGHT/2};
        this.cameraPos.x += (tP.x - this.cameraPos.x) * 0.05; this.cameraPos.y += (tP.y - this.cameraPos.y) * 0.05; this.cameraZoom = 0.6;
    } else { this.cameraPos.x += (this.player.pos.x - this.cameraPos.x) * 0.1; this.cameraPos.y += (this.player.pos.y - this.cameraPos.y) * 0.1; this.cameraZoom = this.player.fov; }

    if (!this.attractMode && !this.player.isDead) this.updatePlayerControl(dt);
    if (!this.sandboxConfig.freezeAll) {
        this.entities.forEach(e => {
            if (e.type === EntityType.ENEMY && !e.isDead && this.sandboxConfig.botsEnabled) this.updateBotAI(e as Tank, dt);
            else if (e.type === EntityType.CRASHER) this.updateCrasherAI(e as Crasher, dt);
        });
    }
    this.entities.forEach(e => { if (this.sandboxConfig.freezeAll && e.type !== EntityType.PLAYER) return; e.update(dt); });
    this.handleCollisions();
    this.particles.forEach(p => p.update()); this.particles = this.particles.filter(p => p.life > 0);
    this.floatingTexts.forEach(ft => ft.update()); this.floatingTexts = this.floatingTexts.filter(ft => ft.life > 0);
    this.uiNotifications.forEach(n => n.life -= dt); this.uiNotifications = this.uiNotifications.filter(n => n.life > 0);
    this.entities = this.entities.filter(e => !e.isDead);

    const lb: LeaderboardEntry[] = (this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && !e.isDead) as Tank[])
        .sort((a, b) => b.score - a.score).slice(0, 10).map(e => ({ id: e.id, name: e.name || 'Unknown', score: e.score, classType: e.classType, isPlayer: e.id === this.player.id, team: e.team }));

    this.onStateUpdate({ score: this.player.score, level: this.level, xp: this.xp, maxXp: this.getLevelXp(this.level), stats: this.player.stats, availableStatPoints: this.player.availableStatPoints, currentClass: this.player.classType, isDead: this.player.isDead, fps: Math.round(1/dt), killFeed: this.killFeed, leaderboard: lb, notifications: this.uiNotifications, health: this.player.displayHealth, maxHealth: this.player.maxHealth, shield: this.player.shield, maxShield: this.player.maxShield, playerPos: this.player.pos, playerRotation: this.player.rotation, camera: { x: this.cameraPos.x, y: this.cameraPos.y, zoom: this.cameraZoom }, mapSize: { width: CANVAS_WIDTH, height: CANVAS_HEIGHT }, gameMode: this.gameMode, autoFire: this.player.autoFire, autoSpin: this.player.autoSpin, minimapMarkers: [], inVoid: this.inVoid, voidTimeRemaining: this.voidTimer, isTransformed: this.player.isTransformed, transformationTime: this.player.transformationTimer, transformationReady: this.transformationReadyTimer > 0, activeBuffs: this.player.activeBuffs, sandboxConfig: this.sandboxConfig, primedSpawn: this.primedSpawn });
  }

  updatePlayerControl(dt: number) {
    const dir = { x: 0, y: 0 };
    if (this.keys.has('w') || this.keys.has('W')) dir.y -= 1; if (this.keys.has('s') || this.keys.has('S')) dir.y += 1;
    if (this.keys.has('a') || this.keys.has('A')) dir.x -= 1; if (this.keys.has('d') || this.keys.has('D')) dir.x += 1;
    this.applyTankMovement(this.player, dir);
    if (!this.player.autoSpin) {
      const sX = (this.player.pos.x - this.cameraPos.x) * this.cameraZoom + window.innerWidth / 2;
      const sY = (this.player.pos.y - this.cameraPos.y) * this.cameraZoom + window.innerHeight / 2;
      this.player.rotation = Math.atan2(this.mouse.y - sY, this.mouse.x - sX);
    } else this.player.rotation += dt * 3;
    if (this.mouseDown || this.player.autoFire) this.attemptShoot(this.player);

    // SACRIFICIAL GOAT: Activation
    const isOverseerType = [TankClass.OVERSEER, TankClass.OVERLORD, TankClass.MANAGER].includes(this.player.classType);
    if (this.rightMouseDown && isOverseerType && this.player.abilityCooldown <= 0) {
        const hpCost = this.player.health * 0.5;
        this.player.health -= hpCost;
        this.player.abilityCooldown = 15; // 15s Cooldown
        this.player.activeBuffs.push({ type: 'SACRIFICIAL_GOAT', timeLeft: 10, totalTime: 10 });
        this.sound.playRoar();
        this.addNotification("SACRIFICIAL GOAT ACTIVATED!", "#a020f0");
        for(let i=0; i<30; i++) this.particles.push(new Particle(this.player.pos.x, this.player.pos.y, '#4a0080', 5, 60, 'SOUL'));
    }
  }

  updateCrasherAI(c: Crasher, dt: number) {
    const v = 700;
    if (!c.target || c.target.isDead) {
        const p = this.entities.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && Vector.dist(e.pos, c.pos) < v);
        c.target = this.findNearest(c, p);
    }
    if (c.target) c.acc = Vector.mult(Vector.normalize(Vector.sub(c.target.pos, c.pos)), 1.5);
  }

  updateBotAI(bot: Tank, dt: number) {
      const neighbors = this.spatialGrid.getNeighbors(bot);
      const en = neighbors.filter(e => (e.type === EntityType.PLAYER || e.type === EntityType.ENEMY) && e.team !== bot.team);
      let t = this.findNearest(bot, en) || this.findNearest(bot, neighbors.filter(e => e.type === EntityType.SHAPE));
      if (t) {
          const dir = Vector.normalize(Vector.sub(t.pos, bot.pos));
          bot.rotation = Math.atan2(dir.y, dir.x);
          this.applyTankMovement(bot, dir); this.attemptShoot(bot);
      }
  }

  attemptShoot(tank: Tank) {
    const bBuff = tank.activeBuffs.find(b => b.type === 'SACRIFICIAL_GOAT');
    const baseReload = (BASE_STATS.reload - (tank.stats[StatType.RELOAD] * 2.5)) * 16.67; 
    const idx = tank.nextBarrelIndex % tank.barrels.length;
    if (tank.barrelCooldowns[idx] <= 0 || this.sandboxConfig.infiniteAmmo) {
        const isManager = tank.classType === TankClass.MANAGER;
        const isOverseerType = tank.classType === TankClass.OVERLORD || tank.classType === TankClass.OVERSEER || tank.classType === TankClass.HYBRID;
        if (isManager) {
            if (this.entities.filter(e => e.type === EntityType.MINI_TANK && (e as MiniTank).owner === tank).length < 6) {
                this.entities.push(new MiniTank(this.nextId(), tank.pos.x, tank.pos.y, tank));
                tank.barrelCooldowns[idx] = (baseReload * 3.5) * (bBuff ? 0.5 : 1.0);
            }
        } else if (isOverseerType) {
            const limit = tank.classType === TankClass.OVERLORD ? 12 : 8;
            if (this.entities.filter(e => e.type === EntityType.DRONE && (e as Drone).owner === tank).length < limit) {
                this.entities.push(new Drone(this.nextId(), tank.pos.x, tank.pos.y, tank));
                tank.barrelCooldowns[idx] = (baseReload * 4.0) * (bBuff ? 0.5 : 1.0);
            }
        } else {
            const barrel = tank.barrels[idx];
            const angle = tank.rotation + barrel[3];
            const tip = Vector.add(tank.pos, Vector.mult(Vector.fromAngle(angle), tank.radius * barrel[0]));
            this.entities.push(new Bullet(this.nextId(), tip.x, tip.y, Vector.mult(Vector.fromAngle(angle), (BASE_STATS.bulletSpeed + tank.stats[StatType.BULLET_SPEED] * 0.8)), tank));
            tank.barrelCooldowns[idx] = baseReload * barrel[4] * (bBuff ? 0.5 : 1.0);
        }
        tank.nextBarrelIndex++; this.sound.playShoot(tank.classType);
    }
  }

  applyTankMovement(tank: Tank, dir: Vector2) { 
    if (Vector.mag(dir) > 0) {
      const sB = tank.stats[StatType.MOVEMENT_SPEED] * 0.6;
      tank.acc = Vector.mult(Vector.normalize(dir), (BASE_STATS.speed + sB) * (1 - tank.friction) / tank.friction); 
    }
  }

  findNearest(origin: Entity, targets: Entity[]): Entity | null { let n = null; let min = Infinity; for (const t of targets) { const d = Vector.dist(origin.pos, t.pos); if (d < min) { min = d; n = t; } } return n; }
  isOnScreen(pos: Vector2, r: number = 0) { const vW = window.innerWidth / this.cameraZoom, vH = window.innerHeight / this.cameraZoom; return (pos.x + r > this.cameraPos.x - vW / 2 && pos.x - r < this.cameraPos.x + vW / 2 && pos.y + r > this.cameraPos.y - vH / 2 && pos.y - r < this.cameraPos.y + vH / 2); }
  spawnShape() {
    let p = Vector.randomPos(CANVAS_WIDTH, CANVAS_HEIGHT), t = ShapeType.SQUARE; const r = Math.random();
    if (r < 0.05) t = ShapeType.PENTAGON; else if (r < 0.2) t = ShapeType.TRIANGLE;
    this.entities.push(new Shape(this.nextId(), p.x, p.y, t, this.inVoid)); this.currentShapeCount++;
  }

  handleCollisions() {
    this.spatialGrid.clear(); this.entities.forEach(e => this.spatialGrid.add(e));
    this.entities.forEach(a => {
        const neighbors = this.spatialGrid.getNeighbors(a);
        neighbors.forEach(b => {
            if (a === b || b.isDead) return;
            if (Vector.dist(a.pos, b.pos) < a.radius + b.radius) {
                if (a.type === EntityType.BULLET && (a as Bullet).ownerId === b.id) return;
                if (b.type === EntityType.BULLET && (b as Bullet).ownerId === a.id) return;
                const aS = a.type === EntityType.DRONE || a.type === EntityType.MINI_TANK;
                const bS = b.type === EntityType.DRONE || b.type === EntityType.MINI_TANK;
                if (aS && bS && (a as any).owner.id === (b as any).owner.id) return;
                this.resolveCollision(a, b);
            }
        });
    });
  }

  resolveCollision(a: Entity, b: Entity) {
     const dir = Vector.normalize(Vector.sub(a.pos, b.pos)), dist = Vector.dist(a.pos, b.pos), overlap = (a.radius + b.radius) - dist;
     let rA = b.mass / (a.mass + b.mass), rB = a.mass / (a.mass + b.mass);
     a.pos = Vector.add(a.pos, Vector.mult(dir, overlap * rA)); b.pos = Vector.sub(b.pos, Vector.mult(dir, overlap * rB));

     const filter = (v: Entity, k: Entity, d: number) => {
         if (v.type === EntityType.MINI_TANK) {
             let allowed = k.type === EntityType.SHAPE || k.type === EntityType.BOSS;
             if (k.type === EntityType.ENEMY && !(k instanceof MiniTank) && !(k instanceof Drone)) allowed = true;
             if (k.type === EntityType.BULLET && this.entities.find(e => e.id === (k as Bullet).ownerId)?.type === EntityType.ENEMY) allowed = true;
             return allowed ? d : 0;
         }
         return d;
     };
     a.takeDamage(filter(a, b, b.damage)); b.takeDamage(filter(b, a, a.damage));
     if (a.isDead) this.handleDeath(a, b); if (b.isDead) this.handleDeath(b, a);
  }

  handleDeath(v: Entity, k: Entity) {
      if (this.isOnScreen(v.pos)) { this.sound.playExplosion(v.radius > 20); this.spawnParticles(v.pos, v.color, 10, 3); }
      this.addToKillFeed(k.name || 'Unknown', v.name || 'Unknown');
  }

  addToKillFeed(k: string, v: string) { this.killFeed.unshift({ id: `${Date.now()}`, killerName: k, victimName: v, timestamp: Date.now() }); if (this.killFeed.length > 6) this.killFeed.pop(); }
  getLevelXp(l: number) { return Math.floor(100 * Math.pow(XP_CURVE_MULTIPLIER, l - 1)); }
  upgradeStat(t: Tank, s: StatType) { if (t.availableStatPoints > 0 && t.stats[s] < 8) { t.stats[s]++; t.availableStatPoints--; t.updateStats(); if (t.id === this.player.id) this.sound.playStatUpgrade(); } }
  upgradeClass(nc: TankClass) { this.upgradeClassForTank(this.player, nc); this.sound.playClassUpgrade(); }
  upgradeClassForTank(tank: Tank, newClass: TankClass) { tank.classType = newClass; tank.barrels = TANK_CONFIGS[newClass]; tank.barrelCooldowns = new Array(tank.barrels.length).fill(0); }

  draw() {
    this.ctx.fillStyle = this.inVoid ? COLORS.voidBackground : '#b4b4b4'; this.ctx.fillRect(0, 0, window.innerWidth, window.innerHeight); 
    this.ctx.save(); this.ctx.translate(window.innerWidth / 2, window.innerHeight / 2); this.ctx.scale(this.cameraZoom, this.cameraZoom); this.ctx.translate(-this.cameraPos.x, -this.cameraPos.y);
    this.drawGrid(this.ctx); 
    this.entities.forEach(e => { if (this.isOnScreen(e.pos, e.radius)) e.draw(this.ctx); });
    this.particles.forEach(p => { if (this.isOnScreen(p.pos, p.size)) p.draw(this.ctx); });
    this.ctx.restore();
  }

  getInterceptPoint(sP: Vector2, bS: number, tP: Vector2, tV: Vector2) { const rP = Vector.sub(tP, sP); const time = Vector.mag(rP) / bS; return Vector.add(tP, Vector.mult(tV, time * 0.8)); }

  drawGrid(ctx: CanvasRenderingContext2D) {
      ctx.strokeStyle = '#999'; ctx.lineWidth = 1; ctx.beginPath();
      for (let x = 0; x <= CANVAS_WIDTH; x += GRID_SIZE) { ctx.moveTo(x, 0); ctx.lineTo(x, CANVAS_HEIGHT); }
      for (let y = 0; y <= CANVAS_HEIGHT; y += GRID_SIZE) { ctx.moveTo(0, y); ctx.lineTo(CANVAS_WIDTH, y); }
      ctx.stroke();
  }
}

import React, { useEffect, useRef, useState } from 'react';
import { GameEngine } from '../services/GameEngine';
import { GameMode, GameState, StatType, TankClass } from '../types';

interface GameCanvasProps {
  onStateUpdate: (state: GameState) => void;
  onEngineInit: (engine: GameEngine) => void;
  onGameOver: (score: number, level: number, classType: TankClass) => void;
  gameMode: GameMode;
}

const STAT_KEY_MAP: Record<string, StatType> = {
  '1': StatType.REGEN,
  '2': StatType.MAX_HEALTH,
  '3': StatType.BODY_DAMAGE,
  '4': StatType.BULLET_SPEED,
  '5': StatType.BULLET_PENETRATION,
  '6': StatType.BULLET_DAMAGE,
  '7': StatType.RELOAD,
  '8': StatType.MOVEMENT_SPEED,
  '9': StatType.BULLET_SPREAD,
  '0': StatType.MAX_SHIELD,
};

const GameCanvas: React.FC<GameCanvasProps> = ({ onStateUpdate, onEngineInit, onGameOver, gameMode }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const engineRef = useRef<GameEngine | null>(null);

  useEffect(() => {
      if (engineRef.current) {
          engineRef.current.setGameMode(gameMode);
      }
  }, [gameMode]);

  useEffect(() => {
    if (!canvasRef.current) return;
    const canvas = canvasRef.current;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    const engine = new GameEngine(canvas, onStateUpdate, onGameOver, gameMode);
    engineRef.current = engine;
    onEngineInit(engine);
    engine.start();

    const keys = new Set<string>();
    let mouseDown = false;
    let rightMouseDown = false;
    let mousePos = { x: 0, y: 0 };

    const handleKeyDown = (e: KeyboardEvent) => {
      if (!e.repeat) {
          if (e.key.toLowerCase() === 'e') engine.toggleAutoFire();
          if (e.key.toLowerCase() === 'c') engine.toggleAutoSpin();
      }
      if (STAT_KEY_MAP[e.key]) engine.upgradeStat(engine.player, STAT_KEY_MAP[e.key]);
      keys.add(e.key);
      engine.handleInput(keys, mousePos, mouseDown, rightMouseDown);
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      keys.delete(e.key);
      engine.handleInput(keys, mousePos, mouseDown, rightMouseDown);
    };
    const handleMouseMove = (e: MouseEvent) => {
      mousePos = { x: e.clientX, y: e.clientY };
      engine.handleInput(keys, mousePos, mouseDown, rightMouseDown);
    };
    const handleMouseDown = (e: MouseEvent) => {
      if (e.button === 0) mouseDown = true;
      if (e.button === 2) rightMouseDown = true;
      engine.handleInput(keys, mousePos, mouseDown, rightMouseDown);
    };
    const handleMouseUp = (e: MouseEvent) => {
      if (e.button === 0) mouseDown = false;
      if (e.button === 2) rightMouseDown = false;
      engine.handleInput(keys, mousePos, mouseDown, rightMouseDown);
    };
    const handleResize = () => {
       canvas.width = window.innerWidth; canvas.height = window.innerHeight;
       engine.width = canvas.width; engine.height = canvas.height;
    };
    const preventCtx = (e: MouseEvent) => e.preventDefault();

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mousedown', handleMouseDown);
    window.addEventListener('mouseup', handleMouseUp);
    window.addEventListener('resize', handleResize);
    window.addEventListener('contextmenu', preventCtx);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mousedown', handleMouseDown);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('resize', handleResize);
      window.removeEventListener('contextmenu', preventCtx);
    };
  }, []);

  return <canvas ref={canvasRef} className="block w-full h-full cursor-crosshair" />;
};

export default GameCanvas;
